-- Poems batch 143
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8764f07a-63c9-415c-b68b-c1bcfcf3d3f2','過清遠大家峽','章才邵','宋','宋诗','song-poetry','','[]','巖頭風急樹欹斜，溪畔漁樵十數家。',32,'全唐诗/poet.song.148000.json','["巖頭風急樹欹斜，溪畔漁樵十數家。", "老盡往來名利客，年年秋水映蘆花。"]'),
('830b4d32-f98e-42d8-a3d6-652dd7f36d88','進月堂','章才邵','宋','宋诗','song-poetry','','[]','不將簾幕礙虛空，爲愛清光入室中。',64,'全唐诗/poet.song.148000.json','["不將簾幕礙虛空，爲愛清光入室中。", "滿目盡成金色界，勝游寧羨水晶宮。", "世緣淡泊尤相稱，心鏡圓明總一同。", "長照金樽歌酒樂，爭如此境樂無窮。"]'),
('b7f70325-3dde-44c4-877a-b1a68f739840','聞象山論學語有得','李伯敏','宋','宋诗','song-poetry','','[]','紛紛枝葉漫推尋，到底根株只在心。',32,'全唐诗/poet.song.148000.json','["紛紛枝葉漫推尋，到底根株只在心。", "莫笑無絃陶靖節，箇中三嘆有遺音。"]'),
('c3cab0bb-2d38-41c0-9b8c-346517f5cb9b','道謁朱晦庵先生  其一','鄒輗','宋','宋诗','song-poetry','','[]','武夷洞前皎月生，歸人近得坦途行。',32,'全唐诗/poet.song.148000.json','["武夷洞前皎月生，歸人近得坦途行。", "陰霾滌盡無纖翳，遠徹乾坤一樣明。"]'),
('19a4f064-ae48-4723-b45b-3cef8b682a23','道謁朱晦庵先生  其二','鄒輗','宋','宋诗','song-poetry','','[]','野意凄凉遠俗情，出門一笑亂山青。',32,'全唐诗/poet.song.149000.json','["野意凄凉遠俗情，出門一笑亂山青。", "癡兒白晝猶鼾睡，可是無人會喚醒。"]'),
('05c16361-0d21-41dc-b597-1fea743d63a9','謁毛竹間先生','鄒輗','宋','宋诗','song-poetry','','[]','不辱其身不辱親，要明聖學盡人倫。',32,'全唐诗/poet.song.149000.json','["不辱其身不辱親，要明聖學盡人倫。", "豈爲媚世文章士，養就中和萬古春。"]'),
('24371545-d9d4-4560-86e8-780a684582e5','題讀書林','鄒輗','宋','宋诗','song-poetry','','[]','諸君著意讀書林，好去鳶魚箇裏尋。',32,'全唐诗/poet.song.149000.json','["諸君著意讀書林，好去鳶魚箇裏尋。", "不必浪浮空記誦，且須識取各人心。"]'),
('ef578939-1060-4e43-b9fa-bfc536fa653b','山居寓興','鄒輗','宋','宋诗','song-poetry','','[]','花陰不正月將西，欲到溪邊步懶移。',32,'全唐诗/poet.song.149000.json','["花陰不正月將西，欲到溪邊步懶移。", "坐對前山無一語，此心惟有古人知。"]'),
('ebaccdbd-008c-4b46-a709-99e7fb2887c4','詩一首','釋志南','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u6625", "\u5199\u98ce", "\u98ce", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','古木陰中繫短篷，杖藜扶我過橋東。',32,'全唐诗/poet.song.149000.json','["古木陰中繫短篷，杖藜扶我過橋東。", "沾衣欲濕杏花雨，吹面不寒楊柳風。"]'),
('80981e5d-0d07-49b7-b005-e6be460324ce','接晦庵薦志南書有作','袁梅岩','宋','宋诗','song-poetry','','[]','上人解作風騷話，雲谷書來特地誇。',32,'全唐诗/poet.song.149000.json','["上人解作風騷話，雲谷書來特地誇。", "楊柳杏花風雨後，不知詩軸在誰家。"]'),
('8aa2af8c-b06b-420a-8969-94f3856781e3','賡韻題精舍','晁子東','宋','宋诗','song-poetry','','[]','數椽茅屋俯清溪，學者盈門所得棲。',64,'全唐诗/poet.song.149000.json','["數椽茅屋俯清溪，學者盈門所得棲。", "地僻任從雲聚散，林深不礙日東西。", "巍巍道德千年在，凜凜聲猷萬古齊。", "遺像載瞻三太息，一庭煙草有餘凄。"]'),
('58bff8e0-ed7c-4cc8-9523-a231f113a95b','三河道中  其一','王暉','宋','宋诗','song-poetry','','[]','龍丘風土類中原，雨勢山開百里川。',32,'全唐诗/poet.song.149000.json','["龍丘風土類中原，雨勢山開百里川。", "白鷺水田摩詰畫，桃花溪洞武陵船。"]'),
('6a2519ab-19c5-46cd-93bd-0490b8353510','三河道中  其二','王暉','宋','宋诗','song-poetry','','[]','路入龍遊不見山，縱橫阡陌濲江邊。',32,'全唐诗/poet.song.149000.json','["路入龍遊不見山，縱橫阡陌濲江邊。", "穿籬殘笋如攢槊，夾道寒花似火燃。"]'),
('5cf1d327-971f-4d71-b9a5-70d6423a1ed8','龍游道中聞雁','王暉','宋','宋诗','song-poetry','','[]','避寒來熱稻粱肥，水遠山長結伴稀。',32,'全唐诗/poet.song.149000.json','["避寒來熱稻粱肥，水遠山長結伴稀。", "已是江湖遠行客，雙雙猶是向南飛。"]'),
('ac214407-6385-4ba5-b411-2024698094ec','句','徐昭然','宋','宋诗','song-poetry','','[]','精一危微共一心。',8,'全唐诗/poet.song.149000.json','["精一危微共一心。"]'),
('ca937038-787b-485b-bda3-28c0aca30157','早離永明晚抵江華道中  其一','江朝議','宋','宋诗','song-poetry','','[]','飛沙羃羃路曼曼，萬籟風聲重曉寒。',32,'全唐诗/poet.song.149000.json','["飛沙羃羃路曼曼，萬籟風聲重曉寒。", "涉澗躋危任勞役，服勤王事敢辭難。"]'),
('72416177-a9b6-45ab-8094-af3a6b70c00c','早離永明晚抵江華道中  其二','江朝議','宋','宋诗','song-poetry','','[]','捨車跨馬喜新晴，倍見旌旗照眼明。',32,'全唐诗/poet.song.149000.json','["捨車跨馬喜新晴，倍見旌旗照眼明。", "顧我未能流美化，邦人何事喜相迎。"]'),
('93ceb639-c20a-4f18-ac65-0635e09621c8','遊陽華口占五言八句呈諸僚友','江朝議','宋','宋诗','song-poetry','','[]','十里雲深處，陽華小洞天。',48,'全唐诗/poet.song.149000.json','["十里雲深處，陽華小洞天。", "千巖虛夜月，萬壑溜寒泉。", "石磬生何世，仙田種幾年。", "神靈自幽顯，時序任流遷。"]'),
('1c5794e1-634b-4299-aea8-e45d033651ba','句','楊興宗','宋','宋诗','song-poetry','','[]','要得一書藏石室，爲緣新說自金陵。',16,'全唐诗/poet.song.149000.json','["要得一書藏石室，爲緣新說自金陵。"]'),
('d23eed8b-fc3b-46c0-a30e-b29ee919943f','賦梅','謝洪','宋','宋诗','song-poetry','','[]','朔風颼颼著古梅，寒枝冷落俟春回。',32,'全唐诗/poet.song.149000.json','["朔風颼颼著古梅，寒枝冷落俟春回。", "可憐雪萼無人問，乞借陽和早放開。"]'),
('9602fdbc-2e8a-45a2-9e10-1e0cd27aeee1','震山巖','莫若晦','宋','宋诗','song-poetry','','[]','一巖孤峻出塵埃，下瞰僧坊七寶臺。',64,'全唐诗/poet.song.149000.json','["一巖孤峻出塵埃，下瞰僧坊七寶臺。", "鴻鵠凌空無礙去，浮山供望有情來。", "臨風笑語飄飄遠，舉酒襟懷落落開。", "莫訝作詩詩句好，醉魂飛自月邊回。"]'),
('f3adeed1-88ae-45ae-b090-b127884fde16','送台倅趙叔明趨朝','高文虎','宋','宋诗','song-poetry','','[]','羲輪正弭節，別駕忽揚鞭。',240,'全唐诗/poet.song.149000.json','["羲輪正弭節，別駕忽揚鞭。", "游從亦雨暑，朋盍知何年。", "欲敘情繾綣，難得形周旋。", "譜系玉爲牒，輝華珠在淵。", "漢家子駿才，今世德麟賢。", "洊倅丹丘地，平分刺史天。", "婉畫邁前輩，陰功培後緣。", "人或得其一，君亦幾於全。", "微凉起天末，觸熱趨日邊。", "石橋禮尊者，瓊臺訪遺仙。", "高張天姥蓋，穩泛雪溪船。", "稽山萬塍稻，鏡湖千頃蓮。", "行庖擊小鮮，觸境亂鳴蟬。", "應酬圖畫中，懷想冕旒前。", "早渡月千里，晴帆風一川。", "清都鬰佳氣，絳闕鎖祥煙。", "放朝上閤後，投謁巖廊先。", "諸公競羅致，百辟會班聯。", "託契荷傾蓋，爲僚因贅員。", "猶憑六六魚，寄問我沈綿。"]'),
('d7660441-4a8f-4ab3-8c2f-dd243a8726c3','和曾原伯寄超化舉長老','高文虎','宋','宋诗','song-poetry','','[]','文聲宮祉韻鸞和，素履冰霜凜節柯。',64,'全唐诗/poet.song.149000.json','["文聲宮祉韻鸞和，素履冰霜凜節柯。", "鵬翼扶摇驚斥鷃，鳳翔寥廓舞靈鵝。", "參玄問學淵源遠，友許游從日月多。", "誰袖新篇來古剡，夜寒不覺聳肩哦。"]'),
('bd9becfc-3eab-4805-8881-7f70ea8c01b8','謝人海棠','高文虎','宋','宋诗','song-poetry','','[]','富貴天姿錦里人，高華全比玉堂臣。',32,'全唐诗/poet.song.149000.json','["富貴天姿錦里人，高華全比玉堂臣。", "綠嬌紅嫩精神是，肯折園林兩樹春。"]'),
('00a38e3a-aef8-4bad-86f7-05381c6ebe55','次韻楊少雲桂花','高文虎','宋','宋诗','song-poetry','','[]','溶溶漠漠秋光淡，耿耿寥寥夜色清。',64,'全唐诗/poet.song.149000.json','["溶溶漠漠秋光淡，耿耿寥寥夜色清。", "不是靈根函爽氣，如何醖得此香成。", "玉兔搗霜千萬粒，凄風折作四花凝。", "廣寒慣識朝真趣，一笑秋空意欲凌。"]'),
('97781bad-6143-4655-b020-d6c81dd947f3','雪館山茶','高文虎','宋','宋诗','song-poetry','','[]','江南嘉木蔚蒼蒼，能與山梅次第芳。',32,'全唐诗/poet.song.149000.json','["江南嘉木蔚蒼蒼，能與山梅次第芳。", "葉厚耐擎三寸雪，飛初怯受一番霜。"]'),
('c836024b-d994-4594-b3de-5f796999c40e','酴醾花','高文虎','宋','宋诗','song-poetry','','[]','羽蓋珠旛上下蒙，倚欄碧動舞蛟龍。',64,'全唐诗/poet.song.149000.json','["羽蓋珠旛上下蒙，倚欄碧動舞蛟龍。", "誰憐澹素朝天面，自現光明滿月容。", "楊柳風柔霑絮濕，薔薇露重染衣濃。", "典型猶带醺酣力，醖得餘春百倍醲。"]'),
('65748289-b45d-4ee1-a168-245097c96c45','瑞香花','高文虎','宋','宋诗','song-poetry','','[]','雲岑深處獨翹翹，香逐吳山一夢銷。',32,'全唐诗/poet.song.149000.json','["雲岑深處獨翹翹，香逐吳山一夢銷。", "味入禪心清透澈，錦熏篝暖不容招。"]'),
('49276ee0-2440-41e8-a40f-39115c286e5f','種菊','高文虎','宋','宋诗','song-poetry','','[]','菊載種農經，不見詩三百。',144,'全唐诗/poet.song.149000.json','["菊載種農經，不見詩三百。", "周官敘鞠衣，一言僅可摘。", "黄華紀呂令，落英餐楚客。", "伯始飲得壽，桐君書探賾。", "移根候萌動，需時當甲拆。", "我羨柴桑里，敢希履道宅。", "不種兒女花，朱朱與白白。", "閲譜品雖多，求栽地恐窄。", "揠苗助其長，抱甕溉以澤。", "朗詠黄爲正，流播風傳格。", "寒香紫茁蘭，晚節銅柯柏。", "相繼早梅芳，一笑巡簷索。"]'),
('04678344-1e40-4964-b78d-8ed0afd407fb','水仙','高文虎','宋','宋诗','song-poetry','','[]','朝朝暮暮泣陽臺，愁絕冰魂水一杯。',64,'全唐诗/poet.song.149000.json','["朝朝暮暮泣陽臺，愁絕冰魂水一杯。", "巫峽雲深迷昨夢，瀟湘雪重寫餘哀。", "菊如相得無先意，梅亦傾心敢後開。", "惱徹會心黄太史，他花從此不須栽。"]'),
('ace245d0-761f-4b09-89a4-e072a76b7907','次韻江朝宗梅花  其一','高文虎','宋','宋诗','song-poetry','','[]','新新數點照疎籬，又折今生第一枝。',32,'全唐诗/poet.song.149000.json','["新新數點照疎籬，又折今生第一枝。", "只爲知心無著處，雪中獨立最多時。"]'),
('978f4c73-8082-40bd-b07c-08746e655dc1','次韻江朝宗梅花  其二','高文虎','宋','宋诗','song-poetry','','[]','踏雪歸來水路長，親曾相見白雲鄉。',32,'全唐诗/poet.song.149000.json','["踏雪歸來水路長，親曾相見白雲鄉。", "風來風去都無那，分付行人一點香。"]'),
('b4d7308d-895f-4190-8fea-0dfbc5e26333','集高亭','高文虎','宋','宋诗','song-poetry','','[]','山亭十月晏溫朝，倚檻一聲婆餠焦。',32,'全唐诗/poet.song.149000.json','["山亭十月晏溫朝，倚檻一聲婆餠焦。", "舌澀力微寒氣早，不成清亮却成嬌。"]'),
('e3159e93-5547-4119-a67b-ab1f227967be','題簡寂觀','錢聞禮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','先生舊隠在廬山，幽谷千年竹萬竿。',32,'全唐诗/poet.song.149000.json','["先生舊隠在廬山，幽谷千年竹萬竿。", "偃松拂盡煎茶石，苦筍撐開禮斗壇。"]'),
('b5c2c81c-3fdd-4cf7-ad13-80b53bc65774','題椿桂堂','張伯垓','宋','宋诗','song-poetry','','[]','進士從來榮一第，至比梯雲仰攀桂。',128,'全唐诗/poet.song.149000.json','["進士從來榮一第，至比梯雲仰攀桂。", "弟兄罕見五枝芳，昔說竇郎今莫氏。", "莫氏一門真可榮，二難三秀衆美并。", "見聞歎羨不易及，往往笞兒親短檠。", "堂下荷衣戲成伍，堂上椿齡奉慈母。", "母夫人是月中娥，種得森森桂如許。", "飛騰從此上天衢，豈但森森月桂如。", "更看勳名相炤燿，連珠光彩奪星榆。"]'),
('0bc0241a-6780-4552-8423-dfd3b3043f05','寄沈菊山','張伯垓','宋','宋诗','song-poetry','','[]','八十乾淳老，生涯半子虛。',48,'全唐诗/poet.song.149000.json','["八十乾淳老，生涯半子虛。", "久無朝士餽，空有故人書。", "詩道窮方進，塵緣老盡除。", "茫茫天壤闊，誰復是知予。"]'),
('bc37ca10-2a09-4950-93b1-74a430d6e0ea','壽昌寺','張伯垓','宋','宋诗','song-poetry','','[]','塵埃終日事無窮，不得探真問遠公。',32,'全唐诗/poet.song.149000.json','["塵埃終日事無窮，不得探真問遠公。", "莫訝殷勤題粉壁，重來應見碧紗籠。"]'),
('651e16ba-768f-4baa-8852-8acbfeafc172','挽崔舍人','耿秉','宋','宋诗','song-poetry','','[]','足躡修門甫十年，惟餘篇翰富流傳。',64,'全唐诗/poet.song.149000.json','["足躡修門甫十年，惟餘篇翰富流傳。", "橫經趣得陳編外，草制雄誇落筆先。", "爭美冰銜塵不染，忍觀華□□隨遷。", "忠輸丹扆箴猶在，一鑑云亡共黯然。"]'),
('6c986441-2a38-4f63-b44f-82b3d464c659','荷花','虞詔','宋','宋诗','song-poetry','','[]','晚來一棹鑑湖東，隊隊峯巒入短篷。',32,'全唐诗/poet.song.149000.json','["晚來一棹鑑湖東，隊隊峯巒入短篷。", "一色藕花三十里，淡粧濃抹錦青紅。"]'),
('b44615b4-5aec-458b-a05b-e019ff33854b','柳花','虞詔','宋','宋诗','song-poetry','','[]','短長亭外柳依依，念我心歸未得歸。',32,'全唐诗/poet.song.149000.json','["短長亭外柳依依，念我心歸未得歸。", "粉蝶不知行客恨，也隨飛絮點征衣。"]'),
('9c0a828f-304d-4c09-b68c-e8273bae6558','遊廬山南阜步月回寓館','周登','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不入山中不識閑，不因月上不知還。',32,'全唐诗/poet.song.149000.json','["不入山中不識閑，不因月上不知還。", "老僧長揖歸方丈，只有鐘聲送出山。"]'),
('0308a8c3-5420-4d54-87a0-21ee12be0fe2','泛舟西湖','周登','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊無日欠春風，金碧樓臺面面同。',64,'全唐诗/poet.song.149000.json','["湖邊無日欠春風，金碧樓臺面面同。", "白鳥慣隨船上下，畫橋分斷水西東。", "百年樂事浮雲外，一段傷心落照中。", "老盡風流無問處，藕花今是幾番紅。"]'),
('ec08d62d-8f05-4d5b-81b8-c6ea8ee4dcc1','鼎湖','朱藻','宋','宋诗','song-poetry','','[]','孤峰獨立聳巑岏，轍跡苔封暈未乾。',64,'全唐诗/poet.song.149000.json','["孤峰獨立聳巑岏，轍跡苔封暈未乾。", "秀拔山川清氣上，直衝星斗夜光寒。", "東南擬作擎天柱，今古稱爲壓地盤。", "上有鼎湖風雨隔，寶蓮吹下碧雲端。"]'),
('41abbf7b-1c79-4ed9-b76b-68982dc70191','都梁宮','吳宗旦','宋','宋诗','song-poetry','','[]','從來香草騷人詠，晚作離宮煬帝遊。',32,'全唐诗/poet.song.149000.json','["從來香草騷人詠，晚作離宮煬帝遊。", "三殿重重鎖秋色，七泉脈脈貫中流。"]'),
('5dd8b7ca-91de-477b-a675-67085bc9fe70','九頂大像閣','吳宗旦','宋','宋诗','song-poetry','','[]','嘉州石佛名天下，回視新昌可子孫。',32,'全唐诗/poet.song.149000.json','["嘉州石佛名天下，回視新昌可子孫。", "幸甚身遊大人國，恍然夢跨北溟鯤。"]'),
('230cc793-dd23-478d-864e-7914d1bc977b','金釜山靈泉','吳宗旦','宋','宋诗','song-poetry','','[]','泉來有脈去無痕，水底神龍暗吐吞。',32,'全唐诗/poet.song.149000.json','["泉來有脈去無痕，水底神龍暗吐吞。", "莫怪一池杯樣小，個中風雨洗乾坤。"]'),
('cc9ca084-17fd-424f-a193-ed2dc2263772','句','吳宗旦','宋','宋诗','song-poetry','','[]','避暑自應歸故國，無端依舊入揚州。',16,'全唐诗/poet.song.149000.json','["避暑自應歸故國，無端依舊入揚州。"]'),
('b61878fa-491f-448b-a452-a3a3ec57aab1','大寧寺過舅書舍','吳時顯','宋','宋诗','song-poetry','','[]','長怕山林勒駕回，幽尋空像櫟山隈。',64,'全唐诗/poet.song.149000.json','["長怕山林勒駕回，幽尋空像櫟山隈。", "乘閑特羨春風約，行樂寧論暮景催。", "情分一家欣滿座，窮愁千斛厭成堆。", "白頭甥舅今稀有，願把清樽日醉陪。"]'),
('dc645b7d-c0e4-4006-8876-937bfd6c569b','法相寺可賦亭','吳時顯','宋','宋诗','song-poetry','','[]','塵埃誰復識瞿曇，高座風生玉麈談。',64,'全唐诗/poet.song.149000.json','["塵埃誰復識瞿曇，高座風生玉麈談。", "露浥芙蓉心與凈，香浮薝蔔鼻先參。", "杜陵託興歌茅屋，山谷留情賦草菴。", "試叩禪關聞密語，前三三與後三三。"]'),
('b3bad8f7-494e-479f-8153-aa2c9057f350','石人','沈瀛','宋','宋诗','song-poetry','','[]','檢點行程歲歲同，石人頭畔且從容。',32,'全唐诗/poet.song.149000.json','["檢點行程歲歲同，石人頭畔且從容。", "向來奉口溪邊月，此夜乾元寺裏鐘。"]'),
('ccc9965a-79d2-404f-86d0-aeb8be4e19bc','夜宿國清寺題更好堂','沈揆','宋','宋诗','song-poetry','','[]','堆案文書在眼邊，身閑俱是好林泉。',32,'全唐诗/poet.song.149000.json','["堆案文書在眼邊，身閑俱是好林泉。", "乞渠解褐休雙足，爲結□中飽睡緣。"]'),
('98920f25-dff2-4da6-81ca-de981ebacb6a','題石井泉  其一','沈揆','宋','宋诗','song-poetry','','[]','靈源一閟幾經年，石上重流豈偶然。',32,'全唐诗/poet.song.149000.json','["靈源一閟幾經年，石上重流豈偶然。", "漸喜行春有幽事，人間初見第三泉。"]'),
('6791a979-b9a4-4200-8b01-8a5c86c58b8b','題石井泉  其二','沈揆','宋','宋诗','song-poetry','','[]','上方高閣倚層巒，下有清泉一鑑寒。',32,'全唐诗/poet.song.149000.json','["上方高閣倚層巒，下有清泉一鑑寒。", "更作小亭供勝覽，盡收吟思入毫端。"]'),
('bced1f2f-c1c9-4096-8095-73a0bed59178','題石井泉  其三','沈揆','宋','宋诗','song-poetry','','[]','圓通大士閟茲境，誰遣石湖詩老知。',32,'全唐诗/poet.song.149000.json','["圓通大士閟茲境，誰遣石湖詩老知。", "人生流止亦如此，時與一來題好詩。"]'),
('9170c440-66d2-4c54-9ff5-c2c666a34a39','石井泉次沈太守韻  其一','尤懋','宋','宋诗','song-poetry','','[]','不知開鑿是何年，已有新亭更翼然。',32,'全唐诗/poet.song.149000.json','["不知開鑿是何年，已有新亭更翼然。", "從此雲巖添勝事，合教名亞第三泉。"]'),
('76ada561-339c-445e-9130-f31151f5cb23','石井泉次沈太守韻  其二','尤懋','宋','宋诗','song-poetry','','[]','煙光滉漾映林巒，井底新泉潄齒寒。',32,'全唐诗/poet.song.149000.json','["煙光滉漾映林巒，井底新泉潄齒寒。", "品第試尋張陸記，却因今日又開端。"]'),
('bf99d884-227d-4cbb-9ccc-33013946b846','石井泉次沈太守韻  其三','尤懋','宋','宋诗','song-poetry','','[]','靈源顯晦豈無時，便有高人作已知。',32,'全唐诗/poet.song.149000.json','["靈源顯晦豈無時，便有高人作已知。", "賞識先從石湖老，發揚更頼隠侯詩。"]'),
('974a6f58-3b22-481e-9309-5b1acd469c6f','三學院','祖世英','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭之山天下奇，岡巒百轉盤青螭。',192,'全唐诗/poet.song.149000.json','["洞庭之山天下奇，岡巒百轉盤青螭。", "金堂玉室白雲鎖，中有仙客來棲遲。", "方睛秀骨郭文舉，孤劍青鞋出巖戶。", "朅來此地訪禪翁，共掃松花談太古。", "拏雲忽駕升天行，西歸隻履埋巖坰。", "聲流影散遽如許，故山惟有松風清。", "道師懷古興不淺，堂宇橫陳迎翠巘。", "悠悠遐想山阿人，水带雲衣猶在眼。", "凉飆五月吹浮埃，蕉旗竹𥶙摇空階。", "我來箕踞發長嘯，月光飛射雲樓開。", "寸心浩蕩逸天外，欲去復住聊徘徊。", "永懷西山五色藥，服之羽化登蓬萊。"]'),
('08b160d5-672b-4432-ae6f-4a2bf437ece4','句','葉延壽','宋','宋诗','song-poetry','','[]','自昔吾泉出異僧，清溪今又兩巖興。',16,'全唐诗/poet.song.149000.json','["自昔吾泉出異僧，清溪今又兩巖興。"]'),
('79c1e16a-332d-4c0b-80a1-6da69ca29f28','題西湖酒家壁','林外','宋','宋诗','song-poetry','','["\u897f\u6e56"]','藥爐丹竈舊生涯，白雲深處是吾家。',32,'全唐诗/poet.song.149000.json','["藥爐丹竈舊生涯，白雲深處是吾家。", "江城戀酒不歸去，老却碧桃無限花。"]'),
('5d31146d-3bec-4ed2-a96f-e8619c071f8e','戲題灘傍驛壁','林外','宋','宋诗','song-poetry','','[]','千古傳名黯淡灘，十船過此九船翻。',36,'全唐诗/poet.song.149000.json','["千古傳名黯淡灘，十船過此九船翻。", "惟有泉南林上舍，我自岸上走，你怎奈何我。"]'),
('5ff7e785-901e-4e29-a81f-786f00af1dc0','喜樂功成招范至能入詩社','馬先覺','宋','宋诗','song-poetry','','[]','燕國將軍善主盟，新封詩將一軍驚。',32,'全唐诗/poet.song.149000.json','["燕國將軍善主盟，新封詩將一軍驚。", "范家老子登壇後，鼓出胸中十萬兵。"]'),
('41717204-1134-41f1-9522-7b5dfc7770c7','幽居客至','馬先覺','宋','宋诗','song-poetry','','[]','吾愛吾廬似野人，軒窗花草逐時新。',64,'全唐诗/poet.song.149000.json','["吾愛吾廬似野人，軒窗花草逐時新。", "尋常俗客經過少，咫尺詩仙往復頻。", "小摘園蔬微带雨，淺篘甕蟻曲留春。", "莫嫌供給全羞澀，禮薄情濃却是真。"]'),
('89805c8a-0130-452d-9b72-4325775bb9e6','索笑圖詩','馬先覺','宋','宋诗','song-poetry','','[]','封侯無骨登淩煙，食肉無相當萬錢。',224,'全唐诗/poet.song.149000.json','["封侯無骨登淩煙，食肉無相當萬錢。", "君看簷下偃蹇者，如何頭上著貂蟬。", "雅宜置之一丘壑，了此三生梅竹緣。", "雲巖霜落月照水，有美玉樹臨風前。", "影窺疏欞香破夢，隠几維摩起幽禪。", "杖藜徐步遶千匝，一笑與花俱欲仙。", "呼童秉燭進詩具，折香來薦冰壺泉。", "少陵此興隔千歲，顧我素好亦同然。", "但覺搜腸乏妙語，也擬著句開雲牋。", "牀頭盎盎春有味，案上泠泠風入弦。", "人生適意政須爾，何用底死浮名牽。", "是圖落筆有妙解，先事立意非徒傳。", "草堂之貲吾辦久，不學杜老長乞憐。", "甫里下田儻逢年，便判百斛買江天。"]'),
('e03ab88f-d257-40d0-b3fe-1fde6eb58204','樂菴李先生居南牀論張同知不行挂冠而歸賦二詩爲壽  其一','馬先覺','宋','宋诗','song-poetry','','[]','高人擺塵鞿，厲俗非小補。',48,'全唐诗/poet.song.149000.json','["高人擺塵鞿，厲俗非小補。", "朝來漉酒巾，談笑易珪組。", "百年全始終，一節照今古。", "回首聲利場，車輪正旁午。"]'),
('6df68998-549d-46d4-8c9d-3f6b085d1b2e','樂菴李先生居南牀論張同知不行挂冠而歸賦二詩爲壽  其二','馬先覺','宋','宋诗','song-poetry','','[]','聞健即收身，歸耕躬饁餉。',48,'全唐诗/poet.song.149000.json','["聞健即收身，歸耕躬饁餉。", "詩中句堂堂，牀頭春盎盎。", "寒花晚更香，霜節老益壯。", "相對無俗情，端的羲皇上。"]'),
('4693e84e-9ff0-4967-a0b9-2467417e2ccf','慧聚僧神濟善醫能知人死生於數歲或數月之前或有奇疾則以意用藥無不差者既享高壽臨終甚了了因作二詩哭之僧諱清照神濟乃其師號云  其一','馬先覺','宋','宋诗','song-poetry','','[]','端的西來了世緣，有身寧肯自謀安。',64,'全唐诗/poet.song.149000.json','["端的西來了世緣，有身寧肯自謀安。", "殷勤療病肱三折，去住無心指一彈。", "貝葉翻餘清磬在，梵音飄斷暮鐘殘。", "祇今雙樹婆娑影，空鏁靈山片月寒。"]'),
('6afa93c1-a68b-4bb8-bb11-44bf60151da4','慧聚僧神濟善醫能知人死生於數歲或數月之前或有奇疾則以意用藥無不差者既享高壽臨終甚了了因作二詩哭之僧諱清照神濟乃其師號云  其二','馬先覺','宋','宋诗','song-poetry','','[]','料理歸期不作難，等閒坐蛻白雲軒。',64,'全唐诗/poet.song.149000.json','["料理歸期不作難，等閒坐蛻白雲軒。", "去來自熟三生路，談笑聊書四偈言。", "舍利雖藏多寶塔，化身應返給孤園。", "陰功若證菩提果，更與衆生洗病根。"]'),
('0d4e8e64-d4d6-44d6-88d2-50741b5da824','送崑山丞謝子潚解官還朝','馬先覺','宋','宋诗','song-poetry','','[]','結交無慮三十年，道同志合難其全。',240,'全唐诗/poet.song.149000.json','["結交無慮三十年，道同志合難其全。", "傾蓋相歡豈無有，當面論心背不然。", "晚知趨向動違俗，閉門避客魚淵潛。", "屬聞貳令非常好，才德遠過崔藍田。", "有懷欲吐難忍脚，試剝雲霧看青天。", "穆如清風濯煩慍，皎若明月墮我前。", "論文未易探涯涘，講政壹以民爲先。", "老夫論說衆所廢，公獨採拾無棄捐。", "承顔請益恨不數，契合乃過金石堅。", "我方怙焉以爲命，忍聞歌吹張離筵。", "西郊日煖玉生煙，羨公此行若登仙。", "何當化龍逐雲氣，四方上下相周旋。", "含情握手不忍別，敢效昔人裨一言。", "聖王當宁方急賢，願公袖疏朝甘泉。", "爲言民瘼殊未痊，徑須下詔寬緡錢。"]'),
('1a194cf2-d7fd-4dae-b844-a42efaf89549','盈川舊縣','陸律','宋','宋诗','song-poetry','','[]','茲地舟行數，懷人思惘然。',48,'全唐诗/poet.song.149000.json','["茲地舟行數，懷人思惘然。", "盈川經此日，流水自唐年。", "廢邑叢春草，荒山入暮烟。", "昔賢不可作，開笥讀遺編。"]'),
('af79feb1-cca9-4370-afd6-4307ddbc9bbf','盈川渡','陸律','宋','宋诗','song-poetry','','[]','青草湖頭合，舟行向晚天。',48,'全唐诗/poet.song.149000.json','["青草湖頭合，舟行向晚天。", "疏燈孤枕宿，細雨片帆懸。", "雁下平沙荻，猿啼獨樹烟。", "風塵隨去住，鄉思倍淒然。"]'),
('9a283ee4-bc68-4d01-87fc-75b69ffa6c31','和人','陳善','宋','宋诗','song-poetry','','[]','鮫綃巧織在深泉，不與人間機杼聯。',32,'全唐诗/poet.song.149000.json','["鮫綃巧織在深泉，不與人間機杼聯。", "要知妙在筆墨外，第一莫爲醒者傳。"]'),
('db3459a9-3709-4fc6-a81d-9aaa34005e6c','姑蘇靈巖寺','陳善','宋','宋诗','song-poetry','','[]','山僧不好古，改作任所欲。',24,'全唐诗/poet.song.149000.json','["山僧不好古，改作任所欲。", "洞荒徑已迷，廊空響誰續。"]'),
('2c7b9526-d055-40d1-bb83-60776cded6d2','句','陳善','宋','宋诗','song-poetry','','[]','不到滄浪亭上望，那知此句是天成。',16,'全唐诗/poet.song.149000.json','["不到滄浪亭上望，那知此句是天成。"]'),
('e264ece8-c8d6-463a-8820-5cba0acb0c09','題廣福寺軒','陳睍','宋','宋诗','song-poetry','','[]','小軒架寒溜，激激鳴水蒼。',144,'全唐诗/poet.song.149000.json','["小軒架寒溜，激激鳴水蒼。", "老僧不靳惜，借與一榻凉。", "枕流暫憩息，清飈襲衣裳。", "蟬聲亦多思，牽引晝夢長。", "俗慮頓消處，栩栩無何鄉。", "翻嫌市廛中，吏隠殊相妨。", "未賦淵明歸，祗益袁君狂。", "平生不勇决，戀戀粟一囊。", "何如水西頭，飛雲共徜徉。", "日尋方外遊，煮茗燒妙香。", "此致渺未遂，嘯歌空自傷。", "坐待山月明，拏舟泛滄浪。"]'),
('38600fad-9061-44ae-a125-6eb26a27a2d8','游曉覺寺','陳睍','宋','宋诗','song-poetry','','[]','肩輿行到竹邊村，竹裏僧房盡閉門。',64,'全唐诗/poet.song.149000.json','["肩輿行到竹邊村，竹裏僧房盡閉門。", "小洞頗聞三里近，殘僧今有一人存。", "旋沽薄酒欺寒力，未怯春泥踏雨痕。", "笑覓梅花伴歸去，斷橋流水月黄昏。"]'),
('c3017f6d-7a50-4411-acf8-5454a1f5b170','句','鍾炤之','宋','宋诗','song-poetry','','[]','霖作商巖雨，薰來舜殿風。',12,'全唐诗/poet.song.149000.json','["霖作商巖雨，薰來舜殿風。"]'),
('11e99deb-9740-4d64-80da-feb49ff3b826','儒生墓','王齊輿','宋','宋诗','song-poetry','','[]','儒生骨朽名猶在，高冢相望已亂真。',32,'全唐诗/poet.song.149000.json','["儒生骨朽名猶在，高冢相望已亂真。", "只認夜深螢聚處，便應泉下讀書人。"]'),
('b01ad3a6-d167-483b-9ee7-e8c15b15dd78','賞蓮','趙濟','宋','宋诗','song-poetry','','[]','芒鞋竹杖踏晴沙，雲白山青老歲華。',32,'全唐诗/poet.song.149000.json','["芒鞋竹杖踏晴沙，雲白山青老歲華。", "太極一丸融造化，賞心應不爲荷花。"]'),
('f922a16b-3b1e-4541-9bf8-89100598883a','夜警','趙濟','宋','宋诗','song-poetry','','[]','滿城警柝喧深夜，半壁青燈動客心。',32,'全唐诗/poet.song.149000.json','["滿城警柝喧深夜，半壁青燈動客心。", "烽火未除眠不得，欲將長劍倚危岑。"]'),
('ce6111a8-fc5e-4877-8cde-61518d193b71','挽崔舍人  其一','李處全','宋','宋诗','song-poetry','','[]','雅望高簪履，昌言動冕旒。',48,'全唐诗/poet.song.149000.json','["雅望高簪履，昌言動冕旒。", "五花方判事，萬戶合封侯。", "未換黄金带，俄成白玉樓。", "匆匆大槐國，起滅等浮漚。"]'),
('6084b327-4956-4b13-ac9f-6c9aa006e73a','挽崔舍人  其二','李處全','宋','宋诗','song-poetry','','[]','桂籍聯升望舜裳，香飄折檻馥天光。',64,'全唐诗/poet.song.149000.json','["桂籍聯升望舜裳，香飄折檻馥天光。", "我心但愧蒹葭倚，衆目爭觀鴻雁翔。", "策足華涂欣衮衮，致身台路失堂堂。", "併看雙璧埋黄壤，一慟風前淚數行。"]'),
('03caf471-4942-45f6-976b-097217656265','蛻龍洞','李處全','宋','宋诗','song-poetry','','[]','龍化當年去不回，空餘古洞出崔巍。',64,'全唐诗/poet.song.149000.json','["龍化當年去不回，空餘古洞出崔巍。", "蒼蒼野色連天遠，脈脈泉音穴地來。", "壁上梭飛三尺雨，匣中劍躍一聲雷。", "紅雲六月炎蒸處，應作商霖澤九垓。"]'),
('de6818f7-e983-4496-b86c-60a040ac9282','深靜堂  其一','李處全','宋','宋诗','song-poetry','','[]','鼎來朱墨苦難逃，兩夕山中暫釋勞。',64,'全唐诗/poet.song.149000.json','["鼎來朱墨苦難逃，兩夕山中暫釋勞。", "野岫擁簷青巀嵲，迴塘足雨綠週遭。", "繙經深院心宜靜，遠跡紅塵意自高。", "漫把新篇供寫物，么麽那敢說詩豪。"]'),
('598f5ec5-1542-4f4c-8842-ed0e20e8a104','深靜堂  其二','李處全','宋','宋诗','song-poetry','','[]','連筒接水下橫塘，漫袚塵襟引興長。',64,'全唐诗/poet.song.149000.json','["連筒接水下橫塘，漫袚塵襟引興長。", "喜有一枝安靜境，閒看九曲泛流觴。", "凉生客枕秋將老，月上紗窗夜未央。", "滿眼詩材皆可賦，惜哉無計脫官忙。"]'),
('13f3bc72-d9e3-4235-a1d5-e8b739878bd2','蘭亭序墨本','羅頌','宋','宋诗','song-poetry','','[]','文皇嗜好非聲色，偶愛蘭亭亦其癖。',160,'全唐诗/poet.song.149000.json','["文皇嗜好非聲色，偶愛蘭亭亦其癖。", "河南猶恐後來聞，竟使昭陵隠真蹟。", "世閒能悟知幾人，墨本珍傳意愈勤。", "有似春雲隠明月，光影還到千江分。", "法曹得此深恨晚，有客携從大梁遠。", "多言南渡罕曾見，大勝薛家蟬翼本。", "嗟我學書從少年，較計點畫分媸妍。", "老拈撅筆萬事懶，忽見錦軸心淒然。", "真行姿媚公所取，篆隸何妨更兼有。", "退之但作石鼓歌，談笑譏訶換鵝手。"]'),
('bdf6f44a-8f62-4bbd-ad4d-cab32fe712bd','妙庭觀','麋師旦','宋','宋诗','song-poetry','','[]','不尋銅鼎不求丹，從許琉璃碎舊盤。',32,'全唐诗/poet.song.149000.json','["不尋銅鼎不求丹，從許琉璃碎舊盤。", "阿母堂前幾春夢，耳邊猶聽玉笙寒。"]'),
('506d893d-4964-4d6e-a048-28e1d9bdb012','鐵笛亭','黄銖','宋','宋诗','song-poetry','','[]','一聲蒼壁裂，再奏蛟龍悲。',24,'全唐诗/poet.song.149000.json','["一聲蒼壁裂，再奏蛟龍悲。", "事往迹猶在，山空人不歸。"]'),
('0ae3ef58-ce3e-489f-ba19-d6c826bccb5a','梅花','黄銖','宋','宋诗','song-poetry','','[]','玉簫吹徹北樓寒，野月崢嶸動萬山。',32,'全唐诗/poet.song.149000.json','["玉簫吹徹北樓寒，野月崢嶸動萬山。", "一夜霜清不成夢，起來春信滿人間。"]'),
('bafd2c60-e19f-485f-8696-499c1d6adcc5','秋日','黄銖','宋','宋诗','song-poetry','','[]','曉日初浮萬里暉，西風摇蕩送秋歸。',32,'全唐诗/poet.song.149000.json','["曉日初浮萬里暉，西風摇蕩送秋歸。", "冥鴻直上三千丈，社燕春鶑不敢飛。"]'),
('c2392b6f-8f60-49e9-a278-59f34f46f8a2','送朱元晦遊湘中','黄銖','宋','宋诗','song-poetry','','[]','有美人兮，蹇何爲兮中洲。',361,'全唐诗/poet.song.149000.json','["有美人兮，蹇何爲兮中洲。", "鳴玉佩兮，冠雲章而遠遊。", "浮沅湘而西蹠兮，因返睇兮層丘。", "繄發軔之指期兮，歌予懷以送之。", "粵大道之汩湮兮，嗟惟君兮何求。", "唐虞遠而不可見兮，鳳鳥去兮周衰。", "翟朱之詭行兮，鄒人拒而劙之。", "竺老氏之猖披兮，浸淫渝而益非。", "思正氣之所繇兮，度百世而固然。", "豈日夜而忘之兮，曰夫子之所傳。", "髮絲絲其不斬兮，哇淫蔽兮莫開。", "訖大振於茲時兮，余將從乎洛之湄。", "心鬰鬰而無告兮，顧衆兆兮何知。", "梏夜氣而不存兮，外其良而四馳。", "彼早興而夕息兮，既日用而不能察也。", "紛蠢蠢其倚靡兮，曰騖亂而莫之達也。", "思存養而莫吾虧兮，所事天下而不忘繇。", "致知以自强兮，至天下以□覽。", "余初其性之兮，稽□墳而載陳。", "仁與人其并致兮，道烏乎而遠身。", "剛柔之弛張兮，一氣繚轉而無息。", "矯吾奠夫兩間兮，又陰陽而與爲一。", "超無極而混淪兮，精凝融而以神。", "卒變化而不窮兮，周流通乎九垠。"]'),
('80f3fec5-ebff-4f8f-b2e0-54e4a4ce02b0','送仲晦','黄銖','宋','宋诗','song-poetry','','[]','靡靡歲時晏，亂山紅葉稀。',180,'全唐诗/poet.song.149000.json','["靡靡歲時晏，亂山紅葉稀。", "端居已無悰，況與親故違。", "駕言臨廣路，惜此須臾期。", "祖燕未云洽，雞鳴促再馳。", "晨裝儼然隊，天澹風凄凄。", "迤邐征人行，悵惘離言悲。", "令德本高世，誠思開聖微。", "虎豹文采異，幾年丹詔垂。", "眷茲皇華寄，那得淹遐隮。", "君王久延佇，去矣翔天墀。", "顧我抱幽獨，已爲清世遺。", "冥鴻聿高舉，蜩鷽何由追。", "縈縈西郊道，晻晻朝陽暉。", "出處自殊迹，操袪胡不怡。", "明當逐雲月，依舊東岡陂。"]'),
('8e3a34a9-0b60-4fde-9eca-5333622c6e92','寄南康使君仲晦五十二兄','黄銖','宋','宋诗','song-poetry','','[]','故人久已別，出擁朱轅轓。',144,'全唐诗/poet.song.149000.json','["故人久已別，出擁朱轅轓。", "昨嘗枉札素，謂言尋里門。", "云胡不踐諾，使我心煩冤。", "天門深九重，叫閽聞有言。", "狺狺猛犬吠，曀曀黄霾昏。", "何由一褰開，豁然見乾坤。", "沈憂諒難寤，掩默孰與論。", "秋風吹層波，落葉何翩翻。", "林端月照夜，谷口雲迷村。", "誰同紫芝友，桂枝誰攀援。", "江蘺老已盡，况復芳蘭蓀。", "應當虎符戀，煢煢勞夢魂。"]'),
('e8689c09-7a84-4006-b4da-299dd75c9f8e','秋日懷元晦','黄銖','宋','宋诗','song-poetry','','[]','葉落不勝秋，山空退煩暑。',108,'全唐诗/poet.song.149000.json','["葉落不勝秋，山空退煩暑。", "高齋讀書罷，枕臂聽殘雨。", "靄靄野雲昏，翻翻墜紅舞。", "中虛萬思息，動靜理可覩。", "敬直如有存，勇進忽無所。", "要當涵濡得，未易氣力取。", "林□傳秋聲，晚色霽宮宇。", "肅騷節物變，仰伏冥鴻舉。", "誰與會心期，懷君自延佇。"]'),
('f741ef08-49d0-4c09-88ea-870291f5cb29','季夏有懷仲晦','黄銖','宋','宋诗','song-poetry','','[]','六月苦炎蒸，山居晝方永。',132,'全唐诗/poet.song.149000.json','["六月苦炎蒸，山居晝方永。", "泠然南風至，蕭散荷氣騁。", "蜩鳴綠樹陰，魚躍橫塘凈。", "高蔓展修條，幽篁茁陰穎。", "良時倏回改，白髮益蔽領。", "雖無簪組累，要有貧賤㾪。", "故交何寥闊，畫戟光烱烱。", "滄洲期未遠，歲晏心獨耿。", "誰同茲寂寞，歛退自幽屏。", "向夕牛羊下，過翮急似逞。", "默默掩荆扉，明蟾在東嶺。"]'),
('63250cfc-5549-4a21-8033-4169af12dc6e','曉起有懷仲晦彥集不至','黄銖','宋','宋诗','song-poetry','','[]','月落北牖曉，鄰雞號夢殘。',96,'全唐诗/poet.song.149000.json','["月落北牖曉，鄰雞號夢殘。", "林端清露墜，寢衣淒已單。", "爽朗朝景晰，嘲啾庭雀喧。", "日高溪霧收，四望開青天。", "荷謝水初冷，菊黄香正繁。", "晶晶灝氣凝，餘光浮遠川。", "懷人天一方，晤言誰與殫。", "徘徊遂薄暝，丹楓摇暮寒。"]'),
('643d1b75-93ef-4c06-9e3e-ce16c125f36b','句  其一','黄銖','宋','宋诗','song-poetry','','[]','先聖有遺訓，憂道不憂貧。',12,'全唐诗/poet.song.149000.json','["先聖有遺訓，憂道不憂貧。"]'),
('754a7462-2a19-4710-9ef5-af05614076d4','句  其二','黄銖','宋','宋诗','song-poetry','','[]','私意苟未克，放心何由馴。',12,'全唐诗/poet.song.149000.json','["私意苟未克，放心何由馴。"]'),
('ce83ceaf-962c-4547-9968-87e74b5954f3','香山刻石','王厚之','宋','宋诗','song-poetry','','[]','山琢青瑶水染藍，鶑聲促我醉雙柑。',32,'全唐诗/poet.song.149000.json','["山琢青瑶水染藍，鶑聲促我醉雙柑。", "十年準備抽身去，記取鎸詩在石龕。"]'),
('69cb8e98-3b48-4b8f-b03c-e6e5ec17c96b','高宗皇帝挽詞  其一','袁樞','宋','宋诗','song-poetry','','[]','雲集燕城擾，龍翔漢業興。',48,'全唐诗/poet.song.149000.json','["雲集燕城擾，龍翔漢業興。", "風燃燎衣火，雪擁渡河冰。", "險難成戡定，憂勞付纂承。", "百年餘父老，嗚咽望原陵。"]'),
('336f2a4b-0753-4923-9af4-0d3563e59e87','高宗皇帝挽詞  其二','袁樞','宋','宋诗','song-poetry','','[]','曆數欽堯命，謳歌樂舜歸。',48,'全唐诗/poet.song.149000.json','["曆數欽堯命，謳歌樂舜歸。", "璣衡新日月，黼黻舊裳衣。", "姑射遊神遠，崆峒探道微。", "龍髯攀莫及，空悵白雲飛。"]'),
('8c72d5ec-1e61-470a-9e49-763daed76b53','題建寧南鄉橋','袁樞','宋','宋诗','song-poetry','','[]','玉龍倒影卧寒潭，人在雲霄天地寬。',32,'全唐诗/poet.song.149000.json','["玉龍倒影卧寒潭，人在雲霄天地寬。", "借問是誰題此柱，茂陵詞客到長安。"]'),
('f3c144e1-13f3-4ccb-abd2-de4fe21a59f0','題屏風','袁樞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山一毫輕，滄海一滴水。',24,'全唐诗/poet.song.149000.json','["泰山一毫輕，滄海一滴水。", "我觀天地間，何啻猶一指。"]'),
('2200b80c-e6ec-40ce-9c91-d006aa17a6a0','武夷精舍十詠 隠屏精舍','袁樞','宋','宋诗','song-poetry','','[]','先生出雲谷，看盡東南山。',48,'全唐诗/poet.song.149000.json','["先生出雲谷，看盡東南山。", "吳越幾往來，衡廬屢躋攀。", "恨無璚瑶英，駐此冰雪顔。", "有懷武夷仙，相期蒼翠間。"]'),
('522fa4a2-a4df-46c0-81ed-8082e59b3224','武夷精舍十詠 仁智堂','袁樞','宋','宋诗','song-poetry','','[]','此身本無累，動靜隨所寓。',48,'全唐诗/poet.song.149000.json','["此身本無累，動靜隨所寓。", "結廬在巖谷，自適山水趣。", "朝來挹雲氣，日夕沐風露。", "坐觀天地心，詎忘仁智慮。"]'),
('2bf7b719-d5a2-4a7d-9789-54aaefa0ed14','武夷精舍十詠 隠求室','袁樞','宋','宋诗','song-poetry','','[]','本是山中人，歸來山中友。',48,'全唐诗/poet.song.149000.json','["本是山中人，歸來山中友。", "豈同荷蓧老，永結躬耕耦。", "浮雲忽出岫，膚寸彌九有。", "此志未可量，見之千載後。"]'),
('840d41c0-c674-43d3-8032-ef568355a85c','武夷精舍十詠 觀善齋','袁樞','宋','宋诗','song-poetry','','[]','出處紹前哲，典型資後生。',48,'全唐诗/poet.song.149000.json','["出處紹前哲，典型資後生。", "虛堂懸青鏡，視者心自明。", "古人不難到，功用在力行。", "緬懷朋簪盍，耿耿中夜情。"]'),
('a3d67ed6-ddb5-4369-928a-fb981026b83f','武夷精舍十詠 寒棲館','袁樞','宋','宋诗','song-poetry','','[]','巖前風入松，谷口泉漱石。',48,'全唐诗/poet.song.149000.json','["巖前風入松，谷口泉漱石。", "寫之五弦琴，身在函丈席。", "竹間有餘地，營館招羽客。", "靜夜緪高弦，待月寒林隙。"]'),
('e1d74a27-4ac1-42a6-921a-46d742ef611f','武夷精舍十詠 晚對亭','袁樞','宋','宋诗','song-poetry','','[]','落日鬰蒼烟，空山轉寒碧。',48,'全唐诗/poet.song.149000.json','["落日鬰蒼烟，空山轉寒碧。", "石屏倚天立，端峭一千尺。", "無言獨與對，足以永朝夕。", "何用向時流，抵掌恣談劇。"]'),
('7034292a-3231-4307-92e3-8783be7571c4','武夷精舍十詠 鐵笛亭','袁樞','宋','宋诗','song-poetry','','[]','當年跨鶴翁，想在雲深處。',48,'全唐诗/poet.song.149000.json','["當年跨鶴翁，想在雲深處。", "鐵笛忽龍吟，萬壑披霾霧。", "遥知發天秘，踏破蒼苔路。", "吹與衆仙聞，來看晚題句。"]'),
('cf5a1c5c-1f89-46ad-a983-fe259086277d','武夷精舍十詠 釣磯','袁樞','宋','宋诗','song-poetry','','[]','投轄出東溟，持竿歸九曲。',48,'全唐诗/poet.song.149000.json','["投轄出東溟，持竿歸九曲。", "溪翁來問訊，笑失雙鬢綠。", "潭邊舊釣石，瑩滑磨青玉。", "竟日謾垂綸，忘機看鷗浴。"]'),
('ac26cfaf-f8ee-44c2-a6ec-f4ff323e2abb','武夷精舍十詠 茶竈','袁樞','宋','宋诗','song-poetry','','[]','摘茗蛻仙巖，汲水潛虬穴。',48,'全唐诗/poet.song.149000.json','["摘茗蛻仙巖，汲水潛虬穴。", "旋然石上竈，輕汎甌中雪。", "清風已生腋，芳味猶在舌。", "何時棹孤舟，來此分餘啜。"]'),
('9c5b6c9a-8b67-4fbd-bbe4-4d28e3043eae','武夷精舍十詠 漁艇','袁樞','宋','宋诗','song-poetry','','[]','溪迴山路斷，月白沙汀冷。',48,'全唐诗/poet.song.149000.json','["溪迴山路斷，月白沙汀冷。", "有人掀短篷，擊櫂歌聲永。", "聞之三嘆息，渙然發深省。", "歸去萬石灘，理我釣魚艇。"]'),
('fda26da1-d38a-4245-93eb-54838f7552f3','寄朱晦翁山中丹砂','袁樞','宋','宋诗','song-poetry','','[]','丹砂九轉世莫傳，羽衣婀娜飛朝天。',160,'全唐诗/poet.song.149000.json','["丹砂九轉世莫傳，羽衣婀娜飛朝天。", "淒然風露洗塵世，星斗一天隨轉旋。", "空餘丹鼎在巖際，夜夜虹光騰霽煙。", "天遺紫陽弭絳節，點石成玉公須專。", "朝來金鎖開洞府，丹火已灰當復然。", "離龍坎虎玄又玄，不須人間詢謫仙。", "黄熊跑號青兕舞，爭欲舐鼎嚴笞鞭。", "巖頭風高捲衣袂，嘶斷玉龍雲滿川。", "怡然上池漱瓊液，鼓枻下濯丹溪泉。", "雲間雙鶴儻未下，招隠爲我歌長篇。"]'),
('3b3752bb-c62b-4f0b-9361-5eedb4491c96','句','袁樞','宋','宋诗','song-poetry','','[]','溫黄前後并，殿下不須行。',12,'全唐诗/poet.song.149000.json','["溫黄前後并，殿下不須行。"]'),
('1f9125f2-6809-4669-a9fc-2964084c0b2b','題椿桂堂','林大中','宋','宋诗','song-poetry','','[]','詩禮栽陪歲月深，流芳到此見天心。',32,'全唐诗/poet.song.149000.json','["詩禮栽陪歲月深，流芳到此見天心。", "桂枝競秀椿難老，寬占堂前十畝陰。"]'),
('c0945406-b7d2-4c1c-bec7-3445cd6c831a','清愛堂','郭知運','宋','宋诗','song-poetry','','[]','清愛堂前竹色佳，留烟带月翠橫斜。',32,'全唐诗/poet.song.149000.json','["清愛堂前竹色佳，留烟带月翠橫斜。", "日長吏散庭空後，風景蕭蕭對瀹茶。"]'),
('52e18d53-63e4-453a-9c83-d7bb27867b6a','題雙廟','郭知運','宋','宋诗','song-poetry','','[]','唐祚中不振，孽胡恣姦驕。',120,'全唐诗/poet.song.149000.json','["唐祚中不振，孽胡恣姦驕。", "君德弗克終，治亂在一朝。", "渠魁睥神器，四海俱動摇。", "向來爲厲階，其迹已冰消。", "中興功孰盛，張許冠百僚。", "堂堂二公烈，千古名不凋。", "義膽極華岳，忠肝齊斗杓。", "平生慕節義，卜居祠匪遥。", "丹青就湮鬰，古屋風蕭蕭。", "英靈如可問，激懦討惛妖。"]'),
('2e95ba76-96c6-493d-9a6d-b63d2f37e0a9','登凌歊臺','郭知運','宋','宋诗','song-poetry','','[]','臺荒落日屯，臺名空在耳。',48,'全唐诗/poet.song.149000.json','["臺荒落日屯，臺名空在耳。", "大江天際來，疊障雲邊起。", "空見梵王宮，占斷黄山址。", "殘碑何處捫，塔影秋空裏。"]'),
('c96e3444-6d98-46ba-a0b2-5d7f333d6986','岳陽樓紀興','郭知運','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u5cb3\u9633\u697c"]','淼淼長江百尺樓，樓頭宿雨坐來收。',64,'全唐诗/poet.song.149000.json','["淼淼長江百尺樓，樓頭宿雨坐來收。", "天連衡嶽烟光淡，日抱瀟湘水氣浮。", "風月豈消今古恨，江湖空代廟廊憂。", "風波滿目鄉關遠，夢遶鴛湖問釣舟。"]'),
('17c82d19-6cc1-44b1-9c78-5527aa554e5a','寄楊公闇修撰','郭知運','宋','宋诗','song-poetry','','[]','秀翮翩翩五采鸞，乘雲飛傍玉闌干。',64,'全唐诗/poet.song.149000.json','["秀翮翩翩五采鸞，乘雲飛傍玉闌干。", "天開金馬文章署，詔選銀魚侍從官。", "念我覊栖三澨水，憐君出入五雲端。", "從容退食鳴琴處，肯信風塵作吏難。"]'),
('891bbcc0-476a-4d10-88fa-095bff50fe7f','送張子韶謫居南安','郭知運','宋','宋诗','song-poetry','','[]','稜稜直節振朝班，孤劍衝風夜度關。',64,'全唐诗/poet.song.149000.json','["稜稜直節振朝班，孤劍衝風夜度關。", "東海波濤明主德，西江烟雨逐臣顔。", "霜青楓老丹成樹，月落猿啼淚滿山。", "橫浦棲遲君莫恨，已留名姓在人間。"]'),
('780da8a9-6553-4959-91be-5caa31d84170','寄孟始兄兼示弟姪','郭知運','宋','宋诗','song-poetry','','[]','奄忽離家已數秋，湖山何日掃松楸。',32,'全唐诗/poet.song.149000.json','["奄忽離家已數秋，湖山何日掃松楸。", "封章允得天恩許，便買春風海上舟。"]'),
('48abcdb3-ad00-48a7-a513-c44c88fd98dc','偶成','郭知運','宋','宋诗','song-poetry','','[]','黿鼎功名染指來，故園山水亦悠哉。',32,'全唐诗/poet.song.149000.json','["黿鼎功名染指來，故園山水亦悠哉。", "可人最是猥園菊，不待秋風也自開。"]'),
('ff983fbf-ef0f-4bb1-b67d-25d3a4f7d4e3','早春','郭知運','宋','宋诗','song-poetry','','[]','年來飄泊任西東，解組論文意自雄。',32,'全唐诗/poet.song.149000.json','["年來飄泊任西東，解組論文意自雄。", "臘盡竺溪漁唱晚，杏花溪上又春風。"]'),
('b4f106e8-23b9-4f46-8f6b-deeede6b01ec','真空寺','李輔','宋','宋诗','song-poetry','','[]','括蒼山上雲，山好雲亦好。',24,'全唐诗/poet.song.149000.json','["括蒼山上雲，山好雲亦好。", "可憐山下僧，看雲不知老。"]'),
('c3495686-d125-4821-83fd-b4cf12d03c95','泰伯廟迎享送神辭三章  其一','龔頤正','宋','宋诗','song-poetry','','[]','翼翼兮新宮，蘭櫋兮枅桂，氣總總兮高靈下隊。',73,'全唐诗/poet.song.149000.json','["翼翼兮新宮，蘭櫋兮枅桂，氣總總兮高靈下隊。", "君視八紘兮昔何殊于棄屣，今復何有兮一席之壝。", "惠我吳人兮曷日以弭。", "吁嗟君來兮我心則喜，君來不來兮我忘食事。"]'),
('20973c04-b6af-436c-a8eb-fed1d90e0eb3','泰伯廟迎享送神辭三章  其二','龔頤正','宋','宋诗','song-poetry','','[]','登歌兮堂上，屢舞兮堂下。',46,'全唐诗/poet.song.149000.json','["登歌兮堂上，屢舞兮堂下。", "君來享兮清酤，溪毛陸離兮筐筥。", "蓴鯽芳鮮兮亦有肥羜，君不來兮使我心苦。"]'),
('3d82eac1-5c17-4d9f-a833-debbc1f5f26b','泰伯廟迎享送神辭三章  其三','龔頤正','宋','宋诗','song-poetry','','[]','車兮載旃，舟兮揚帆，鼓咽咽兮君當還。',67,'全唐诗/poet.song.149000.json','["車兮載旃，舟兮揚帆，鼓咽咽兮君當還。", "君肯來兮尚盤桓，我心煢煢兮其無端，君不我留兮下土囂煩。", "福我吳人兮無疾與患，千秋萬歲兮歌至德以何言。"]'),
('bc492311-ec52-4685-93ab-bafdabbaba7e','陳山龍君祠迎享送神曲  其一','龔頤正','宋','宋诗','song-poetry','','[]','海波淵淪兮海山巃嵷，其下潜通兮君之宮。',60,'全唐诗/poet.song.149000.json','["海波淵淪兮海山巃嵷，其下潜通兮君之宮。", "時思其母兮來舂容，菖葉生兮杏蔕融。", "君之來兮雷隆隆，雨我田兮秋芃芃，我之懷兮無初終。"]'),
('b1340edc-e586-4b5c-a65f-204501ce435c','陳山龍君祠迎享送神曲  其二','龔頤正','宋','宋诗','song-poetry','','[]','君祝駕兮芬陽斯陳，鼓鐘廣享兮列鼎重茵。',55,'全唐诗/poet.song.149000.json','["君祝駕兮芬陽斯陳，鼓鐘廣享兮列鼎重茵。", "君之宮兮屯雲，蕙肴蒸兮芬芬。", "我黍我稌兮抑亦薦其萍芹，君明其衷兮無吐芳新。"]'),
('90944ccc-fea7-4cf2-8f1d-f078683199d4','陳山龍君祠迎享送神曲  其三','龔頤正','宋','宋诗','song-poetry','','[]','吹洞簫兮望極浦，君之歸兮雲在下土。',52,'全唐诗/poet.song.149000.json','["吹洞簫兮望極浦，君之歸兮雲在下土。", "十風兮五雨，祐我海邦兮汙萊斥鹵。", "君不來兮使吾心苦，千秋萬歲兮爲民所怙。"]'),
('df138b8c-5096-4999-89a2-6a202f4d0fe1','贈林次齡','部使者','宋','宋诗','song-poetry','','[]','戶長盡蠲民不病，室家相慶酒頻沾。',32,'全唐诗/poet.song.149000.json','["戶長盡蠲民不病，室家相慶酒頻沾。", "農桑課績無遺恨，循吏聲名并兩都。"]'),
('100d7abf-94a1-453d-b64c-43158e078294','高宗皇帝輓詞  其一','韓彥質','宋','宋诗','song-poetry','','[]','大曆開真主，羣雄控六飛。',48,'全唐诗/poet.song.149000.json','["大曆開真主，羣雄控六飛。", "山河千載業，天地一戎衣。", "復古邊疆定，銷兵聖母歸。", "依然興禮樂，文武徧郊畿。"]'),
('4c0ae34f-b3c1-4fdb-9678-db081e42f1f8','高宗皇帝輓詞  其二','韓彥質','宋','宋诗','song-poetry','','[]','爲物聊經世，本無黄屋心。',48,'全唐诗/poet.song.149000.json','["爲物聊經世，本無黄屋心。", "重明得傳器，大業若遺簪。", "典冊褒崇極，庭闈孝養深。", "昊天歸德報，不使二毛侵。"]'),
('8aebcf5a-32f1-49b0-b0fc-5e329661b82c','高宗皇帝輓詞  其三','韓彥質','宋','宋诗','song-poetry','','[]','八秩歸希有，三靈感具衣。',48,'全唐诗/poet.song.149000.json','["八秩歸希有，三靈感具衣。", "鼎湖龍已遠，汾水雁空飛。", "羽衛愁無色，風雲慘不暉。", "惟餘功與德，千古歎巍巍。"]'),
('d7a3c963-b013-4982-813f-cba1a041da56','題大智院明月巢','韓彥古','宋','宋诗','song-poetry','','[]','清風去無塵，白雲來無心。',24,'全唐诗/poet.song.149000.json','["清風去無塵，白雲來無心。", "一笑玉溪上，落花流水深。"]'),
('259c25b5-8384-4a60-abdf-82df1c43de03','題鳴山祠','紹興士人','宋','宋诗','song-poetry','','[]','自擊牛昌隠，威風震海寰。',24,'全唐诗/poet.song.149000.json','["自擊牛昌隠，威風震海寰。", "待吾謀用日，同共掃完顔。"]'),
('b55caf45-93a7-46b5-ba79-9a452e902124','留題延慶院','何中太','宋','宋诗','song-poetry','','[]','一峯環合柏蒼蒼，中有金仙古道場。',32,'全唐诗/poet.song.149000.json','["一峯環合柏蒼蒼，中有金仙古道場。", "夜半雨聲來枕上，頓令炎熱變清凉。"]'),
('f5a51087-e33f-44d0-8fd8-682faba5e863','東巖寺','雍大椿','宋','宋诗','song-poetry','','[]','精廬隠東山，氣象嚴竹柏。',144,'全唐诗/poet.song.149000.json','["精廬隠東山，氣象嚴竹柏。", "入門佛畫好，曉日明金碧。", "向來巖名寺，初不覘遺迹。", "隠庵中梁秀，邂逅論夙昔。", "行前亟指似，雲磴飛雙舄。", "始知翠微中，洞穴刊青壁。", "莓苔暗龍象，缺甃貯靈液。", "開山記乾元，斷碣餘□□。", "經營想耆舊，興廢今幾易。", "平生泉石心，逮此欣有□。", "惜哉荆棘地，尚阻遊人屐。", "疇能發其秘，澄觀今藉□。"]'),
('26e3afa8-e508-4232-ac4b-30086d5cd7fd','偈頌六首  其一','釋深','宋','宋诗','song-poetry','','[]','風蕭蕭，葉飄飄。',32,'全唐诗/poet.song.149000.json','["風蕭蕭，葉飄飄。", "雲片片，水茫茫。", "江干獨立向誰說，天外飛鴻三兩行。"]'),
('e05ade10-d443-43e1-9a17-ef27847e13fd','偈頌六首  其二','釋深','宋','宋诗','song-poetry','','[]','龍生龍，鳳生鳳，老鼠養兒緣屋棟。',32,'全唐诗/poet.song.149000.json','["龍生龍，鳳生鳳，老鼠養兒緣屋棟。", "達磨大師不會禪，歷魏遊梁乾打閧。"]'),
('1ea752e3-b3d3-47a9-8da2-2f97238486cb','偈頌六首  其三','釋深','宋','宋诗','song-poetry','','[]','桃符休釘，艾人莫縛。',36,'全唐诗/poet.song.149000.json','["桃符休釘，艾人莫縛。", "太虛無雲，本自寥廓。", "大家拊掌歸去休，擬議思量錯錯錯。"]'),
('589d96f0-989b-48cd-8886-15f0c3d16b37','偈頌六首  其四','釋深','宋','宋诗','song-poetry','','[]','維摩默然，普賢廣說。',39,'全唐诗/poet.song.149000.json','["維摩默然，普賢廣說。", "歷代聖賢，互呈醜拙。", "君不見落花三月子規啼，一聲聲是一滴血。"]'),
('7a4d2a83-e29f-4d81-9c21-80b73772fe1e','偈頌六首  其五','釋深','宋','宋诗','song-poetry','','[]','一九二九，相逢不出手。',51,'全唐诗/poet.song.149000.json','["一九二九，相逢不出手。", "三九二十七，籬頭吹觱篥。", "翻憶小釋迦，雙手抱屈膝。", "知不知，實不實，摩訶般若波羅蜜。"]'),
('6526d211-58a9-44dd-99ff-698f3ff11017','偈頌六首  其六','釋深','宋','宋诗','song-poetry','','[]','東村王老夜燒錢，百萬雄兵带甲眠。',32,'全唐诗/poet.song.149000.json','["東村王老夜燒錢，百萬雄兵带甲眠。", "四塞八蠻皆鎮靜，大家拊掌賀堯年。"]'),
('468a8c7f-6080-483b-93fd-ed9fe90c733d','頌古八首  其一','釋深','宋','宋诗','song-poetry','','["\u8861\u5c71"]','厖眉策起貌稜層，見佛元來却不曾。',32,'全唐诗/poet.song.149000.json','["厖眉策起貌稜層，見佛元來却不曾。", "南嶽天台相撞著，被人喚作捉齋儈。"]'),
('65857d29-d725-4483-a327-d4b90da90641','頌古八首  其二','釋深','宋','宋诗','song-poetry','','[]','龐公倒地，靈照扶起。',34,'全唐诗/poet.song.149000.json','["龐公倒地，靈照扶起。", "至今幾百年，清風猶未已。", "猶未已，東海鯉魚千尺觜。"]'),
('7440daa9-242c-4047-acb1-55513fdd10cd','頌古八首  其三','釋深','宋','宋诗','song-poetry','','[]','大家在裏許，南山焦尾虎。',24,'全唐诗/poet.song.149000.json','["大家在裏許，南山焦尾虎。", "牙爪利如鋒，日輪正當午。"]'),
('0bef8e2c-0bea-4d85-b930-327e2b876db2','頌古八首  其四','釋深','宋','宋诗','song-poetry','','[]','一人背手抽金鏃，一人反身控角弓。',32,'全唐诗/poet.song.149000.json','["一人背手抽金鏃，一人反身控角弓。", "南北東西競頭看，果然一鴈落寒空。"]'),
('825a0524-6fad-4e59-b677-c1e87d6cc645','頌古八首  其五','釋深','宋','宋诗','song-poetry','','[]','狗子無佛性，勸君不用舉。',24,'全唐诗/poet.song.149000.json','["狗子無佛性，勸君不用舉。", "欲透萬重關，須是千鈞弩。"]'),
('32c458ba-8faf-4802-a796-baef62d20a7e','頌古八首  其六','釋深','宋','宋诗','song-poetry','','[]','行喝也打，禮拜也打。',20,'全唐诗/poet.song.149000.json','["行喝也打，禮拜也打。", "臨濟大師，可知禮也。"]'),
('451e8923-8e3e-421d-a1cb-170f6f9c137c','頌古八首  其七','釋深','宋','宋诗','song-poetry','','[]','昨夜三更轉向西，明眼宗師爲指迷。',32,'全唐诗/poet.song.149000.json','["昨夜三更轉向西，明眼宗師爲指迷。", "若於話下尋端的，未免泥中又洗泥。"]'),
('02472ca1-cecb-4004-adf2-265faa4c1a58','頌古八首  其八','釋深','宋','宋诗','song-poetry','','[]','不點自行，不撥自轉。',52,'全唐诗/poet.song.149000.json','["不點自行，不撥自轉。", "伎倆天然，機輪如箭。", "如今分付當行家，百歲光陰已不多。", "若能直下猛提取，天上人間爭奈何。"]'),
('ec7aca1b-8c06-4d7a-9c97-0eea3cb326bf','乞貲曹勣','釋法空','宋','宋诗','song-poetry','','[]','一夢江湖已十春，芒鞋不踐馬頭塵。',64,'全唐诗/poet.song.149000.json','["一夢江湖已十春，芒鞋不踐馬頭塵。", "只知今日了今日，豈料一身愁一身。", "南阮固應慚北阮，越人哪得累秦人。", "西風不但吹游子，吹老天涯白髮新。"]'),
('58482597-371d-474c-a424-b445b4bcdfb4','和何子應賦不欺室韻','張孝祥','宋','宋诗','song-poetry','','[]','隆興天子開千齡，六龍飛天動潛鱗。',96,'全唐诗/poet.song.149000.json','["隆興天子開千齡，六龍飛天動潛鱗。", "東嘉先生初召對，不欺之論驚廷臣。", "誰令浮雲蔽白日，脫幘歸來環堵室。", "巍巍烏府憶霜簡，凜凜螭坳有椽筆。", "魏公眼力無餘子，與公周旋豈其死。", "請公細讀不欺銘，一字之褒如魯史。"]'),
('4800ddfc-f554-4b8c-a9ff-4bfbcabac238','讀中興碑','張孝祥','宋','宋诗','song-poetry','','[]','繡綳兒啼思塞酥，重牀燎香驅羣胡。',96,'全唐诗/poet.song.149000.json','["繡綳兒啼思塞酥，重牀燎香驅羣胡。", "阿環錦襪無尋處，一夜驚眠摇帳柱。", "朔方天子神爲謀，三郎歸來長慶樓。", "樓前拜舞作奇祟，中興之功不贖罪。", "日光玉潔十丈碑，蛟龍蟠拏與天齊。", "北望神皋雙淚落，祇今何人老文學。"]'),
('22f2c18b-3302-40f8-8e6f-baf002758852','題張仲欽所藏隆茂宗畫登瀛圖','張孝祥','宋','宋诗','song-poetry','','[]','老隆已死畫筆枯，畫歸天上人間無。',128,'全唐诗/poet.song.149000.json','["老隆已死畫筆枯，畫歸天上人間無。", "公從何處得此圖，眼明嶺海三歎吁。", "天策上將天爲徒，指揮羣龍清八區。", "褒鄂英衛供掃除，功成告廟金模胡。", "歌童舞女不願渠，乃此數士相爲娛。", "鐵面苦口談詩書，直欲措世如唐虞。", "老隆妙手神所摹，蒼頭廬兒亦敷腴。", "祝公歸直承明廬，願持此道補帝裾。"]'),
('a69602c5-d97a-41c0-a563-979d44baa9b0','題蔡濟忠所摹御府米帖','張孝祥','宋','宋诗','song-poetry','','[]','生前官職但執戟，身後一字萬金直。',202,'全唐诗/poet.song.149000.json','["生前官職但執戟，身後一字萬金直。", "當時雷霆下收拾，世間不復有遺逸。", "上清虛皇手自擇，編星爲囊雲作笈。", "流鈴擲火守護密，君從何處見真跡。", "知君定通玉帝籍，太微垣中賜餘墨。", "龍騰虎卧摹不得，想君神授五色筆。", "江南鈎鎖腕中力，釵折屋漏千態出。", "整整十卷字猶濕，光彩激射海爲立。", "平生我亦有書癖，對此戃怳心若失。", "口呿汗下屢太息，十日把玩不得食。", "作牋天公拜稽首，乞我此老生時一雙手，爲君痛飲百斛酒。", "墨池如江筆如帚，一掃萬字不停肘。"]'),
('371174aa-dbfc-4dbc-b2fc-e7be6b73046e','賦王唐卿廬山所得靈壁石','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','湘江竹深韶不傳，后夔神禹飛上天。',288,'全唐诗/poet.song.149000.json','["湘江竹深韶不傳，后夔神禹飛上天。", "泗濱之磬無人編，帝敕此寶淪深淵。", "於乎不知幾千年，奇形異質鬼所鎸。", "青虬赤虎遭縛纒，蹙筋怒爪身攣拳。", "自從胡塵障中原，神物變化隨霏煙。", "金聲玉振義不辱，六丁徙置康廬巔。", "靈臺星官未知處，但怪寶氣干霄躔。", "王郎齋居敷淺原，飲水泣血天所憐。", "空山無人下羣仙，似夢非夢或告旃。", "捫蘿獨上果有得，失喜而懼心茫然。", "百夫挽取自包裹，解衣更買蠻兒氈。", "緘扃不肯鄉人說，知我好古容觀瞻。", "焚香再拜婁歎息，安得致之天子前。", "安得致之天子前，明堂郊丘備宮縣。", "調和正聲薦上帝，簫勺羣慝收戈鋋。", "朝廷清明用耆哲，一律四海歸陶甄。", "鳳皇來儀獸率舞，復古却到虞韶邊。", "是時賦公筆如椽，襞牋爲草登歌篇。"]'),
('1454406b-b038-488f-af2b-e4c5d36af31f','月之四日至南陵大雨江邊之圩已有沒者入鄱陽境中山田乃以無雨爲病偶成一章呈王龜齡','張孝祥','宋','宋诗','song-poetry','','[]','圩田雨多水拍拍，山田政作龜兆拆。',96,'全唐诗/poet.song.149000.json','["圩田雨多水拍拍，山田政作龜兆拆。", "兩般種田一般苦，一處祈晴一祈雨。", "去年水大高田熟，低田不收一粒穀。", "只今萬錢糴一斛，浙西排門煮稀粥。", "聖神天子如堯湯，曰雨而雨暘而暘。", "天公廣大豈有意，爾自作孽非天殃。"]'),
('58766437-2f30-4ca9-8c0b-36c2effd83c0','近得一二硯示范達甫笑以爲堪支牀也許送端州大硯作詩以堅其約','張孝祥','宋','宋诗','song-poetry','','[]','范郎紫玉餘半圭，翻手作雲雨雹隨。',160,'全唐诗/poet.song.149000.json','["范郎紫玉餘半圭，翻手作雲雨雹隨。", "龍蛇起陸孔翠飛，雲收雨霽千首詩。", "薦以文錦盤珠璣，夜光發屋鄰翁知。", "桂州刺史書成癡，單車萬里日夜馳。", "囊中已無去年錐，欠此石友相娛嬉。", "范郎笑我支牀龜，忽遣致我重寶齎。", "金印如斗不願携，愛此直欲忘朝饑。", "君行題輿古端溪，溪石醜好紛不齊。", "溪邊之人足謾欺，須君眼力爲辨之。", "更作萬斛之墨池，爲君大書十丈碑。"]'),
('ac3182bb-6551-4d03-8537-33c60851a989','劉倅示崇寧上舍題名翰林其父也','張孝祥','宋','宋诗','song-poetry','','[]','崇寧天子開皇極，發揮神謨詔羣辟。',88,'全唐诗/poet.song.149000.json','["崇寧天子開皇極，發揮神謨詔羣辟。", "十八學士天與力，攀鱗附鳳才一日。", "翰林尚書古遺直，不作三公奄窀穸。", "當時盛事刊樂石，後五十年已今昔。", "令我再拜三嘆息，尚有之子似世德，不羸其躬且赫奕。"]'),
('5b77ed75-505b-4c3a-bb27-adc4958e6802','黄升卿送棕鞋','張孝祥','宋','宋诗','song-poetry','','[]','編棕織蒲繩作底，輕凉堅密穩稱趾。',96,'全唐诗/poet.song.149000.json','["編棕織蒲繩作底，輕凉堅密穩稱趾。", "帝庭無復夢絲絇，上客還同貺珠履。", "我家江南山水窟，日日行山勞屐齒。", "感君投贈欲別時，布襪青鞋從此始。", "亨衢知子方著脚，直上雲霄三萬里。", "泰階歷盡却歸來，赤舄一雙應几几。"]'),
('8fe78517-c3c3-486a-ac06-372e265bf505','贈張欽州','張孝祥','宋','宋诗','song-poetry','','[]','張家承平四姓侯，門前列戟金成丘。',128,'全唐诗/poet.song.149000.json','["張家承平四姓侯，門前列戟金成丘。", "南來清貧家立壁，但有萬卷書滿樓。", "雲山極觀半空寫，下有花竹秀而野。", "閉門讀易已三年，樂天知命忘華顛。", "我行湘中識此老，難兄莫年更枯槁。", "從來戚畹須表勸，會聽鳴珂趁朝早。", "衡陽小隠雖深幽，去天尺五君無留。", "貂蟬兜鍪何足道，君必不爲猿鶴羞。"]'),
('743149ad-f663-4e46-86a2-b9873488a468','賦沈商卿硯','張孝祥','宋','宋诗','song-poetry','','[]','石渠東觀天尺五，壁星下直圖書府。',192,'全唐诗/poet.song.149000.json','["石渠東觀天尺五，壁星下直圖書府。", "琳琅寶鎮出三代，浩瀚簡編照千古。", "右文儲硯一百九，鈿匣珠囊護瓊玖。", "有時清夜發光怪，諸儒縱觀容拜手。", "一收朝蹟歸故園，瓦池葦管涂突煙。", "夢尋清都故歷歷，起憑書案空潸然。", "眼明見此超萬石，色如馬肝涵玉質。", "白圭之玷尚可磨，澀不拒筆滑留墨。", "摩挲太息不自已，呼兒汲甘爲湔洗。", "天遺至寶瑞吾子，要與詞林壯根柢。", "子行飛騫爲時須，西清承明有佳除。", "收功翰墨儻乞我，田間自抄種樹書。"]'),
('d083ce54-1ae1-4a86-81d7-33ef0784bbae','大雨呈同行諸公','張孝祥','宋','宋诗','song-poetry','','[]','我船千斛初甚遲，上灘下灘風薄之。',208,'全唐诗/poet.song.149000.json','["我船千斛初甚遲，上灘下灘風薄之。", "百夫撐挽才得過，水淺舟大行無期。", "同來賓客笑鈍滯，一葉自買如鳧鷖。", "瞥波急槳亂藻荇，瞬息不見飈車馳。", "忽然昨夜雷雨作，黑雲頹山風卷壑。", "龍門春漲魚鱉亂，牛渚宵明鬼神惡。", "篷翻纜斷泊不得，客只一身無處著。", "長年絕叫客驚起，一浪先掀半船水。", "囊衣漂盡到巾屢，一夜奔忙沙石裏。", "我時甘寢殊不覺，但怪颼颼風到耳。", "起來呼酒自勞苦，水滿凉生差可喜。", "鄉來笑者今却悲，人生淹速那能知。", "明朝轉柁我船快，喚客同船莫嫌隘。"]'),
('8091049c-d46c-4c51-b558-22da831b1dee','吳城阻風','張孝祥','宋','宋诗','song-poetry','','[]','吳城山頭三日風，白浪如屋雲埋空。',128,'全唐诗/poet.song.149000.json','["吳城山頭三日風，白浪如屋雲埋空。", "北來大舸氣勢雄，車帆打鼓聲韸韸。", "我船政爾不得去，跼促沙岸如鳬翁。", "長年三老屢彈指，六月何曾北風起。", "由來官儂多齟齬，世不汝諧神亦爾。", "我愧此言呼使前，順風逆風皆偶然。", "皇天廣大豈有意，想汝嗔喜庸非偏。", "瓶中有粟囊有錢，與汝飽飯姑留連。"]'),
('042b8904-3a97-4354-88da-0e26ff5dcb7e','金沙堆','張孝祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','玻璃盆中金作堆，藥房桂棟中天開。',128,'全唐诗/poet.song.149000.json','["玻璃盆中金作堆，藥房桂棟中天開。", "洞庭無底蛟蜃惡，君不喚我那能來。", "旁船守風四十日，我行昨夜到磊石。", "山頭望君乞杯珓，僮僕歡呼得頭擲。", "二更南風轉旗脚，打鼓開船曉星落。", "秋光凈洗八百里，亭午投君廟前泊。", "斬牲釃酒報君德，君今清都豈其食。", "聊須醉飽撐船儂，明日依舊行南風。"]'),
('d68cfe53-425f-4479-a3a7-f8a2791be2ec','欲雪','張孝祥','宋','宋诗','song-poetry','','[]','欲雪未雪天模胡，凍行沙尾鶬鴰呼。',64,'全唐诗/poet.song.149000.json','["欲雪未雪天模胡，凍行沙尾鶬鴰呼。", "北風刮耳立不住，更騎鈍馬穿枯蘆。", "兩生憐我意不舒，江頭三日占檣烏。", "高堂明朝置安輿，買羊沽酒償勤渠。"]'),
('528e662f-30d6-44d8-a353-4c160598ee24','鑑湖納凉','張孝祥','宋','宋诗','song-poetry','','[]','鑑湖周圍三百里，極目平波清到底。',64,'全唐诗/poet.song.149000.json','["鑑湖周圍三百里，極目平波清到底。", "荷花歲久生滿湖，人來採蓮唱歌起。", "賀家千頃水雲鄉，六月荷花風最凉。", "短楫輕舟來斷續，山橫曉月正蒼蒼。"]'),
('5697df27-afd3-4bcc-8808-ffc1722dcfcd','和沈教授子壽賦雪三首  其一','張孝祥','宋','宋诗','song-poetry','','[]','北風吹來燕山雪，十萬王師方浴鐵。',80,'全唐诗/poet.song.149000.json','["北風吹來燕山雪，十萬王師方浴鐵。", "風纏熊虎靈旗靜，凍合蛟龍寶刀折。", "何人夜縛吳元濟，我欲從之九原隔。", "東南固自王氣勝，西北那憂陣雲結。", "豈無祖逖去誓江，已有辛毗來仗節。"]'),
('74d65722-c5ed-48f4-aade-c4a4c0383ade','和沈教授子壽賦雪三首  其二','張孝祥','宋','宋诗','song-poetry','','[]','今年米貴更風雪，破屋荒凉冷於鐵。',81,'全唐诗/poet.song.149000.json','["今年米貴更風雪，破屋荒凉冷於鐵。", "道人三日不出門，卧聽欹簷竹枝折。", "高吟忽送三十韻，覿面未覺千里隔。", "比公也自可憐人，家徒四壁衣鶉結。", "君不見漢時蘇子卿，窖中齧氈終持節。"]'),
('46386c7b-c5f1-433a-aa2a-befacdf0e6c0','和沈教授子壽賦雪三首  其三','張孝祥','宋','宋诗','song-poetry','','[]','天公作劇已三白，刮面東風利如鐵。',80,'全唐诗/poet.song.149000.json','["天公作劇已三白，刮面東風利如鐵。", "只今斗米錢數百，更說流民心欲折。", "胡兒打圍涂塘北，煙火穹廬一江隔。", "陛下宵衣甚焦勞，微臣私憂長鬰結。", "爾曹忍凍不足說，我輩何時立奇節。"]'),
('83a549a7-cedd-4bbf-b821-b06c776650ee','鄱陽史君王龜齡閔雨再賦一首','張孝祥','宋','宋诗','song-poetry','','[]','老農歌舞手作拍，一雨紛紛稻花拆。',96,'全唐诗/poet.song.149000.json','["老農歌舞手作拍，一雨紛紛稻花拆。", "去年秋田旱政苦，史君隨車有甘雨。", "旁州不熟我州熟，至今中家有藏穀。", "地碓舂秔珠滿斛，老農左餐仍右粥。", "史君行矣伊佐湯，緝熙和氣無常暘。", "豈徒一雨潤九穀，要爲萬物除千殃。"]'),
('1bdcc1c8-373a-448e-98b5-4dbd0dd6303c','喜晴賦呈常守葉夢錫','張孝祥','宋','宋诗','song-poetry','','[]','史君憂民出至誠，欲晴未晴天所矜。',96,'全唐诗/poet.song.149000.json','["史君憂民出至誠，欲晴未晴天所矜。", "白衣老人無逢迎，香火未收東方明。", "指揮六龍扶日行，羣陰卷盡見太清。", "女擷柔桑男趁耕，熙熙和氣滿春城。", "去年歲事已如許，田頭試聽老農語。", "淛西更著五日雨，麥根爛盡種不土。"]'),
('52e19959-9575-430d-a5db-bf29702af088','七夕','張孝祥','宋','宋诗','song-poetry','','[]','去年永州逢七夕，今年衡州逢七夕。',64,'全唐诗/poet.song.149000.json','["去年永州逢七夕，今年衡州逢七夕。", "往來不敢怨道路，迎送但知慚吏卒。", "年年七夕有定時，我行屬天那得知。", "東西南北會逢汝，但願强健無所苦。"]'),
('8500b9b7-b967-4439-83d5-4ff7be89c3ca','謝劉恭父玉潭月色真石室之賜','張孝祥','宋','宋诗','song-poetry','','[]','玉潭月色冽以清，石室千里猶典刑。',64,'全唐诗/poet.song.149000.json','["玉潭月色冽以清，石室千里猶典刑。", "何人遺我雙玉瓶，武夷先生翰林卿。", "約束風雨驅雷霆，長鯨夜吸川爲傾。", "明朝風止醉不醒，扁舟徑度君山青。"]'),
('d8436f02-fdf3-407d-8ae6-98681f7a02ec','從張欽夫覓紙','張孝祥','宋','宋诗','song-poetry','','[]','蜀江擣麻色勝玉，百金才能致一幅。',64,'全唐诗/poet.song.149000.json','["蜀江擣麻色勝玉，百金才能致一幅。", "君家入則充棟宇，再拜未肯乞纖粟。", "爲君破慳作此詩，擔囊揭篋應有時。", "比鄰寒亡忌唇齒，君但勤渠送川紙。"]'),
('a1f4a295-4e9b-4ae5-b57b-4cb68c8afe03','幽興','張孝祥','宋','宋诗','song-poetry','','[]','海涵大陰日西墜，畫角一聲城欲閉。',64,'全唐诗/poet.song.149000.json','["海涵大陰日西墜，畫角一聲城欲閉。", "柴門關上濯足眠，萬事不如高枕睡。", "睡鄉廣大能我容，兀兀騰騰興莫窮。", "推枕起瞻河漢曉，月明庭竹響清風。"]'),
('55374c1d-d4ed-4108-8d4f-13c7e51507b9','麒麟硯滴分韻得文字','張孝祥','宋','宋诗','song-poetry','','[]','素王西狩麟，筆削昌斯文。',84,'全唐诗/poet.song.149000.json','["素王西狩麟，筆削昌斯文。", "茂陵一角獸，妙語聞終軍。", "壯哉筆硯間，英姿欲拏雲。", "名參龜龍瑞，威掃狐兔羣。", "豈獨濡毫端，政爾清妖氛。", "會當獻君王，玉殿春夜分。", "輸寫胸中奇，恩波被無垠。"]'),
('a7124d34-b79b-4565-9a87-987355bab661','諸公分韻躡冒頓之區落焚老上之龍庭得老庭字  其一','張孝祥','宋','宋诗','song-poetry','','[]','橫槊能賦詩，下馬具檄草。',84,'全唐诗/poet.song.149000.json','["橫槊能賦詩，下馬具檄草。", "忠義乃天賦，勳名要時早。", "龍卧南陽客，鷹揚渭濱老。", "當其尚棲遲，衆或輕潦倒。", "風雲會相遇，氛祲當獨掃。", "鳳皇翔千仞，駑馬顧棧皁。", "士爲一飽謀，懸知不同道。"]'),
('661634de-fb99-480b-8c99-425a64a373b3','諸公分韻躡冒頓之區落焚老上之龍庭得老庭字  其二','張孝祥','宋','宋诗','song-poetry','','[]','吳甲組練明，吳鈎瑩青萍。',168,'全唐诗/poet.song.149000.json','["吳甲組練明，吳鈎瑩青萍。", "戰士三百萬，猛將森列星。", "揮戈却白日，飲渴枯滄溟。", "如何天驕子，敢來干大刑。", "嗚呼三十年，中原飽羶腥。", "陛下極涵容，宗祊甚威靈。", "犬羊爾何知，梟獍心未寧。", "囊血規射天，蒼蠅混驚霆。", "佛狸定送死，榆關不須扃。", "虜勢看破竹，我師真建瓴。", "便當收咸陽，政爾空朔庭。", "明堂朝玉帛，劍佩鳴東丁。", "八章車攻詩，十丈燕然銘。", "我學益荒落，尚可寫汗青。"]'),
('c6db3cc0-554b-412e-a49f-1d7a810ef78a','椰子酒榼','張孝祥','宋','宋诗','song-poetry','','[]','矮胡生南方，託家碧山崖。',192,'全唐诗/poet.song.149000.json','["矮胡生南方，託家碧山崖。", "採擇供貢篚，扶持上天街。", "愧此願慤姿，欲售久未諧。", "道傍麴先生，風味故自佳。", "逢渠即傾蓋，輸寫能開懷。", "刮削出光彩，規繩去欹𠇗。", "金玉豈足貴，膠漆真吾儕。", "客來有嘉招，二士往必偕。", "婆娑止坐隅，供饋煩金釵。", "矮胡雖木强，醇德真無涯。", "虛心實其腹，居然外形骸。", "微物幸見用，棄置理則乖。", "毛穎有封國，陶匏薦欽柴。", "大藥起世痾，炮燔及根荄。", "願子自洗濯，勿受塵埃埋。", "暇日肯相從，醉經坐高齋。"]'),
('ac4c73cc-e4b4-4d24-9de5-045cbb21b91b','赭山分韻得成葉字  其一','張孝祥','宋','宋诗','song-poetry','','[]','昨日一尺雪，今朝十分晴。',168,'全唐诗/poet.song.149000.json','["昨日一尺雪，今朝十分晴。", "杲日上積雪，光若虹氣升。", "江平鏡新磨，地迥玉琢成。", "赭山有令色，令我白眼青。", "借馬屋東家，喚客踏層冰。", "冒貂挾裘茸，石路五里平。", "竹樹紛掩冉，珠幢間霓旌。", "野僧不慣客，倉皇門前迎。", "屋古少完壁，堂虛有危登。", "石上迹宛宛，山腰塔亭亭。", "劫火偶不燒，百年費支撐。", "我有一尊酒，高處得細傾。", "諒非無事飲，憂國空含情。", "長歌眇寥廓，歸路已戴星。"]'),
('f640b382-69f9-477d-8785-53410830034c','赭山分韻得成葉字  其二','張孝祥','宋','宋诗','song-poetry','','[]','萬生紛不同，宿昔有定業。',168,'全唐诗/poet.song.149000.json','["萬生紛不同，宿昔有定業。", "哀哉彼遷民，苦事乃稠疊。", "纍纍庭際炊，采采澗底葉。", "問渠胡爲來，悲淚不盈睫。", "連年避胡亂，生理安可說。", "今年更倉皇，芻藁亦焚劫。", "扶持過江南，十口四五活。", "斗米六百錢，兼旬又風雪。", "前時詔書下，振廩要周浹。", "聖主甚哀矜，我曹空感咽。", "願今兵革罷，復得理歸楫。", "傳聞菰蒲中，相殺血新喋。", "本是耕田農，饑寒實敺脅。", "須公語縣吏，早與支米帖。"]'),
('0a265999-8e77-4c69-8a83-de634534d040','重入昭亭賦二十韻','張孝祥','宋','宋诗','song-poetry','','[]','我本山中人，對山輒忻然。',228,'全唐诗/poet.song.149000.json','["我本山中人，對山輒忻然。", "蹉跎落世網，欲去常拘牽。", "蒼鷹著珠韝，側腦思高騫。", "青絲絡奔驥，擺脫意乃便。", "抑鬰不自聊，沉冥向誰宣。", "長懷昭亭山，積翠摩青天。", "下有千柱宮，突兀數百年。", "往者雪中游，羣峯玉回旋。", "飛閣出木末，下睨春無邊。", "堂中二老人，龍象開法筵。", "炯炯月在空，浩浩海納川。", "應庵默無言，妙處心已傳。", "如庵說千偈，微辭諦真詮。", "靜極炷爐熏，對床且安眠。", "更欲捐冠簪，一簞寄三椽。", "此志竟不遂，緇塵亂歸韉。", "今朝復何朝，却望山中煙。", "縹緲見樓觀，鍾梵聲清圓。", "我携九節筇，飛步雲蘿巔。"]'),
('d9e661f9-9d43-4b08-ac2d-d4821ddeef43','登馬氏永寧閣和朱漕元順分韻','張孝祥','宋','宋诗','song-poetry','','[]','佛宮昔誰營，猶挾蓋世氣。',216,'全唐诗/poet.song.149000.json','["佛宮昔誰營，猶挾蓋世氣。", "應慚割據醜，稍識苦空味。", "重簷隠白日，隆棟湧金地。", "耽耽壁間像，尚可將千騎。", "鄉來歌舞處，荒棘擁城雉。", "惟此悲願成，歷劫更興起。", "橫撞鍾萬石，妙響警昏醉。", "憶當風雪辰，茲事實經始。", "老僧喜成就，膜拜顙有泚。", "喚客饌伊蒲，齋房頗深邃。", "空巖才跬步，不往獨何謂。", "徑携雙竹杖，脚力勇難制。", "繡衣兩使者，風誼我所畏。", "相逢瘴海上，此樂豈天惠。", "山林與心會，風月可回施。", "聊乘簿書隙，拚此一日費。", "摩挲水邊石，勝處欲專美。", "不用濡漆書，公詩即行記。"]'),
('6282cf9b-ab5f-46e1-84db-aaea7111e7b5','再用韻呈仲欽元順','張孝祥','宋','宋诗','song-poetry','','[]','今時朱仲欽，文字有奇氣。',216,'全唐诗/poet.song.149000.json','["今時朱仲欽，文字有奇氣。", "潜幽覩天奧，雋永得古味。", "袖手閲世紛，虛心餘樂地。", "那持瘴野節，不從羽林騎。", "埋輪吾宗英，補衮五色雉。", "去年對延英，御坐再三起。", "憂民甚己溺，稽古乃心醉。", "天衢行日月，發軔從此始。", "會當紀鴻業，我筆墨先泚。", "相期并徵詔，禁殿直清邃。", "尚憶此追游，班中語相謂。", "我懷江湖去，初服反芰制。", "閑邊靜成趣，岐路險多畏。", "此事屬兩君，它年儻終惠。", "長篇起予病，妙語充法施。", "調高和難工，初學慚紙費。", "郊原春無數，風日極清美。", "已遣具方舟，重游更須記。"]'),
('26a25d45-9b0e-4561-a061-19d03ba5e16c','贈江清卿','張孝祥','宋','宋诗','song-poetry','','[]','吾友林少穎，讀書不計屋。',276,'全唐诗/poet.song.149000.json','["吾友林少穎，讀書不計屋。", "抄書手生繭，照書眼如燭。", "往時羣玉府，上直對床宿。", "夜半聞吾伊，我睡已再熟。", "此君抱高節，雪柏映霜竹。", "造物乃兒戲，卧病在空谷。", "尚能作手書，寄我成一束。", "我懶更愧渠，終歲不報復。", "今來見江子，少穎儼在目。", "不必不如師，惟子肖甚速。", "持身嚴法律，自愛比冰玉。", "學官冷徹骨，三月食無肉。", "危坐談仁義，口吻若布穀。", "時能從我游，騎馬踏溪淥。", "定自我輩人，胸次不碌碌。", "惟皇開洪業，大厦非一木。", "豈有梁棟姿，而令久淹辱。", "願子益寵珍，即日馬首北。", "我懷山林去，掃迹混樵牧。", "躬耕得薄少，持用供水菽。", "稍遠聲利場，真勝萬鍾祿。", "但恨與子別，醉語成諄複。", "因書寄少穎，以寫我心曲。"]'),
('ce589fad-7f65-40f5-8438-98a84951c65d','和蔡濟忠天字韻','張孝祥','宋','宋诗','song-poetry','','[]','憶我初識君，屈指今七年。',144,'全唐诗/poet.song.149000.json','["憶我初識君，屈指今七年。", "鹽車著騏驥，駑蹇紛爭先。", "謂當對清閑，帝席半夜前。", "稍使修世官，復近尺五天。", "如何尚朱紱，亦墮嶺海邊。", "前山春色多，佳樹午陰圓。", "散策履幽徑，方舟下長川。", "心目得開明，語笑爲芳鮮。", "但恨暝色至，不得窮攀援。", "尚欲夜然犀，下照蛟龍淵。", "清遊渺難繼，歸夢蒼山巔。", "須君換鵝帖，更敘山陰賢。"]'),
('b069e11f-368f-4940-8318-761306567f2d','考試呈周茂振舍人陳季陵國正','張孝祥','宋','宋诗','song-poetry','','[]','胸中五斗棘，厭此十日讀。',120,'全唐诗/poet.song.149000.json','["胸中五斗棘，厭此十日讀。", "紛然湘羅帕，猶作春笋束。", "先生擇法眼，一閲不再復。", "探囊得至寶，每出輒驚俗。", "孟公更超絕，涇渭飽渟滀。", "從容了官事，繭紙唾珠玉。", "鄙夫聞道晚，衡鑑恐不足。", "冥搜夜無寐，慚愧費宮燭。", "何時即三昧，屈指社甕熟。", "秋容日夕好，應到堂前菊。"]'),
('670684bc-8b97-4906-9cb5-003b688ae807','和子雲白蓮','張孝祥','宋','宋诗','song-poetry','','[]','仙人玉步摇，佛子白練衣。',120,'全唐诗/poet.song.149000.json','["仙人玉步摇，佛子白練衣。", "新粧水底明，素手風中揮。", "盈盈夜露光，灧灧秋江肥。", "寒月分好色，朝霞借餘輝。", "遥聞功德水，盡洗幻化非。", "惟此妙花幢，坐受諸天圍。", "鄉來孤山遊，末覺所見稀。", "零落塞草邊，相逢故依依。", "結實須及早，要令飽霜威。", "采剝登君盤，勿嫌此么微。"]'),
('32f570df-5f98-477a-afeb-1ad3598485e3','與趙李二同年夜飲有懷石使君惠叔','張孝祥','宋','宋诗','song-poetry','','[]','佳月久不見，忽見如故人。',120,'全唐诗/poet.song.149000.json','["佳月久不見，忽見如故人。", "清風何方來，過我孤竹君。", "我有一尊酒，政爲二子斟。", "會此風月宵，更覺笑語新。", "北城石先生，欲喚不敢頻。", "坐上欠此客，長懷渺無津。", "南方鳳之徒，瑞世五色文。", "鐵石賦梅花，一洗瘴海氛。", "臺家須貢珍，我欲列九閽。", "且補諫官闕，日酌白獸尊。"]'),
('1dc1addd-857b-41b0-ac04-cc0945a99e7f','金沙堆廟有曰忠潔侯者屈大夫也感之賦詩','張孝祥','宋','宋诗','song-poetry','','[]','伍君爲濤頭，妬婦名河津。',180,'全唐诗/poet.song.149000.json','["伍君爲濤頭，妬婦名河津。", "那知屈大夫，亦作主水神。", "我識大夫公，自托腑肺親。", "獨醒梗羣昏，聚臭醜一薰。", "瀝血摧心肝，懷襄如不聞。", "已矣無柰何，質之雲中君。", "天門開九重，帝曰哀汝勤。", "狹世非汝留，賜汝班列真。", "司命馳先驅，太一諏吉辰。", "翩然乘回風，脫迹此水濱。", "朱宮紫具闕，冠珮儼以珍。", "宓妃與娥女，修潔充下陳。", "至今幾千年，玉顔凜如新。", "楚人殊不知，謂公果沉淪。", "年年作端午，兒戲公應嗔。"]'),
('2ccd7942-fdc8-415c-9d70-06dea53e62f6','詠雪','張孝祥','宋','宋诗','song-poetry','','[]','東皇携春來，屬車載霓裳。',96,'全唐诗/poet.song.149000.json','["東皇携春來，屬車載霓裳。", "回風作妙舞，雜珮鳴珠璫。", "千官玉笋班，再拜稱瑶觴。", "酒罷各分瑞，圭琮粲琳琅。", "浩蕩涵濡恩，一笑徧八荒。", "塵垢得湔洗，焦枯亦輝光。", "偉哉造化力，天地爲翕張。", "功成了不居，杲日天中央。"]'),
('8edc6c1a-9c32-46d7-89b5-fa782972758e','題朱元順浯溪圖','張孝祥','宋','宋诗','song-poetry','','[]','去年過浯溪，王事有期程。',144,'全唐诗/poet.song.149000.json','["去年過浯溪，王事有期程。", "夜半度湘水，但見天上星。", "平生中興碑，夢入紫翠屏。", "已辦北歸時，十日窮攀登。", "今朝復何朝，忽此短軸橫。", "歷歷眼中見，湘山無數青。", "白雲著山腰，樓閣秋氣明。", "便欲扶短策，下濯滄浪纓。", "主人山水仙，妙處心自評。", "元順骨已冷，千載交蓋傾。", "賞音寄幅紙，益見忠孝情。", "題詩疥公畫，託我不朽名。"]'),
('2b50f663-1664-464a-96df-6edf6ae64dbf','寄題向彥績史君采菊堂','張孝祥','宋','宋诗','song-poetry','','[]','史君天資高，夙昔事幽屏。',72,'全唐诗/poet.song.149000.json','["史君天資高，夙昔事幽屏。", "長懷渺丘壑，餘習謝鍾鼎。", "東籬羲皇人，槁死骨已冷。", "凄其千載後，妙處一笑領。", "高堂娛白髮，兄弟極整整。", "不須南陽泉，壽與日月等。"]'),
('6260f5bd-1fd8-4c28-a875-2a0983c05672','止酒','張孝祥','宋','宋诗','song-poetry','','[]','飲酒見真性，此酒不可止。',96,'全唐诗/poet.song.149000.json','["飲酒見真性，此酒不可止。", "一飲病三日，止酒寧獲已。", "飲酒有別腸，勸酒無惡意。", "既因酒成病，那識酒真味。", "將軍罵不敬，次公醒而狂。", "破面棖觸人，不如持空觴。", "人言我止酒，似是遣客計。", "但使客常滿，客醉我亦醉。"]'),
('8b4838f6-aa3c-4ab3-a9b5-209b3499c079','昨日極暑今日極寒','張孝祥','宋','宋诗','song-poetry','','[]','昨日火流金，今日風折膠。',120,'全唐诗/poet.song.149000.json','["昨日火流金，今日風折膠。", "昨著綀布衣，今衣弊縕袍。", "赤帝與玄冥，凜凜隔一宵。", "聊將擁爐適，換此揮箑勞。", "冰炭欲盈懷，炎凉不崇朝。", "幻生過隙駒，是身九牛毛。", "等是一寒暑，胡爲自詼嘲。", "萬法從心生，心靜境亦消。", "悟此本來無，絺綌同狐貂。", "還當隠吾几，試聽萬竅號。"]'),
('34014338-b63d-4973-8718-ba45d6a5e395','初得愛巖','張孝祥','宋','宋诗','song-poetry','','[]','高巖劃天門，仄徑通乳穴。',132,'全唐诗/poet.song.149000.json','["高巖劃天門，仄徑通乳穴。", "隈堆青螺髺，嵽嵲白玉闕。", "外有虎豹蹲，中恐蛟蜃蟄。", "東榮俯雷電，西出挾日月。", "萬壑生悲風，六月不知熱。", "但覺駭心目，未易紀筆舌。", "平生山水趣，嶺海最奇絕。", "洞府二十四，未厭屐齒折。", "晚乃得游此，餘地皆僕妾。", "同來六七士，嗜好頗相躡。", "舉酒酹山神，慰汝久湮滅。"]'),
('cc402e21-7e9d-4bff-86ce-9967cbce2673','與邵陽李守二子用東坡韻','張孝祥','宋','宋诗','song-poetry','','[]','兩李有佳句，冰雪灑肺肝。',120,'全唐诗/poet.song.149000.json','["兩李有佳句，冰雪灑肺肝。", "清越石在懸，圓熟珠走盤。", "我家十二樓，下俯千仞湍。", "誰掣白玉瑣，借與二子看。", "臨風度長篴，瘴海爲清寒。", "却立望九州，隘陿非所安。", "便欲馭長鯤，九萬扶摇摶。", "神山在吾牖，弱水空瀰漫。", "回首五千劫，不費一指彈。", "絕笑塵中年，攝提與涒灘。"]'),
('72274e5e-045e-4383-92cb-1dfc7c92b41a','奉送李彥國還廬陵','張孝祥','宋','宋诗','song-poetry','','[]','李生來嶺南，自挾書一束。',120,'全唐诗/poet.song.149000.json','["李生來嶺南，自挾書一束。", "食簞寄蕭寺，矻矻晝夜讀。", "餘子讓頭角，文作翻手速。", "小試不盡能，它日真可卜。", "里中老仙伯，曾對玉堂宿。", "高節老彌厲，名蓋斗南北。", "掖垣我畏友，不愛萬鍾祿。", "卷藏一丘下，勳業所迫逐。", "子歸問道要，儲作饑歲穀。", "富貴偶然耳，吾欲子金玉。"]'),
('a6800e45-5f20-486e-a9f6-d1ebbb9826fe','暑甚得雨與張文伯同登禪智寺','張孝祥','宋','宋诗','song-poetry','','[]','老火陵穉金，聚作三日熱。',156,'全唐诗/poet.song.149000.json','["老火陵穉金，聚作三日熱。", "舟行湘江上，蒸煮到魚鱉。", "黑雲起東北，一震山石裂。", "不知雨來處，但見風卷葉。", "銀河倚天瀉，高浪舞飛雪。", "只聽打篷聲，已覺凉意愜。", "岸傍古佛屋，樓殿頗嵽嵲。", "不辭衝泥去，一看雨脚闊。", "吾宗紫巖客，窮苦志不懾。", "自我來浯溪，奔走已旬浹。", "我懶久廢學，愧子來挈挈。", "相携得偉觀，爲子熾然說。", "願子領話頭，吾今指摽月。"]'),
('460f3074-92d1-4e8c-853a-5d42ffe2aeb0','丙戌七夕入衡陽境獨游岸傍小寺','張孝祥','宋','宋诗','song-poetry','','[]','七年暑中行，道路萬里賒。',168,'全唐诗/poet.song.149000.json','["七年暑中行，道路萬里賒。", "今夕已七夕，我猶在天涯。", "繫船蒼石根，人影散晚沙。", "上岸是修竹，仄徑如行蛇。", "茅屋四五間，往昔佛所家。", "經禪劫火盡，舊觀初萌芽。", "牆疊古瓦盆，僧披破袈裟。", "喜聞拄杖聲，掃地自點茶。", "何以爲我娛，冰雪汲井花。", "一洗十日渴，分凉到童髽。", "盈盈牛女期，不著雨洗車。", "疏星銀漢動，新月玉鈎斜。", "更呼老奚官，卷蘆作鳴笳。", "莫驚潭中龍，聊起棲樹鴉。"]'),
('73273cf1-3311-4f1d-8916-d165ff1ee670','福嚴','張孝祥','宋','宋诗','song-poetry','','[]','行行山益高，所見益以奇。',217,'全唐诗/poet.song.149000.json','["行行山益高，所見益以奇。", "煮茶南臺寺，更上千級梯。", "道傍古時松，閲世心已灰。", "不與歲月競，况受霜雪威。", "路回聞鐘聲，寶剎隠翠微。", "排空寫金碧，刓石著栱枅。", "門前兜率橋，劫火昔所遺。", "神龍厭庳陋，一炬然枯萁。", "譚笑舊觀還，殿柱百尺圍。", "老禪七十餘，高與此山齊。", "大屋貯龍象，空巖走金犀。", "齋盂細細參，至味無鹽醯。", "頗聞三生藏，中有萬寶齎。", "佛牙舍利湧，貝葉旁行稀。", "剖蚌慈相尊，破匣血縷飛。", "稽首所願觀，爲洗往昔非。", "却尋上山路，擬看浴日池。", "急雨忽留人，吾其具少須之。"]'),
('ba06967f-bc8c-4c1d-9789-40ae6ee9f4cd','湖湘以竹車激水秔稻如雲書此能仁院壁','張孝祥','宋','宋诗','song-poetry','','["\u8d5e\u9882", "\u6c34", "\u519c\u6751"]','象龍喚不應，竹龍起行雨。',120,'全唐诗/poet.song.149000.json','["象龍喚不應，竹龍起行雨。", "聯綿十車輻，伊軋百舟櫓。", "轉此大法輪，救汝旱歲苦。", "橫江鎖巨石，濺瀑疊城鼓。", "神機日夜運，甘澤高下普。", "老農用不知，瞬息了千畝。", "抱孫带黄犢，但看翠浪舞。", "餘波及井臼，舂玉飲酡乳。", "江吳誇七蹋，足繭腰背僂。", "此樂殊未知，吾歸當教汝。"]'),
('75fe24d6-3d34-43c3-bf67-77a83f773303','贈黄司法','張孝祥','宋','宋诗','song-poetry','','[]','吾友黄升卿，乃是天下士。',84,'全唐诗/poet.song.149000.json','["吾友黄升卿，乃是天下士。", "阿翁苦硬節，御坐留諫紙。", "辛勤教其子，不但爲科第。", "一官法曹掾，整整老胥忌。", "吾行桂嶺南，所得但吾子。", "願渠自愛惜，窮達初不計。", "功名儻來耳，期子以千歲。"]'),
('2f0e5fdd-a863-40dd-9c08-f9875df332af','宵征','張孝祥','宋','宋诗','song-poetry','','[]','畏暑倦長道，呼童戒宵征。',84,'全唐诗/poet.song.149000.json','["畏暑倦長道，呼童戒宵征。", "三更渡前溪，溪水清且鳴。", "舟人自相喚，炬火如疎星。", "俯視亂石多，仰見北斗橫。", "微微白露下，磔磔宿鳥驚。", "竹輿出林薄，十里月漸明。", "光采散草木，凉意侵冠纓。"]'),
('b69ff364-73cb-4d92-bb26-f8f6013220c9','汎湘江','張孝祥','宋','宋诗','song-poetry','','[]','十日行湘江，湘水清而溫。',72,'全唐诗/poet.song.149000.json','["十日行湘江，湘水清而溫。", "不療亭午渴，却憶土井渾。", "道傍古剎竿，著屋高樹根。", "飛泉出山腹，甘冷冰瓶盆。", "何止解百憂，一灑塵埃昏。", "設供者誰與，稽首兩足尊。"]'),
('87396c24-d65e-4427-8d09-f398a42d8573','上封寺','張孝祥','宋','宋诗','song-poetry','','[]','七月十五夜，我在祝融峯。',72,'全唐诗/poet.song.149000.json','["七月十五夜，我在祝融峯。", "與世隔幾塵，上天通九重。", "手取白玉盤，納之朱陵宮。", "羣山羅豆豋，萬籟酣笙鏞。", "盡酌五湖水，勸我酒一鍾。", "爲君賦長言，寫向西北風。"]'),
('2b481b92-9e19-4b65-a9e1-8416e353cb9e','岸傍偶得木犀','張孝祥','宋','宋诗','song-poetry','','[]','天公不求金，富媼不復藏。',120,'全唐诗/poet.song.149000.json','["天公不求金，富媼不復藏。", "居然土同價，散作草木芳。", "英英園中葵，一心傾太陽。", "采采籬下菊，令汝壽命康。", "惟此木之犀，更貯萬斛香。", "雄姿傲霜雪，鱗甲森青蒼。", "三賢鼎足立，正色凜相望。", "豈比桃李徒，紅紫紛披昌。", "聊息貪者心，來上君子堂。", "歲晚從我遊，寘汝兄弟行。"]'),
('d6682c3e-57f7-4400-9ed7-e67fb5fbf60d','王弱翁與余相遇漢口賦古意贈別','張孝祥','宋','宋诗','song-poetry','','[]','我船行荆江，厭此江水渾。',72,'全唐诗/poet.song.149000.json','["我船行荆江，厭此江水渾。", "北風知人意，引著清漢濱。", "漢濱有佳人，心與漢水白。", "涉江弄秋葉，喚客踏明月。", "明月永相望，佳人不可忘。", "期君以千年，珮我明珠璫。"]'),
('740bada4-a648-4275-afda-c51abae45164','贈朱遠遊','張孝祥','宋','宋诗','song-poetry','','[]','遠遊何方來，峩峩古衣冠。',72,'全唐诗/poet.song.149000.json','["遠遊何方來，峩峩古衣冠。", "袖中三百篇，貯月白玉盤。", "溪清石瀨急，雪凍銅壺乾。", "有如山澤仙，外瘠中氣完。", "便合朱絃彈，細著青瑶刊。", "懷哉人未識，飛步江風寒。"]'),
('c7fd400a-9855-4cb8-8ab9-144ddfa3372a','和張欽夫尋梅','張孝祥','宋','宋诗','song-poetry','','[]','寒梅本無心，適與春風期。',96,'全唐诗/poet.song.149000.json','["寒梅本無心，適與春風期。", "孤根擢歲晚，桃李更媢之。", "取我碧玉壺，薦此白雪枝。", "故人不可寄，耿耿空自奇。", "故人隔湘江，獨立知者稀。", "采香正滋蘭，忍饑不食薇。", "拏舟許過我，此約不可違。", "江南煙雨村，願與子俱歸。"]'),
('ddb9c482-e765-487e-87c4-679f74043e36','黄龍侍者本高覓詩','張孝祥','宋','宋诗','song-poetry','','[]','高禪本儒冠，誰令著伽黎。',72,'全唐诗/poet.song.149000.json','["高禪本儒冠，誰令著伽黎。", "勞渠千里來，贈我一卷詩。", "句法有源流，人物乃清苦。", "不用追九僧，政須越諸祖。", "君家寒巖師，今代僧中龍。", "持此送君行，更去問乃翁。"]'),
('0ec0d039-f9b9-49c3-8d79-3ccab68e3e81','題濁醪賦後','張孝祥','宋','宋诗','song-poetry','','[]','仇公昔釣璜，乃得丹竈術。',72,'全唐诗/poet.song.149000.json','["仇公昔釣璜，乃得丹竈術。", "閉門養真火，贛甕釀新秫。", "酒熟分四鄰，丹成活千人。", "窮巷不改樂，一室長如春。", "我知酒中仙，歲晚當得度。", "乘雲見東皇，請誦濁醪賦。"]'),
('9a756be3-e874-453c-862c-e8b03f2c286e','屢登橫舟欲賦不成阻風漢口乃追作寄趙富文楊齊伯','張孝祥','宋','宋诗','song-poetry','','[]','已過漢陽岸，却望橫舟山。',72,'全唐诗/poet.song.149000.json','["已過漢陽岸，却望橫舟山。", "秀色挹不盡，西風將夢還。", "我昔登橫舟，最愛漢陽樹。", "橫舟今不見，樹色只如故。", "公舟在青冥，我舟一浮萍。", "闌干試拍手，我亦同舉酒。"]'),
('2656814b-e31f-4b94-bd69-362ce92035fc','棲真寄南康錢守','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶昔姑蘇臺，實與君子別。',108,'全唐诗/poet.song.149000.json','["憶昔姑蘇臺，實與君子別。", "一別已六年，音書間何闊。", "我行半天下，塵土汙鬚髮。", "君亦抱艱棘，衣袂灑清血。", "今日復何日，相望一山隔。", "我領通玄府，乃在廬山北。", "君宦山之南，兵衛森畫戟。", "無由接杯酒，但可共明月。", "作詩付郵筒，聊復寄消息。"]'),
('22df6d96-8a19-4923-815d-85a2ea667303','黄子餘自海昏見予於九江欲行爲賦此詩','張孝祥','宋','宋诗','song-poetry','','[]','昔我初識君，乃在潯陽城。',72,'全唐诗/poet.song.149000.json','["昔我初識君，乃在潯陽城。", "却數已十年，此地還見君。", "積雨楚水高，落日淮山明。", "我病不舉酒，何以娛佳賓。", "我行不可留，明復與君別。", "悠悠千里情，還當付明月。"]'),
('7ad2202d-4826-45ad-aa15-d85e36880c6b','勸范東叔飲','張孝祥','宋','宋诗','song-poetry','','[]','今代太史公，四海范氏門。',72,'全唐诗/poet.song.149000.json','["今代太史公，四海范氏門。", "斯文十世澤，斑斑被諸孫。", "我識叔西父，白玉比粹溫。", "今來見令弟，俊氣百馬奔。", "一第溷子耳，勿愧而家尊。", "臨分無多言，更酌老瓦盆。"]'),
('9480cfe2-8d94-44f7-b013-e77fd91fb8fa','留題彭澤故縣修真觀','張孝祥','宋','宋诗','song-poetry','','[]','五月問修途，今日一百里。',60,'全唐诗/poet.song.149000.json','["五月問修途，今日一百里。", "莫投彭澤縣，愧此邑中士。", "古觀官道傍，借榻暫少憩。", "折腰向道士，乞我五斗米。", "聊爲奴僕飯，明日更早起。"]'),
('d0b6fcee-6cf6-4e8b-830f-89e730ec5f09','湘中館','張孝祥','宋','宋诗','song-poetry','','[]','雲去月在沙，潦凈秋滿川。',108,'全唐诗/poet.song.149000.json','["雲去月在沙，潦凈秋滿川。", "北斗挂落木，西風送歸船。", "去年過湘中，夜半投馬鞭。", "篝燈洗塵土，所見只屋椽。", "雞鳴問前途，殘夢兀擔肩。", "那知闌干外，有此山水妍。", "微微清露漙，稍稍明河偏。", "孤光耿自照，靜極忻所便。", "身世兩悠然，吾其遂飛仙。"]'),
('092b1494-fe93-417a-93c8-6cedb9585e8e','中隠','張孝祥','宋','宋诗','song-poetry','','[]','吾家中隠君，才比萬斛泉。',132,'全唐诗/poet.song.149000.json','["吾家中隠君，才比萬斛泉。", "短小精悍姿，一劍當雄邊。", "去年郴州賊，俯視衡嶽顛。", "君從襄陽來，孤忠作戈鋋。", "譚笑百雉安，凈洗湖嶺煙。", "謂當酬王勳，金印如斗懸。", "言歸遽如許，此意誰爲宣。", "小隠即居山，大隠即居廛。", "夫君處其中，政爾當留連。", "早晚有詔書，喚君遠朝天。", "欲爲中隠遊，更著三十年。"]'),
('126c3752-2f76-4080-8422-c9341b2965c0','贈師永錫併簡子西文潜','張孝祥','宋','宋诗','song-poetry','','[]','永錫西方來，持論乃據正。',96,'全唐诗/poet.song.149000.json','["永錫西方來，持論乃據正。", "健飯不飲酒，自詭作縣令。", "我已識淮父，但未見伯渾。", "林林三珠樹，知是難弟昆。", "上方顧中原，有君但無臣。", "豈有千里足，而令走踆踆。", "願子徑入關，請對通明殿。", "此事定在我，不必問和戰。"]'),
('52c8d39b-133c-4c58-939e-b8182052294e','萍鄉境上有驛傍有老杉餘百本余過而愛之驛無名余名之曰愛直而爲之詩又以告邑大夫趙君公廩曰使繼自今爲令者幸如君之賢也則此杉長存不然將斧斤斯民以自封植於杉何有','張孝祥','宋','宋诗','song-poetry','','[]','此杉已百年，林立官道側。',72,'全唐诗/poet.song.149000.json','["此杉已百年，林立官道側。", "鬼神所訶護，斤斧不敢迫。", "愛此遺直姿，凜凜有正色。", "未云支大厦，聊以蔭行客。", "作詩調令尹，爲我驛壁刻。", "但使杉長存，懸知令清白。"]'),
('aa99af54-2747-4c84-a0d7-cb55ba187010','遊千山觀','張孝祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','朝遊七星巖，莫上千山觀。',144,'全唐诗/poet.song.149000.json','["朝遊七星巖，莫上千山觀。", "東西兩奇絕，勢略領海半。", "長江寫縑素，疊嶂俯杯案。", "中有萬雉城，鐵立不可玩。", "伏龍起行雨，老樹舞影亂。", "衝風挾驚電，意恐崖谷斷。", "路懸石磴滑，衆客紛駭汗。", "嵌空偶自託，發若鳥集灌。", "須臾便開霽，杲日麗清漢。", "却坐山巔亭，容我烏幘岸。", "長懷付尊酒，別語不容判。", "會須九垓外，與子期汗漫。"]'),
('9bf61374-6aca-4602-87b7-ef48c392150f','庚辰二月夜雪','張孝祥','宋','宋诗','song-poetry','','[]','夜半雨鳴廊，晨起雪暗空。',72,'全唐诗/poet.song.149000.json','["夜半雨鳴廊，晨起雪暗空。", "不減臘月寒，故作昨日風。", "融銀擁山腰，飛花滿裘茸。", "辦此了不難，咳唾煩天工。", "纖纖園中花，一夕無光容。", "凜凜庭下松，巍然兩蒼龍。"]'),
('5d6203ad-e4d9-46aa-85ca-476a829158ea','張欽夫笋脯甚佳秘其方不以示人戲遣此詩','張孝祥','宋','宋诗','song-poetry','','[]','使君喜食笋，笋脯味勝肉。',59,'全唐诗/poet.song.149000.json','["使君喜食笋，笋脯味勝肉。", "秘法不肯傳，閉門課私僕。", "君不見金谷饌客本萍虀，豪世藉此真成癡。", "但令長須日致饋，不敢求君帳下兒。"]'),
('f3733918-2619-498e-9a7c-6fe9059df032','蒙和答益奇輒復爲謝','張孝祥','宋','宋诗','song-poetry','','[]','齋厨極蕭條，晚食以當肉。',56,'全唐诗/poet.song.149000.json','["齋厨極蕭條，晚食以當肉。", "公來共蔬盤，留語輒更僕。", "平生懲沸仍吹虀，欲了官事渠能癡。", "何時竟作淮南歸，擊鮮校獵從廬兒。"]'),
('ee250c3f-0350-450c-afbf-6d9c263a556e','張欽夫送笋脯與方俱來復作','張孝祥','宋','宋诗','song-poetry','','[]','笋脯登吾盤，可使食無肉。',56,'全唐诗/poet.song.149000.json','["笋脯登吾盤，可使食無肉。", "鮭腥辟三舍，棕栮乃臣僕。", "書生長有十甕虀，却笑虎頭骨相癡。", "得君新法也大奇，且復從游錦綳兒。"]'),
('37455d58-1269-40d7-8c23-2a08706365bc','勸農以湘波不動楚山碧花壓闌干春晝長爲韻得干字','張孝祥','宋','宋诗','song-poetry','','[]','積雨已連月，長沙尚春寒。',156,'全唐诗/poet.song.149000.json','["積雨已連月，長沙尚春寒。", "今朝定何朝，喚客來江干。", "問訊湘西寺，霧重江漫漫。", "聊須萬斛舟，渡此千尺湍。", "老松如相迎，翠落頭上冠。", "却望城中花，寶髻垂珠鬘。", "勸農有故事，般樂非所安。", "薄晚會春園，老稚隨馬鞍。", "彘肩侑尊酒，呼喚來同盤。", "從容及鄙事，爾汝開心肝。", "我是耕田夫，偶然此爲官。", "飽不知稼穡，愧汝催租瘢。", "願言各努力，長年好相看。"]'),
('f4e55685-c5fa-4df3-bb84-a3765292e72b','陳仲思以太夫人高年奉祠便養卜居城東茅屋數間澹如也移花種竹山林丘壑之勝湘州所無食不足而樂有餘謂古之隠君子若仲思者非耶乾道戊子六月某同張欽夫過焉裴回彌日既莫而忘去欽夫欲專壑買鄰欽夫有詩某次韻','張孝祥','宋','宋诗','song-poetry','','[]','平生交游中，此士故耐久。',192,'全唐诗/poet.song.149000.json','["平生交游中，此士故耐久。", "不折爲米腰，頗袖斲輪手。", "卜居并東郭，草草宮一畝。", "日課種樹書，箋題徧窗牖。", "花草當姬妾，松竹是朋友。", "上堂娛偏親，家飯隨野蔌。", "客至即舉詩，興來亦沽酒。", "清溪遶屋角，高木老未朽。", "翻翻荷見背，戢戢魚駢首。", "幽觀天所藏，勝踐我獨後。", "不因南軒君，茲遊幾時有。", "爲君便買鄰，溪南好岡阜。", "我喜君亦狂，呼兒挈尊卣。", "一灑塵埃胸，快若苗去莠。", "夜凉佳月出，人影散箕斗。", "恨我當先歸，君能小留否。"]'),
('ae1f63f2-d05e-45dd-a656-8221419d84a8','贈陳監廟','張孝祥','宋','宋诗','song-poetry','','[]','陳子居城東，茆屋三四間。',120,'全唐诗/poet.song.149000.json','["陳子居城東，茆屋三四間。", "下有五畝園，灌畦泐清灣。", "松柏充羽葆，荷芰作髻鬟。", "再拜太夫人，壽比衡麓慳。", "我早與子遊，期子到孔顔。", "察子意甚真，不與時輩班。", "扁舟漾荆渚，餘子頗謗訕。", "大道甚坦夷，勿歎行路難。", "彼自種荆棘，吾寧翦榛菅。", "一醉乘秋風，共此霜月彎。"]'),
('d9b91388-1c21-4fc3-a605-eeb0565c3ae1','送邵懷英分魯直詩韻人間風日不到處天上玉堂森寶書得書字','張孝祥','宋','宋诗','song-poetry','','[]','將酒澆君車，問君行何如。',120,'全唐诗/poet.song.149000.json','["將酒澆君車，問君行何如。", "初無十萬錢，但有一束書。", "往昔千官班，渠曾綴簪裾。", "日月九門隔，江湖十年餘。", "老榦久凌剝，寒灰費吹噓。", "今者尺一追，問津承明廬。", "蓬萊道家山，紫極帝所居。", "功名儻來爾，步武當徐徐。", "遥岑出疎林，淺水行游魚。", "臨分再三囑，音信莫我疎。"]'),
('9676dcb4-1b5f-4196-93e1-3d4f92a04fc5','送張定叟','張孝祥','宋','宋诗','song-poetry','','[]','戊子歲二月，定叟如南山。',132,'全唐诗/poet.song.149000.json','["戊子歲二月，定叟如南山。", "行李太匆草，問君何當還。", "敬展南陽阡，永慕涕已潸。", "畢事却登攬，紓子悲悴顔。", "羣峯最高處，眼界窮塵寰。", "紫蓋款佛剎，黄庭扣玄關。", "夜榻藉雲衲，曉窗闖煙鬟。", "野飯薦笋蕨，幽尋翦榛菅。", "酒賤可痛飲，詩成要重刪。", "勿作賈胡留，閨人賦刀環。", "歸時買竹䶉，小破行囊慳。"]'),
('90765e14-0635-4066-b18f-977b89e28a86','朱陵洞','張孝祥','宋','宋诗','song-poetry','','[]','黑雲起我趾，白雨過山脚。',48,'全唐诗/poet.song.149000.json','["黑雲起我趾，白雨過山脚。", "却立朱陵洞，一望紫虛閣。", "神丹吾已必，仙臂真可握。", "試向靜處聽，空濛有笙鶴。"]'),
('c23f1897-0067-41d8-b65d-123ea2646dd2','題屏風送裘甫歸臨川','張孝祥','宋','宋诗','song-poetry','','[]','不見已四年，既見還作別。',48,'全唐诗/poet.song.149000.json','["不見已四年，既見還作別。", "贈以墨竹屏，况此君子節。", "歲月不我留，玉立空山陰。", "願言無相忘，因風時寄音。"]'),
('e923fcf6-7412-41e0-bb70-8e1043afef5c','送道州酒與吳伯承','張孝祥','宋','宋诗','song-poetry','','[]','陽城所臨州，酒味猶清醇。',48,'全唐诗/poet.song.149000.json','["陽城所臨州，酒味猶清醇。", "我病不能飲，負此盎盎春。", "髯吳燒苦笋，喚客車連軫。", "名酒隨惡詩，掀髯一笑囅。"]'),
('22254871-31d2-4369-9e39-a4f71dd91207','葵軒觀笋','張孝祥','宋','宋诗','song-poetry','','[]','葵軒新笋生，戢戢水蒼玉。',48,'全唐诗/poet.song.149000.json','["葵軒新笋生，戢戢水蒼玉。", "脫籜便林立，爾輩殊窘束。", "黄梅四月雨，念子亦良苦。", "十二鳳凰鳴，秋風何處聲。"]'),
('2be611b8-155f-47ac-a268-c360327f4391','贈尹童子夢龍','張孝祥','宋','宋诗','song-poetry','','[]','長沙尹氏子，四歲誦萬言。',60,'全唐诗/poet.song.149000.json','["長沙尹氏子，四歲誦萬言。", "青松一寸長，歲晚當摩天。", "終爲棟梁用，莫作桷與椽。", "斫根刳其明，本瘁末亦顛。", "持此勸乃翁，閉門養真源。"]'),
('c940f475-5941-4a54-b2c4-796777eb1295','一覽亭','張孝祥','宋','宋诗','song-poetry','','[]','城中十萬戶，亭脚五千丈。',48,'全唐诗/poet.song.149000.json','["城中十萬戶，亭脚五千丈。", "小退鴈鶩行，却立雲雨上。", "主人心如此，坐了鏡中像。", "沙尾是我船，煙波更空曠。"]'),
('a1ae065c-62c9-4421-a655-3abae552245f','睡起','張孝祥','宋','宋诗','song-poetry','','[]','睡起有佳聲，蕭蕭竹間雨。',48,'全唐诗/poet.song.149000.json','["睡起有佳聲，蕭蕭竹間雨。", "蒿廬澹無營，一榻不受暑。", "微颸入牖來，喚起香中縷。", "撫卷忽超然，空梁走饑鼠。"]'),
('95369c60-97bd-425d-afc5-008dcc0fef7e','吳伯承送苦笋消梅用來韻各賦一篇  其一','張孝祥','宋','宋诗','song-poetry','','[]','問訊湘西笋，政得夜來雨。',24,'全唐诗/poet.song.149000.json','["問訊湘西笋，政得夜來雨。", "高標諸枉直，餘味良藥苦。"]'),
('19b50341-6e33-4512-832a-bff4db95f937','吳伯承送苦笋消梅用來韻各賦一篇  其二','張孝祥','宋','宋诗','song-poetry','','[]','脆圓供小摘，不待四月雨。',24,'全唐诗/poet.song.149000.json','["脆圓供小摘，不待四月雨。", "新詩同咀嚼，學子心獨苦。"]'),
('8fbabb80-18c5-44ec-b29f-232ea54d725f','戲書贈蘇待問','張孝祥','宋','宋诗','song-poetry','','[]','從公覓此紙，欲與蘇待問。',48,'全唐诗/poet.song.149000.json','["從公覓此紙，欲與蘇待問。", "醉中墨鴉黑，北風起雲陣。", "明朝酒醒看，爲子傳心印。", "子若不領略，取火燒作燼。"]'),
('5d37a497-d1ba-4bbb-b09a-643f542eef01','贈震山主','張孝祥','宋','宋诗','song-poetry','','[]','震公住山年，與我共壬子。',48,'全唐诗/poet.song.149000.json','["震公住山年，與我共壬子。", "瓦礫化金碧，願力一彈指。", "鄉來祖師禪，風定月滿天。", "語子義第一，饑餐困當眠。"]'),
('9a1c1f8c-5730-425f-994f-ac660d942da0','春盡日送聞人伯卿次家君韻','張孝祥','宋','宋诗','song-poetry','','[]','早年翰墨場，未見心已親。',48,'全唐诗/poet.song.149000.json','["早年翰墨場，未見心已親。", "筆底三峽流，胸次萬卷春。", "相從未淹時，欲別故惱人。", "敢賡老仙詩，索去不用頻。"]'),
('ad494df1-7b61-4d0b-b646-5ce71127af85','洗塵贈張立之判官','張孝祥','宋','宋诗','song-poetry','','[]','立之居糟丘，胸有萬斛塵。',48,'全唐诗/poet.song.149000.json','["立之居糟丘，胸有萬斛塵。", "歸來卧西窗，涇渭自此分。", "汙泥生芙蕖，榛墟有白雲。", "莫厭吏事煩，願子清天君。"]'),
('18b832cb-76d3-4209-8720-8834d326a1c0','王龜齡賦喜雨諸賢畢和某客行半月未嘗晴也故於末章云  其一','張孝祥','宋','宋诗','song-poetry','','[]','久旱一雨足，高低水平分。',48,'全唐诗/poet.song.149000.json','["久旱一雨足，高低水平分。", "老農爾何知，史君甚艱勤。", "史君家鴈山，出作無心雲。", "四海方立槁，須君來救焚。"]'),
('0ce50b60-cab5-4855-bc7c-09cc8da1bc30','王龜齡賦喜雨諸賢畢和某客行半月未嘗晴也故於末章云  其二','張孝祥','宋','宋诗','song-poetry','','[]','客行苦淫潦，道路渺不分。',48,'全唐诗/poet.song.149000.json','["客行苦淫潦，道路渺不分。", "十步九掀淖，眷言僕夫勤。", "昔旱欲訟風，今雨當誅雲。", "我已寫綠章，擬向清夜焚。"]'),
('d7afc8d0-9628-49b4-bb11-df3e69de4b09','八桂堂池上賞蓮納凉','張孝祥','宋','宋诗','song-poetry','','[]','山月半池白，水風終夜凉。',48,'全唐诗/poet.song.149000.json','["山月半池白，水風終夜凉。", "蛙聲作鼓吹，芰製爲衣裳。", "萬里俱遠客，三人同一觴。", "但使嶺海豐，此樂未渠央。"]'),
('196fac26-d228-4dd0-98e6-818898b1e5c5','前日出城苗猶立槁今日過興安境上田水灌輸鬰然彌望有秋可必乃知賢者之政神速如此輒寄呈交代仲欽秘閣','張孝祥','宋','宋诗','song-poetry','','[]','筒車無停輪，木枧著高格。',48,'全唐诗/poet.song.149000.json','["筒車無停輪，木枧著高格。", "秔稌接新潤，草木丐餘澤。", "府公爲霖手，號令行頃刻。", "願持一勺水，敬往壽南伯。"]'),
('dca46e4f-b098-49d0-8aa9-1d06806d50f9','南臺','張孝祥','宋','宋诗','song-poetry','','[]','我遊衡嶽巔，路半此歇脚。',48,'全唐诗/poet.song.149000.json','["我遊衡嶽巔，路半此歇脚。", "風雷駕飛殿，日月隠傑閣。", "闌干十萬里，仰視天一握。", "遂訪紫虛君，歸時騎白鶴。"]'),
('82b3d822-1def-4c53-a8f7-7098d39c9138','書懷','張孝祥','宋','宋诗','song-poetry','','[]','七夕在衡陽，九日在蘄州。',48,'全唐诗/poet.song.149000.json','["七夕在衡陽，九日在蘄州。", "秋風浩如海，我行尚扁舟。", "破帽不堪落，菊花空滿頭。", "醉眼忽瞠若，悠然過滄洲。"]'),
('2ab348a9-7737-4193-9403-9a23e2d92467','元宵同張欽夫邵懷英分韻得紅旗字  其一','張孝祥','宋','宋诗','song-poetry','','[]','佳月妬纖雲，微和扇東風。',48,'全唐诗/poet.song.149000.json','["佳月妬纖雲，微和扇東風。", "聊持一杯淥，共此千燈紅。", "吾宗延閣英，聖學與天通。", "且最治郡課，遂收活國功。"]'),
('3d6c70c6-987e-45a4-ab92-4676817f38ee','元宵同張欽夫邵懷英分韻得紅旗字  其二','張孝祥','宋','宋诗','song-poetry','','[]','邵子坐學官，今日有詔追。',48,'全唐诗/poet.song.149000.json','["邵子坐學官，今日有詔追。", "道山萃竹帛，武庫森戈旗。", "文武要兩有，腐儒不足爲。", "明年燕端門，舉酒還相思。"]'),
('89804aa5-e788-43d0-8998-4f5711470eec','贈盧司法','張孝祥','宋','宋诗','song-poetry','','[]','逃秦盧博士，讀書不讀律。',48,'全唐诗/poet.song.149000.json','["逃秦盧博士，讀書不讀律。", "江陵法曹掾，移病滿百日。", "燕坐供佛香，青燈照繩床。", "肺熱今無恙，門前春草長。"]'),
('112391ca-7da1-472d-9611-872bdfe714d2','進芝草  其一','張孝祥','宋','宋诗','song-poetry','','[]','廟錫珍符豈偶然，靈華再見只經年。',64,'全唐诗/poet.song.149000.json','["廟錫珍符豈偶然，靈華再見只經年。", "祥開二室昭貽燕，根託同楹自屬聯。", "上瑞應誠雖紹至，宸衷思孝益增虔。", "微臣願考皇天意，不獻終童效異篇。"]'),
('c3a10e09-4a8f-4e68-a399-699b88c52033','進芝草  其二','張孝祥','宋','宋诗','song-poetry','','[]','煌煌瑞彩映金鋪，元氣回旋即此都。',64,'全唐诗/poet.song.149000.json','["煌煌瑞彩映金鋪，元氣回旋即此都。", "太史連年書盛事，近臣更日奏新圖。", "璇宮薦祉寧虛應，玉葉流芳已兆符。", "早晚清塵款原廟，臨觀敢請駐前驅。"]'),
('643dcac9-4070-4423-99b3-305695039c88','某頃蒙信陽使君教以邊字韻佳句伏讀降歎病倦答謝甚緩復不能奇仰俟斲削  其一','張孝祥','宋','宋诗','song-poetry','','[]','風流追數建安年，誰遣朱轓并塞邊。',64,'全唐诗/poet.song.149000.json','["風流追數建安年，誰遣朱轓并塞邊。", "舉國向來儒服少，是邦端有大夫賢。", "須公帷幄收長策，著我江湖刺釣船。", "池閣追凉肯臨否，紅粧翠蓋擁三千。"]'),
('5af55079-ad51-4063-a07c-6dc80061662d','某頃蒙信陽使君教以邊字韻佳句伏讀降歎病倦答謝甚緩復不能奇仰俟斲削  其二','張孝祥','宋','宋诗','song-poetry','','[]','百適歸來又一年，投身烽火戍樓邊。',64,'全唐诗/poet.song.149000.json','["百適歸來又一年，投身烽火戍樓邊。", "私憂自笑愚無策，制勝懸知國有賢。", "北去燕然堪勒石，西來樊口看燒船。", "中州更有王夫子，筆陣猶能獨掃千。"]'),
('409febc4-c569-4f1d-aa9d-2d778bf7e1b0','子雲壓境先遣詩次韻','張孝祥','宋','宋诗','song-poetry','','[]','相風日日問長年，鷁首遥知近箇邊。',64,'全唐诗/poet.song.149000.json','["相風日日問長年，鷁首遥知近箇邊。", "別後情親難過我，故家人物更誰賢。", "一尊且對荒城酒，六月休牽上水船。", "小此淹留待追詔，公車歸奏牘三千。"]'),
('e8615f45-f383-4367-95fc-00944dc4710a','送劉伯同侍開府公入覲','張孝祥','宋','宋诗','song-poetry','','[]','相公早勒太常銘，康樂當家更典刑。',64,'全唐诗/poet.song.149000.json','["相公早勒太常銘，康樂當家更典刑。", "槍急曾看飛鳥過，筆精時作換鵝經。", "極知許國心常赤，趁取封侯鬢尚青。", "若到都城見知舊，爲言江漢有浮萍。"]'),
('2cdb6cf0-5206-4b59-9eca-8d9a84c7e54d','送子雲倅荆州  其一','張孝祥','宋','宋诗','song-poetry','','[]','閲世波流險未涯，愛君悃愊靜無華。',64,'全唐诗/poet.song.149000.json','["閲世波流險未涯，愛君悃愊靜無華。", "高門自惜聯三㦸，飛珮何當乞九霞。", "喬木世臣餘故國，采蘋齊女甚宜家。", "君王早晚思前席，會有徵書訪賈嘉。"]'),
('a56d6f0f-61b8-47cf-a054-7c4e99b9825c','送子雲倅荆州  其二','張孝祥','宋','宋诗','song-poetry','','[]','荆吳相望各天涯，惜別尊前菊未華。',64,'全唐诗/poet.song.149000.json','["荆吳相望各天涯，惜別尊前菊未華。", "便放扁舟衝駭浪，要看秋日冠輕霞。", "新詩滿路分吾子，盛業康時是故家。", "好去依劉靜邊瑣，策勳行即賜褒嘉。"]'),
('5f22911c-2d57-43e9-922d-79fc2e4524c9','枕上聞雪呈趙郭二丈','張孝祥','宋','宋诗','song-poetry','','[]','上瑞來寧玉座憂，夜聲先到竹窗幽。',64,'全唐诗/poet.song.149000.json','["上瑞來寧玉座憂，夜聲先到竹窗幽。", "饑腸已作來年飽，病眼聊須臘月收。", "高士清貧無弊履，故人狂興阻扁舟。", "却思清曠江邊路，鶉兔成車酒自篘。"]'),
('9dc9e79b-9e77-4ed1-a943-519d03bbd3fb','湖上晚歸遇雨','張孝祥','宋','宋诗','song-poetry','','[]','陰雲靄靄草萋萋，晚過東湖雨濕衣。',64,'全唐诗/poet.song.149000.json','["陰雲靄靄草萋萋，晚過東湖雨濕衣。", "細柳含煙凝翠色，浮鷗戲水弄晴暉。", "輕舟繫纜斜依岸，釣子收綸欲下磯。", "湖上人家未扃戶，兒童蓑笠負薪歸。"]'),
('b4894782-f59d-43b2-85c6-a0a827071c05','雨入廬山','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夢想羌廬一段奇，經行那得雨追隨。',64,'全唐诗/poet.song.149000.json','["夢想羌廬一段奇，經行那得雨追隨。", "晴來見說山逾好，勝處如今我自知。", "虛室真人珠咳唾，卍庵老子白鬚眉。", "并游三士風流甚，袖手傍觀定有詩。"]'),
('cd30a886-c81d-4838-a8ea-fa835f462a0a','再和','張孝祥','宋','宋诗','song-poetry','','[]','借雨尋山故自奇，幕中佳客肯相隨。',64,'全唐诗/poet.song.149000.json','["借雨尋山故自奇，幕中佳客肯相隨。", "清游端拜史君賜，此樂詎容兒輩知。", "暗谷水來鳴雜佩，遠峯煙斷出脩眉。", "庾樓百尺江千里，遥憶憑高政索詩。"]'),
('4e727fba-1a96-487a-962e-9f21149a9f9e','郡侯遣騎至山中餽名醖輒呈長句用黄宰韻','張孝祥','宋','宋诗','song-poetry','','[]','山南山北雨生寒，竹樹風煙蒼莽間。',64,'全唐诗/poet.song.149000.json','["山南山北雨生寒，竹樹風煙蒼莽間。", "青壁倚天元未見，白衣送酒故相關。", "共追蓮社公應許，穩上籃輿我欲還。", "後日重來拚一月，細扶藜杖覓孱顔。"]'),
('55ae64b3-904e-4440-9c03-4cc2c862a7ac','去年正月三日雪霽入昭亭訪應庵如庵二老今年在臨川追懷昔游用寄卍庵韻','張孝祥','宋','宋诗','song-poetry','','[]','蹇馿衝雪度松林，齧石溪流有令音。',64,'全唐诗/poet.song.149000.json','["蹇馿衝雪度松林，齧石溪流有令音。", "旋摘白雲濡燥吻，更參黄蘗印初心。", "嵐開複嶺雲千疊，凍合浮圖玉數尋。", "一夢經年歸去好，宦情全薄此情深。"]'),
('0a4c1dd8-1182-44c2-9615-74cfe6cd7beb','卍庵自東林欲還蜀某以報恩招之大人賦詩勸請再次韻','張孝祥','宋','宋诗','song-poetry','','[]','憶携拄杖過東林，掣電奔雷聽法音。',64,'全唐诗/poet.song.149000.json','["憶携拄杖過東林，掣電奔雷聽法音。", "青壁倚天元滿眼，白雲出岫本無心。", "峩眉江嶮公無度，法眼泉清我欲尋。", "手種庭前柏樹子，孤根應比鄉來深。"]'),
('cd39e80c-735e-46db-a754-baf0219482ff','用韻簡天童應庵','張孝祥','宋','宋诗','song-poetry','','[]','敬亭松竹古藂林，二老風流舊賞音。',64,'全唐诗/poet.song.149000.json','["敬亭松竹古藂林，二老風流舊賞音。", "樓閣長開太平象，鐘魚能洗祖師心。", "別來黄鵠還千里，盟在白鷗當再尋。", "却憶西堂大言客，只今高坐海雲深。"]'),
('a8a51413-55b6-4599-8abb-6175f9c660af','奉陪宣守任史君謁昭亭神祠  其一','張孝祥','宋','宋诗','song-poetry','','[]','緩驅千騎出朝京，喚得春回眼界青。',64,'全唐诗/poet.song.149000.json','["緩驅千騎出朝京，喚得春回眼界青。", "旗脚靈風來廟步，馬蹄山雪過昭亭。", "極知太守懷忠款，端爲君王薦德馨。", "慚愧去年冬十月，軍書徹夜聽鳴鈴。"]'),
('7b2835cb-283a-406a-b6d2-2c932c2abd3c','奉陪宣守任史君謁昭亭神祠  其二','張孝祥','宋','宋诗','song-poetry','','[]','豐年已卜稻如京，雪盡春從草際青。',64,'全唐诗/poet.song.149000.json','["豐年已卜稻如京，雪盡春從草際青。", "竹裏紅旗行點點，松間白塔見亭亭。", "暖回宿麥開寒色，風約疎梅度晚馨。", "却憶宣城李太白，也將詩句掣齋鈴。"]'),
('69b12bfd-6aa0-4d18-a4ff-78295c35cce3','任守作醮爲民祈福先期而雪是日開霽','張孝祥','宋','宋诗','song-poetry','','[]','紫府仙人自列真，綠章封事更通神。',64,'全唐诗/poet.song.149000.json','["紫府仙人自列真，綠章封事更通神。", "清塵已作連宵雪，不夜潜回萬屋春。", "玉節朱幡來浩蕩，雲車風馬正紛綸。", "步虛聲徹朝元路，便挈荷囊款帝闉。"]'),
('5b88e2bb-b574-4fc6-ba64-aaf6bcf4d91b','應庵退席蔣山來寄昭亭萬壽三請不得已而去輒贈長句兼簡蘇州內翰尚書  其一','張孝祥','宋','宋诗','song-poetry','','[]','逍遥丘壑欲忘年，忽作風蟬蛻骨仙。',64,'全唐诗/poet.song.149000.json','["逍遥丘壑欲忘年，忽作風蟬蛻骨仙。", "鍾阜恰從三昧起，靈巖重要一燈傳。", "極知掃迹終無策，且與臨岐快著鞭。", "莫作山林城市想，從來大隠故居廛。"]'),
('c561e567-6be0-4ed8-847f-0f735a6d31ba','應庵退席蔣山來寄昭亭萬壽三請不得已而去輒贈長句兼簡蘇州內翰尚書  其二','張孝祥','宋','宋诗','song-poetry','','[]','不寄音書又隔年，因師問訊玉堂仙。',64,'全唐诗/poet.song.149000.json','["不寄音書又隔年，因師問訊玉堂仙。", "碧油早覺儒爲貴，青海應無箭可傳。", "憶昔絲綸催喚仗，何時沙路聽鳴鞭。", "生涯落寞公知否，準擬松江受一廛。"]'),
('4f545223-a6e2-4b31-9298-cb688e8c8a3c','辛巳冬聞德音  其一','張孝祥','宋','宋诗','song-poetry','','[]','帳殿稱觴送喜頻，德音借與萬方春。',64,'全唐诗/poet.song.149000.json','["帳殿稱觴送喜頻，德音借與萬方春。", "指揮夷夏無遺策，開闔乾坤有至神。", "南斗夜纏龍虎氣，北風朝蕩犬羊塵。", "明年玉燭王正月，擬上梁園奉貢珍。"]'),
('a76bc91e-95f3-46b6-bf8c-bf7356c74093','辛巳冬聞德音  其二','張孝祥','宋','宋诗','song-poetry','','[]','韃靼奚家款附多，王師直到白溝河。',64,'全唐诗/poet.song.149000.json','["韃靼奚家款附多，王師直到白溝河。", "守江諸將遥分閫，絕漠殘胡競倒戈。", "翠蹕春行天動色，牙檣宵濟海無波。", "小儒不得參戎事，賦賦新詩續雅歌。"]'),
('9ef11d1c-6a5f-4f80-ba6a-fc18d208955f','和曾裘父韻送老人赴鎮九江','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','邊箭收聲江不波，廬山高處與天摩。',64,'全唐诗/poet.song.149000.json','["邊箭收聲江不波，廬山高處與天摩。", "向來只作青鞋計，此去無如紫詔何。", "塵滿庾樓煩翦拂，經餘蓮社更摩挲。", "文成本自籌帷幄，不數黥彭戰伐多。"]'),
('111d3566-9434-431e-b4d2-becce1431298','上丁齋宿','張孝祥','宋','宋诗','song-poetry','','[]','青衿陪祀憶初年，老矣齋居重慨然。',64,'全唐诗/poet.song.149000.json','["青衿陪祀憶初年，老矣齋居重慨然。", "俎豆不知鵝鸛事，牲牢空薦犬羊羶。", "北來被髮車連野，東去乘槎浪接天。", "汲汲兩宮常旰食，受膰歸去淚如川。"]'),
('22572080-a54f-479b-b9ff-79209af2eb43','和總得居士康樂亭韻','張孝祥','宋','宋诗','song-poetry','','[]','尚憶池塘夢阿連，當時此意惜無傳。',64,'全唐诗/poet.song.149000.json','["尚憶池塘夢阿連，當時此意惜無傳。", "薪車不障洪河决，喬木終隨故國顛。", "柳下煅工真得道，竹林酒友謾稱賢。", "先生義慨雲天薄，千載參渠活句禪。"]'),
('2e62413e-73af-45fd-b55d-a7f025809b52','寄張真父舍人  其一','張孝祥','宋','宋诗','song-poetry','','[]','玉珮瓊琚出近班，仙槎從此到人間。',64,'全唐诗/poet.song.149000.json','["玉珮瓊琚出近班，仙槎從此到人間。", "聊須海內無雙士，往鎮坤維百二關。", "御府應留霜簡看，鄉人休羨錦衣還。", "嗚呼國步艱危日，補衮懸知欠仲山。"]'),
('7c8dcae1-0ef8-4be1-b112-fa11cc51e94c','寄張真父舍人  其二','張孝祥','宋','宋诗','song-poetry','','[]','投分平生不數人，憶陪文館笑談新。',64,'全唐诗/poet.song.149000.json','["投分平生不數人，憶陪文館笑談新。", "資中宰樹看成拱，荆府詩筒迹又陳。", "已恨別離空歲月，那知解后亦參辰。", "古來命駕須千里，薄宦區區愧此身。"]'),
('818d8792-ab8d-4741-bb9b-e4b0613de7b2','中秋觀月齊雲樓用孫昌符韻','張孝祥','宋','宋诗','song-poetry','','[]','玉宇無塵夜氣清，銀河徹底素波明。',64,'全唐诗/poet.song.149000.json','["玉宇無塵夜氣清，銀河徹底素波明。", "人應好月同千里，身在高樓近五城。", "丹桂定知憐我老，綠尊何惜爲君傾。", "建章鳷鵲當年夢，便欲憑空上玉京。"]'),
('0976c6d3-e870-476d-a65b-0fa390651b65','題魯如晦通隠','張孝祥','宋','宋诗','song-poetry','','[]','先生早結社中蓮，覆錦憑熊亦偶然。',64,'全唐诗/poet.song.149000.json','["先生早結社中蓮，覆錦憑熊亦偶然。", "不向江湖忘魏闕，故應山澤有儒仙。", "十洲便著登瀛士，三徑難留避世賢。", "我亦經營一丘壑，問公先乞小壺天。"]'),
('6e6c8c13-10fc-481b-87b1-89d922cb68a9','同胡邦衡夜直','張孝祥','宋','宋诗','song-poetry','','[]','慕用高名二十年，敢期丹地接周旋。',64,'全唐诗/poet.song.149000.json','["慕用高名二十年，敢期丹地接周旋。", "先生義與雲天薄，老去心如鐵石堅。", "夢了瓊崖身益壯，煙銷金塢臭空傳。", "一尊莫惜空相屬，宮漏穿花夜色鮮。"]'),
('a7046cf3-e395-459a-862f-1d2bf7566515','雪晴成五十六字','張孝祥','宋','宋诗','song-poetry','','[]','鳥烏聲樂作初晴，日到南窗氣象新。',64,'全唐诗/poet.song.149000.json','["鳥烏聲樂作初晴，日到南窗氣象新。", "天接瓊瑶三萬頃，樹明組練五千人。", "已從炎海消陰盭，更與神皋洗戰塵。", "曾侍嚴宸知帝力，隆興借與萬方春。"]'),
('4bad6659-7b63-4cb2-91f1-1cf064b168a3','將如會稽寄曾吉甫','張孝祥','宋','宋诗','song-poetry','','[]','起居一代文章老，闕寄音書恰二年。',64,'全唐诗/poet.song.149000.json','["起居一代文章老，闕寄音書恰二年。", "詩債未還緣懶拙，官游如此竟危顛。", "會稽舊有探書穴，賀監應尋載酒船。", "我欲從公留十日，問公乞句手親編。"]'),
('baec5142-646e-4dae-9b56-a5193f112d12','過昭亭哭二弟墓','張孝祥','宋','宋诗','song-poetry','','[]','陌上春風久矣歸，墓頭衰草正迷離。',64,'全唐诗/poet.song.149000.json','["陌上春風久矣歸，墓頭衰草正迷離。", "白頭未抆三年淚，黄壤長埋短世悲。", "憶昔追游常并轡，只今獨往更題詩。", "兩兒二弟俱冥漠，顧影伶俜欲語誰。"]'),
('051fbc57-c6d3-41d2-a599-ad4ee925a2be','贈邕州滕史君','張孝祥','宋','宋诗','song-poetry','','[]','千騎東方白玉鑣，十眉環坐紫檀槽。',64,'全唐诗/poet.song.149000.json','["千騎東方白玉鑣，十眉環坐紫檀槽。", "安南都護來鰲禁，建武將軍握豹韜。", "瘴雨蠻煙驚鼓角，朔雲邊雪滿旌旄。", "夕烽不到甘泉殿，尺一徵還近赭袍。"]'),
('7b93b042-e70a-4175-a746-6bd4b60918d9','齊山','張孝祥','宋','宋诗','song-poetry','','[]','江山平遠三千里，水石嵌空二百巖。',64,'全唐诗/poet.song.149000.json','["江山平遠三千里，水石嵌空二百巖。", "地闢天開成洞府，峯回路轉有精藍。", "九華却立纔堪倚，萬井橫陳我所監。", "欲賦齊山無傑句，夢中危壁尚巉巉。"]'),
('0afabc86-d0e3-44a4-837e-7064774849b0','夜讀五公楚東酬唱輒書其後呈龜齡','張孝祥','宋','宋诗','song-poetry','','[]','同是清都紫府仙，帝教彈壓楚山川。',64,'全唐诗/poet.song.149000.json','["同是清都紫府仙，帝教彈壓楚山川。", "星躔錯落珠連緯，嶽鎮岧嶢柱倚天。", "宮羽在縣金奏合，驊騮參隊寶花鮮。", "平生我亦詩成癖，却悔來遲不與編。"]'),
('b58b4e48-d26a-4241-a8f4-4595b413b2bb','薦福觀何卿壁間詩對之悵然次前韻','張孝祥','宋','宋诗','song-poetry','','[]','金華老子定臞仙，翰墨文章徧兩川。',64,'全唐诗/poet.song.149000.json','["金華老子定臞仙，翰墨文章徧兩川。", "遺迹已驚風落木，高名依舊日行天。", "人間易得朱顔老，寺壁空懸玉唾鮮。", "欲繼三賢歌薤露，嚴詩杜集儻同編。"]'),
('f93c6b66-51cc-4364-aaee-11b6e72e5606','再用韻作五公詩','張孝祥','宋','宋诗','song-poetry','','[]','公如韓子定飛仙，更喜門人老玉川。',64,'全唐诗/poet.song.149000.json','["公如韓子定飛仙，更喜門人老玉川。", "莫說詩筒頻度嶺，即看侯弁去朝天。", "飛龍位正雲霄近，集鳳樓高采色鮮。", "我欲扁舟君記否，但教歸去雜民編。"]'),
('339fa3ec-5955-4c7b-96fe-b7cbc6863141','蒙侍御丈再用韻作送行詩走筆和答迫放船不暇工也','張孝祥','宋','宋诗','song-poetry','','[]','憶曾總領道山仙，自挽狂瀾制百川。',64,'全唐诗/poet.song.149000.json','["憶曾總領道山仙，自挽狂瀾制百川。", "廷策萬言功蓋世，臺評三上力回天。", "楚東賸喜詩郵速，天北催頒詔墨鮮。", "老我江湖堪野史，看公勳業手親編。"]'),
('da6c511c-0436-4498-9135-c7337ee33e6d','龜齡携具同景盧嘉叟餞別於薦福即席再用韻賦四客詩','張孝祥','宋','宋诗','song-poetry','','[]','使君領客訪金仙，小隊旌旗錦一川。',64,'全唐诗/poet.song.149000.json','["使君領客訪金仙，小隊旌旗錦一川。", "我欲采芝非辟世，公當立極要擎天。", "詩聲政爾容傳稿，僧律何嘗禁割鮮。", "一笑番陽逢歲熟，問公鐘磬幾時編。"]'),
('f9ca4fee-aa3e-4d89-86cd-86b07c87c8e1','登清音堂其下琵琶洲也再用韻','張孝祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','夜橫霜竹夢遊仙，曉到餘干月滿川。',64,'全唐诗/poet.song.149000.json','["夜橫霜竹夢遊仙，曉到餘干月滿川。", "山遶樓臺欲無地，水環洲渚更連天。", "明霞一抹朱弦直，芳草分垂綠綬鮮。", "却憶洞庭張樂地，石鐘浮磬定同編。"]'),
('fd5f5365-6601-4262-9273-5b58c4dd16f9','餘干趙公頙賢宗室也魏公題其堂曰養正且爲作銘取易頤之義刻碑堂上予過之爲賦詩','張孝祥','宋','宋诗','song-poetry','','[]','眼裏紛紛不要同，從教三徑滿蒿蓬。',64,'全唐诗/poet.song.149000.json','["眼裏紛紛不要同，從教三徑滿蒿蓬。", "肯來與子談周易，此去何人識魏公。", "家近星辰雙闕北，身居煙浪五湖東。", "清臺有日占雲氣，一丈豐碑夜貫虹。"]'),
('9c68341d-c743-45a1-9c61-040859430052','雞籠福地在歷陽將至豐城望一山宛然感之賦詩','張孝祥','宋','宋诗','song-poetry','','[]','黄茅白葦徑才通，忽見晴嵐掃翠空。',64,'全唐诗/poet.song.149000.json','["黄茅白葦徑才通，忽見晴嵐掃翠空。", "從吏只令俱蜑戶，仙山何許是雞籠。", "逢人漸覺交游少，問路仍行盜賊中。", "自是粗才合粗使，瘴鄉那得便途窮。"]'),
('bdc6f1c7-2df1-41c4-b46e-bc8f15779c73','午憩道傍人家','張孝祥','宋','宋诗','song-poetry','','[]','一崦人家竹樹凉，午陰深處著胡床。',64,'全唐诗/poet.song.149000.json','["一崦人家竹樹凉，午陰深處著胡床。", "石泉政似煮茗沸，稻花已作炊秔香。", "夢到家園歸自好，起尋官路去何長。", "塵埃滿面迎西日，底處青山是故鄉。"]'),
('b4319769-7308-4544-af5e-06a92e182b64','入清江界地名九段田沃壤百里黄雲際天他處未有也','張孝祥','宋','宋诗','song-poetry','','[]','野水瀰漫欲漲川，稻雲烘日更連天。',64,'全唐诗/poet.song.149000.json','["野水瀰漫欲漲川，稻雲烘日更連天。", "定無適粵千金橐，可買臨江九段田。", "黄犢眠邊高樹蔭，白雞啼處遠炊煙。", "此中若許投簪紱，便老耡耰卜數椽。"]'),
('33c4848b-dd57-4420-9b1e-a72cc4f5dd84','題吳城廟','張孝祥','宋','宋诗','song-poetry','','[]','乞得東歸一信風，敬持牲酒扣靈宮。',64,'全唐诗/poet.song.149000.json','["乞得東歸一信風，敬持牲酒扣靈宮。", "千尋石甃蒼藤合，百歲神倉赤眚空。", "浥浥午陰移岸樹，蕭蕭凉意滿船篷。", "杖藜更作僧坊去，借壁題詩却未工。"]'),
('c7834d5e-6fb2-4835-8684-670799d66a3f','呈樞密劉恭父','張孝祥','宋','宋诗','song-poetry','','[]','鼎席方虛望已隆，上游那得更煩公。',64,'全唐诗/poet.song.149000.json','["鼎席方虛望已隆，上游那得更煩公。", "敢言兩鎮成交契，自是孤根累化工。", "舊弼新開元帥府，閑官且領太平宮。", "歸家凈洗如椽筆，準擬燕然勒駿功。"]'),
('fd044084-b8ab-459f-a9e2-c5d6eae1be5e','子功補之遠送海錯甚珍','張孝祥','宋','宋诗','song-poetry','','[]','白彘烏羊見未曾，青蛇赤蟻當常珍。',64,'全唐诗/poet.song.149000.json','["白彘烏羊見未曾，青蛇赤蟻當常珍。", "忽驚海物來登坐，能致南烹有故人。", "萬里漂流憐逐食，百年粗糲愧嘗新。", "新篘恰趁來時熟，細酌梅花雪片春。"]'),
('91906a1a-a4ba-4b8f-b6fc-0c774729672a','張仲欽朝陽亭','張孝祥','宋','宋诗','song-poetry','','[]','便合朝陽作鳳鳴，江亭聊此駐脩程。',64,'全唐诗/poet.song.149000.json','["便合朝陽作鳳鳴，江亭聊此駐脩程。", "南瞻御路臨雙闕，東望仙家接五城。", "日上白門兵氣靜，春歸淮浦暗潮平。", "遥憐莫府文書省，時下滄浪自濯纓。"]'),
('68e3c890-89e1-4aab-bfb6-3aff25d5ebdd','次韻  其一','張孝祥','宋','宋诗','song-poetry','','[]','空巖相望一牛鳴，不要郵籤報水程。',64,'全唐诗/poet.song.149000.json','["空巖相望一牛鳴，不要郵籤報水程。", "天接海光通外徼，地連江勢挾重城。", "絲綸疊至龍恩重，綉斧前驅蜑霧平。", "鳳閣鸞臺有虛位，請君從此振朝纓。"]'),
('4692b2c3-e11f-4e79-b520-7cc1a8b9f4f6','次韻  其二','張孝祥','宋','宋诗','song-poetry','','[]','饑腸得酒作雷鳴，痛飲狂歌不自程。',64,'全唐诗/poet.song.149000.json','["饑腸得酒作雷鳴，痛飲狂歌不自程。", "坐上波瀾生健筆，歸來鐘鼓動嚴城。", "不應此地淹鴻業，盍與吾君致太平。", "伏櫪壯心猶未已，須君爲我請長纓。"]'),
('6aec96a0-cc02-47f5-852c-ba30e1b7745f','送張司戶還蜀','張孝祥','宋','宋诗','song-poetry','','[]','似向川人有夙緣，交游存歿最多賢。',64,'全唐诗/poet.song.149000.json','["似向川人有夙緣，交游存歿最多賢。", "今年初識張公子，六月還尋上水船。", "萬里親庭心已到，一杯別酒意空傳。", "西行賸有新詩句，寄我應書十樣牋。"]'),
('b85d52f9-03a7-4b5d-8216-c3b8bb124ea2','和仲彌性煙霏佳句兼簡貳車  其一','張孝祥','宋','宋诗','song-poetry','','[]','收歛經綸寄一麾，戲分風月與煙霏。',64,'全唐诗/poet.song.149000.json','["收歛經綸寄一麾，戲分風月與煙霏。", "醉餘綵筆三千首，老去蒼官四十圍。", "露菊漙秋催落帽，蠟花摧夜照更衣。", "登臨縱好難留滯，白髮雙親待汝歸。"]'),
('2ccaf960-4ad3-471f-881b-6ce3b9a05321','和仲彌性煙霏佳句兼簡貳車  其二','張孝祥','宋','宋诗','song-poetry','','[]','引手星辰逼太微，盪胸雲物散空霏。',64,'全唐诗/poet.song.149000.json','["引手星辰逼太微，盪胸雲物散空霏。", "莫山好處青成案，秋月明時雪打圍。", "竹洗佳人千點淚，荷翻仙子六銖衣。", "西巖定有漁翁宿，障雨攔風不肯歸。"]'),
('f6f17d07-17b7-49f7-843f-372a38720e0a','庾樓和林黄中韻','張孝祥','宋','宋诗','song-poetry','','[]','九月扁舟下水風，一尊佳處與君同。',64,'全唐诗/poet.song.149000.json','["九月扁舟下水風，一尊佳處與君同。", "眼高四海氛塵外，詩在千山紫翠中。", "傾坐只驚談麈白，踏筵不怕舞衫紅。", "樓頭今古無窮事，醉倚胡床月滿空。"]'),
('bde80641-17ae-4582-beaa-bd723cf445b3','高遠亭和林黄中韻','張孝祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','簷桷飛翔入太空，下窺廬嶽最高峯。',64,'全唐诗/poet.song.149000.json','["簷桷飛翔入太空，下窺廬嶽最高峯。", "亭如峴首應遺愛，詩比西湖欲亢宗。", "天上喚君從此近，酒邊著我幾時重。", "憑闌欲去仍回首，誰與佳名自點胸。"]'),
('1bbea611-cb10-45b6-a2b5-c31b265ce410','與同僚十五人謝晴東明得淵字','張孝祥','宋','宋诗','song-poetry','','[]','靈光便滿恒沙界，大士重來七十年。',64,'全唐诗/poet.song.149000.json','["靈光便滿恒沙界，大士重來七十年。", "秋入郊原成樂歲，風隨簫鼓散香煙。", "定知蠻獠安三窟，更遣蛟龍閟九淵。", "太守憂民但逃責，所忻畢至有群賢。"]'),
('eeff358f-5625-4ac7-b424-50044ec31297','釋奠','張孝祥','宋','宋诗','song-poetry','','[]','又領諸儒款泮宮，車書同處禮應同。',64,'全唐诗/poet.song.149000.json','["又領諸儒款泮宮，車書同處禮應同。", "柏庭老影留江月，竹屋寒聲作社風。", "坐客語殘香一穗，候人催起鼓三通。", "歸來稅冕仍分肉，更覺休官興未窮。"]'),
('79bbf2ee-8c38-4223-972c-814d0ada2ec1','風雨石首呈同行寄荆州僚舊','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昨日離筵酒未醒，今朝風雨暗江亭。',64,'全唐诗/poet.song.149000.json','["昨日離筵酒未醒，今朝風雨暗江亭。", "近人積水春全綠，隔岸荒山夜却青。", "野吏衣冠行木偶，客船燈火散疎星。", "寬程且作三旬約，要看廬山紫翠屏。"]'),
('c11bb43a-7c18-42c6-bfec-e72dd1d7ada4','江行再用前韻','張孝祥','宋','宋诗','song-poetry','','[]','澤畔行吟我獨醒，歸程不計短長亭。',64,'全唐诗/poet.song.149000.json','["澤畔行吟我獨醒，歸程不計短長亭。", "西風送浪頭頭白，芳草隨人段段青。", "昨夜疎篷猶窘雨，今朝嚴鼓欲侵星。", "無人去喚華容宰，畫我江行作小屏。"]'),
('aa5ac6dd-f9da-44ca-b225-b9fddfcf8975','次韻黄子餘','張孝祥','宋','宋诗','song-poetry','','[]','縮肩得句極酸寒，何似黄郎咳唾間。',64,'全唐诗/poet.song.149000.json','["縮肩得句極酸寒，何似黄郎咳唾間。", "少日曾經諸老學，傳家自有祖師關。", "詞林根柢今誰在，振古風流要力還。", "我老故應無用此，因君猶欲更晞顔。"]'),
('216b9c26-0b3b-4658-abb3-ce86c6a395bd','去臨川書西津漁家','張孝祥','宋','宋诗','song-poetry','','[]','作客臨川又一年，却尋歸路淺灘船。',64,'全唐诗/poet.song.149000.json','["作客臨川又一年，却尋歸路淺灘船。", "宦游到處真聊爾，別恨何須更黯然。", "夾道長紅慚父老，繞城濃碧記山川。", "無端此地成留滯，定自從渠有宿緣。"]'),
('c2d8b768-2ce5-46e0-9bde-77135ca80811','將至池陽呈魯使君','張孝祥','宋','宋诗','song-poetry','','[]','珍重池陽魯使君，忘年交契獨情親。',64,'全唐诗/poet.song.149000.json','["珍重池陽魯使君，忘年交契獨情親。", "江山佳處公開府，風雨來時我問津。", "翠逼筍輿松徑合，綠隨秧馬稻畦新。", "東歸賸作登臨好，病怯詩腸故惱人。"]'),
('0d23b696-c796-47de-84d5-c69348ff98dd','上元設醮畢作長句','張孝祥','宋','宋诗','song-poetry','','[]','綠簡朱書自叩真，復爐香霧晚絪縕。',64,'全唐诗/poet.song.149000.json','["綠簡朱書自叩真，復爐香霧晚絪縕。", "雪花便作茶花白，春色還隨月色新。", "江漲不憂堤萬丈，年豐何啻粟千囷。", "微生只擬休官去，拜胙歸來吉夢頻。"]'),
('dfecd92b-8b5c-47b8-82b7-6752003fce7c','齊安郡夫人挽章','張孝祥','宋','宋诗','song-poetry','','[]','儲祥吳越王家子，媲德蓬萊閣上仙。',64,'全唐诗/poet.song.149000.json','["儲祥吳越王家子，媲德蓬萊閣上仙。", "湯沐幾年開大國，笄珈長夜揜窮泉。", "鸞臺曉月悲塵鏡，鳳軫春風泣斷弦。", "木落荄枯何限恨，藁砧應賦悼亡篇。"]'),
('b597bfbf-5868-4880-a9c3-1a1f9d503926','賀郊祀','張孝祥','宋','宋诗','song-poetry','','[]','漢統千齡接，虞衡七政齊。',240,'全唐诗/poet.song.149000.json','["漢統千齡接，虞衡七政齊。", "德馨天自饗，容祲古猶稽。", "輿衛鈎陳北，衣冠觀闕西。", "雨先清道蹕，寒避禮神圭。", "方士朝仙仗，宮垣挾御堤。", "廟芝楹疊璧，帝樂字連奎。", "虛次尤祗慄，懷親極慘悽。", "珠旒依玉色，蘭炬映璇題。", "兩相初扶翼，崇壇六降隮。", "高靈森欲墮，諸福應如携。", "燎夜壇三燭，凌霜甲萬犀。", "宗藩申寶酌，祕檢護金泥。", "奉引星辰爛，旋歸錦繡迷。", "端門臨五鳳，步輦駐雙霓。", "日照雲裳委，風含綵筤低。", "和聲翔四表，嘉澤浸羣黎。", "盛事真寥廓，微生荷奬提。", "侍祠叨執爵，著籍繆通閨。", "異寵何由報，孤忠誓不睽。", "裁詩獨慚晚，猶得并鳧鷖。"]'),
('6a588422-20b9-4f77-9eab-453e8ce91968','送顔廷藻歸三衢','張孝祥','宋','宋诗','song-poetry','','[]','歲事今如此，公歸意若何。',48,'全唐诗/poet.song.149000.json','["歲事今如此，公歸意若何。", "倚門親望切，傳舍客愁多。", "美讖當圓石，仙游看爛柯。", "一科須俯拾，五字要長哦。"]'),
('58777e30-d41c-4770-9378-897384201bf5','送郭遐齡','張孝祥','宋','宋诗','song-poetry','','[]','去從公府辟，不爲故人留。',48,'全唐诗/poet.song.149000.json','["去從公府辟，不爲故人留。", "國士真如此，臺家合見收。", "聲名早多誤，功業晚方優。", "不必毛錐子，相期定遠侯。"]'),
('8d4a3444-3b3e-4b04-b10a-508fe02706a6','次家君韻  其一','張孝祥','宋','宋诗','song-poetry','','[]','柏禪工立雪，松壽不凋寒。',48,'全唐诗/poet.song.149000.json','["柏禪工立雪，松壽不凋寒。", "筆底波瀾壯，胸中宇宙寬。", "登車慵攬轡，投檄願休官。", "四海英名滿，懸知袖手難。"]'),
('9bc5d1d2-a604-4a0a-89b0-5f984ad5487f','次家君韻  其二','張孝祥','宋','宋诗','song-poetry','','[]','憶昔金門直，通班玉殿寒。',48,'全唐诗/poet.song.149000.json','["憶昔金門直，通班玉殿寒。", "風雲黄道近，日月太虛寬。", "法錦羅千仗，宮花覆百官。", "江湖歲將晚，未覺報君難。"]'),
('9f082a15-e596-47cb-8a4a-12511cc91966','題玄英先生廟','張孝祥','宋','宋诗','song-poetry','','[]','木老參天直，江清白日閑。',48,'全唐诗/poet.song.149000.json','["木老參天直，江清白日閑。", "先生元不死，遺廟亦空山。", "文采雲仍似，風流正始間。", "平生子嚴子，高處得追攀。"]'),
('47ecfc9a-d2bf-4636-a348-ed111307add2','謹和老人貽具圓復之什','張孝祥','宋','宋诗','song-poetry','','[]','儒名參墨行，詩律傲宗風。',48,'全唐诗/poet.song.149000.json','["儒名參墨行，詩律傲宗風。", "老去能從我，生來未識公。", "據梧心已死，行李歲將窮。", "應見維摩詰，天花結習空。"]'),
('ef8385b0-ef1e-4af9-bdfd-f1434ddc9441','和王景文  其一','張孝祥','宋','宋诗','song-poetry','','[]','陸行忌豺虎，水去怯風波。',48,'全唐诗/poet.song.149000.json','["陸行忌豺虎，水去怯風波。", "世路險猶爾，客中愁更多。", "吾生真漫與，天道合如何。", "千古興亡意，臨風一放歌。"]'),
('4b28e9df-7af1-44a8-a338-565ec313b5de','和王景文  其二','張孝祥','宋','宋诗','song-poetry','','[]','斯文到之子，砥柱閲頹波。',48,'全唐诗/poet.song.149000.json','["斯文到之子，砥柱閲頹波。", "致主規模別，傷時疾疢多。", "大臣讒賈誼，逆旅欠常何。", "無路排閶闔，聊當扣角歌。"]'),
('0606d445-b1d9-499b-89ad-bf1ee60a995a','和王景文  其三','張孝祥','宋','宋诗','song-poetry','','[]','王師行六月，淮海靜無波。',48,'全唐诗/poet.song.149000.json','["王師行六月，淮海靜無波。", "元老前籌密，諸軍捷奏多。", "西風向蕭瑟，北顧要誰何。", "聞說收兵後，謳吟雜雅歌。"]'),
('8bd03aea-649e-477a-bc9c-1080df53474f','即事簡蘇廷藻','張孝祥','宋','宋诗','song-poetry','','[]','落日邊書急，秋風戰鼓多。',48,'全唐诗/poet.song.149000.json','["落日邊書急，秋風戰鼓多。", "私憂真過計，長算合如何。", "盡歛清淮戍，仍收瀚海波。", "棲遲一尊酒，幽恨滿關河。"]'),
('658e7844-77ba-4bae-8514-a7011323bdec','和韓中父  其一','張孝祥','宋','宋诗','song-poetry','','[]','天入南郊白，雲連朔野昏。',48,'全唐诗/poet.song.149000.json','["天入南郊白，雲連朔野昏。", "弼臣開盛府，殤虜哭新魂。", "聞道通軺傳，何當拜寢園。", "荒寒歲將晚，愁絕更堪言。"]'),
('e61594a5-49c0-4a64-8314-4e1d67ce51d9','和韓中父  其二','張孝祥','宋','宋诗','song-poetry','','[]','東鄰子韓子，憂國忘晨昏。',48,'全唐诗/poet.song.149000.json','["東鄰子韓子，憂國忘晨昏。", "也作漳濱卧，誰招楚些魂。", "舊勳留幕府，新渥到丘園。", "家法傳來久，遲君一盡言。"]'),
('36619902-f530-4f64-a99f-81c2372df953','東壩','張孝祥','宋','宋诗','song-poetry','','[]','固城朝送客，東壩晚留儂。',48,'全唐诗/poet.song.149000.json','["固城朝送客，東壩晚留儂。", "浙近風煙好，春回港汊通。", "北來愁亂轍，南去喜疎篷。", "不是趨朝市，松江學釣翁。"]'),
('bce1ea25-1260-49ee-a662-8efba7bb904c','過建德','張孝祥','宋','宋诗','song-poetry','','[]','古縣依山住，肩輿带雨來。',48,'全唐诗/poet.song.149000.json','["古縣依山住，肩輿带雨來。", "閭閻無地著，巖壑有天開。", "野驛編青竹，公庭砌碧苔。", "傳聞長官好，小泊亦佳哉。"]'),
('2e355bf7-7f8b-4c0f-a769-c43c5ef12008','龜齡侍御以番陽士子之意作五峰亭且賦詩某敬和','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山真滿眼，秀句憶東坡。',48,'全唐诗/poet.song.149000.json','["廬山真滿眼，秀句憶東坡。", "但遣佳名易，懸知得士多。", "雲霄身已近，星象手能摩。", "太守文章伯，風行水自波。"]'),
('b65e835f-814f-4e5c-ab36-54ed7e72ba40','過嶽麓見子雲題字偶逢來使因寄二詩  其一','張孝祥','宋','宋诗','song-poetry','','[]','籍甚韓公子，情親我弟兄。',48,'全唐诗/poet.song.149000.json','["籍甚韓公子，情親我弟兄。", "星沙逢驛使，嶽麓見題名。", "共作三年別，相望五日程。", "湘江接淮水，寄與濯塵纓。"]'),
('6effa52f-ef07-4ec3-b5ea-8557127c06e2','過嶽麓見子雲題字偶逢來使因寄二詩  其二','張孝祥','宋','宋诗','song-poetry','','[]','故人應問我，客裏定何如。',48,'全唐诗/poet.song.149000.json','["故人應問我，客裏定何如。", "馬鋪爲行館，雞栖是使車。", "四郊多賊壘，五筦欠兵儲。", "此去無來鴈，因人數寄書。"]'),
('e5dc221f-c49e-4032-b519-79bc0e37661b','送劉子思','張孝祥','宋','宋诗','song-poetry','','[]','送客古城東，陰晴一日中。',48,'全唐诗/poet.song.149000.json','["送客古城東，陰晴一日中。", "舊憐杉桱碧，新喜荔枝紅。", "香火叢祠冷，魚蝦小市空。", "明朝萬里別，今夕此尊同。"]'),
('790c458a-613d-4164-af1b-de822bc4bdb1','月夜與蔡濟忠曹公會汎舟自水東歸','張孝祥','宋','宋诗','song-poetry','','[]','一舸駕長風，銀河此路通。',48,'全唐诗/poet.song.149000.json','["一舸駕長風，銀河此路通。", "波光連月白，燭影到江紅。", "五嶺經星外，千山颶霧中。", "不知今夜賞，更有幾人同。"]'),
('27c6a1e5-3e50-4a37-814b-0f3df6b454b6','鹿鳴燕','張孝祥','宋','宋诗','song-poetry','','[]','明庭下溫詔，方岳貢羣賢。',48,'全唐诗/poet.song.149000.json','["明庭下溫詔，方岳貢羣賢。", "巢鳳山中客，栖鸞地上仙。", "魚龍回夜水，鵰鶚在秋天。", "添種家鄉桂，歸途快著鞭。"]'),
('68663907-26cf-4ed3-ad09-57cd4ecd0d81','訾洲即事','張孝祥','宋','宋诗','song-poetry','','[]','一雨便清凉，風回百草香。',48,'全唐诗/poet.song.149000.json','["一雨便清凉，風回百草香。", "雲山米家畫，水竹輞川莊。", "僧賦蠲新帖，牆榛斬舊行。", "歸鞍乘晚霽，空翠滿輕裝。"]'),
('b7646902-abf0-4dc8-969a-f1e8d4eb4281','罷歸','張孝祥','宋','宋诗','song-poetry','','[]','親老難爲住，恩深許放歸。',48,'全唐诗/poet.song.149000.json','["親老難爲住，恩深許放歸。", "北行湘水闊，南望瘴煙微。", "兵衛收門戟，征塵上客衣。", "遥知六七月，喜氣滿庭闈。"]'),
('8294438a-d2a8-4c7f-a368-4dcdd411efa2','罷歸呈同官  其一','張孝祥','宋','宋诗','song-poetry','','[]','去年秋七月，我犯瘴煙來。',48,'全唐诗/poet.song.149000.json','["去年秋七月，我犯瘴煙來。", "賦少畬田熟，徭歸驛路開。", "上恩均雨露，孤迹返蒿萊。", "想像山中趣，參差屐齒苔。"]'),
('0212e2de-f6b9-4cc1-9451-c1eea4633511','罷歸呈同官  其二','張孝祥','宋','宋诗','song-poetry','','[]','嶺水常時急，蠻山是處高。',48,'全唐诗/poet.song.149000.json','["嶺水常時急，蠻山是處高。", "戶輸無翠羽，溪瘴有黄茅。", "游子歸鄉國，斯人滯冗曹。", "臨分那忍別，風裏鬢蕭騷。"]'),
('b0bba639-cb35-46ba-859d-2c48b9e19753','贈江清卿','張孝祥','宋','宋诗','song-poetry','','[]','嶺海適相逢，經年颶霧中。',48,'全唐诗/poet.song.149000.json','["嶺海適相逢，經年颶霧中。", "官閑詩格進，祿薄俸囊空。", "子昔南征鶴，吾今北去鴻。", "江湖渺何許，聽唳九霄風。"]'),
('9a40fad1-cc88-4de4-bc18-818db3c5ff13','過靈川寄張仲欽兼贈王令尹','張孝祥','宋','宋诗','song-poetry','','[]','塵沙行半日，煙火是靈川。',48,'全唐诗/poet.song.149000.json','["塵沙行半日，煙火是靈川。", "縣只三家市，渠通十斛船。", "官空無見俸，稅重有荒田。", "太息王郎子，棲遲欲四年。"]'),
('77968f1b-6497-4307-aa34-c4a7281c7a12','滑石','張孝祥','宋','宋诗','song-poetry','','[]','重來滑石鋪，爲愛碧泉鳴。',48,'全唐诗/poet.song.149000.json','["重來滑石鋪，爲愛碧泉鳴。", "古甃苔花澀，虛簷桂月明。", "喬林通夜氣，密竹動秋聲。", "客裏清凉地，悠然一振纓。"]'),
('a8ac9832-1e38-46be-ac6a-284c2e20ac30','興安','張孝祥','宋','宋诗','song-poetry','','[]','提封連嶺海，風土似江吳。',48,'全唐诗/poet.song.149000.json','["提封連嶺海，風土似江吳。", "仙去山藏乳，商歸斗算珠。", "劭農多樂歲，厲俗有通儒。", "已過炎關了，吾行且緩驅。"]'),
('943dff76-60e5-4d5c-9e7d-f830257c6257','炎關','張孝祥','宋','宋诗','song-poetry','','[]','驅馬度炎關，身經瘴野還。',48,'全唐诗/poet.song.149000.json','["驅馬度炎關，身經瘴野還。", "稍餘衣带水，已盡劍鋩山。", "海月隨人遠，湘雲似我閑。", "不須占紫氣，游戲且人間。"]'),
('e0403071-9493-4deb-aa35-1af9d27a6630','蒸霞谷爲曹公會賦','張孝祥','宋','宋诗','song-poetry','','[]','見說蒸霞谷，連山只種桃。',48,'全唐诗/poet.song.149000.json','["見說蒸霞谷，連山只種桃。", "補成天五色，散作佛千毫。", "月底羣仙下，風前細仗高。", "期君成美實，歸獻赤霜袍。"]'),
('6420140c-0894-4a4f-893f-59482ab98ec3','登瀛橋爲曹公會賦','張孝祥','宋','宋诗','song-poetry','','[]','從此上瀛洲，虹蜺晚未收。',48,'全唐诗/poet.song.149000.json','["從此上瀛洲，虹蜺晚未收。", "濟川誰作楫，浮海不乘桴。", "弱水三萬里，五城十二樓。", "讀書羣玉府，風袂揖丹丘。"]'),
('c8c765f2-0e01-481e-81fa-7d3f77e698f2','丙戌七月望日自南臺遊福嚴書留山中','張孝祥','宋','宋诗','song-poetry','','[]','乞我一枝筇，經行又別峯。',48,'全唐诗/poet.song.149000.json','["乞我一枝筇，經行又別峯。", "水流仙界葉，風落化城鍾。", "錫去泉無恙，車行石有蹤。", "却憐磨衲老，曾見兩儒宗。"]'),
('df4b8956-640a-4924-8d2f-04f787d751b8','和萬老','張孝祥','宋','宋诗','song-poetry','','[]','歸途正遼邈，此地更淹留。',48,'全唐诗/poet.song.149000.json','["歸途正遼邈，此地更淹留。", "落木千山夜，空江萬里秋。", "聊爲無事飲，莫賦畔牢愁。", "明發催船鼓，風帆過橘洲。"]'),
('7b6db304-430f-4310-9463-1c755b22b4a0','再和','張孝祥','宋','宋诗','song-poetry','','[]','吾行聊復爾，處處賈胡留。',48,'全唐诗/poet.song.149000.json','["吾行聊復爾，處處賈胡留。", "天入星沙晚，風連夢澤秋。", "未容詩作祟，政要酒澆愁。", "明月無人伴，携君鸚鵡洲。"]'),
('5c42758c-756c-4d4f-bff5-ccae1b1892a0','三塔寺阻雨  其一','張孝祥','宋','宋诗','song-poetry','','[]','塔上一鈴語，湖頭三日風。',48,'全唐诗/poet.song.149000.json','["塔上一鈴語，湖頭三日風。", "蒼山在煙外，高浪與天通。", "市迥薪芻少，僧殘像教空。", "不妨留滯好，且看夕陽紅。"]'),
('58da28d5-0808-47ad-9756-798cb89cbbac','三塔寺阻雨  其二','張孝祥','宋','宋诗','song-poetry','','[]','倦客三杯酒，高僧一味茶。',48,'全唐诗/poet.song.149000.json','["倦客三杯酒，高僧一味茶。", "凉風撼楊柳，晴日麗荷花。", "鐸語時鳴塔，漁歌晚釣槎。", "停艫快清憩，步穩襯明霞。"]'),
('73bacaf1-b6e8-41d3-88c4-9fabf0189bbc','過湘中得詩僧萬致一於書無所不讀非苟得詩名於僧中者余欲與俱還吳中而萬家浯溪將結草庵其上送余至湘陰復歸作四十字以別','張孝祥','宋','宋诗','song-poetry','','[]','別去太匆匆，回船夢澤東。',48,'全唐诗/poet.song.149000.json','["別去太匆匆，回船夢澤東。", "擬尋行脚路，忽遇打頭風。", "梵網威儀在，天花結習空。", "它年三百首，吾爲子流通。"]'),
('43102249-70ee-4877-b0a2-c1acf9a2ce42','欽夫子明定叟夜話舟中欽夫說論語數解天地之心聖人之心盡在是矣明日賦詩以別','張孝祥','宋','宋诗','song-poetry','','[]','江北我歸去，湘西君卜居。',48,'全唐诗/poet.song.149000.json','["江北我歸去，湘西君卜居。", "誰知對床語，勝讀十年書。", "不飲清無寐，來朋樂有餘。", "明朝千里別，密處幾曾疎。"]'),
('69e44f47-2212-4096-962d-504af04d6229','送張立之赴臨江判官','張孝祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','珍重清江掾，相從五見秋。',48,'全唐诗/poet.song.149000.json','["珍重清江掾，相從五見秋。", "炎凉無改節，夷險有忠謀。", "蓮幕開新府，蒲帆漾小舟。", "凄然洞庭野，別意與川流。"]'),
('07a76df4-2728-431f-bd0a-3ec46df6cb1c','黄陵廟','張孝祥','宋','宋诗','song-poetry','','[]','百世黄陵廟，凄凉屋數間。',48,'全唐诗/poet.song.149000.json','["百世黄陵廟，凄凉屋數間。", "只憐斑楚竹，那記赭湘山。", "訪古韓碑在，徵歌屈些閑。", "虞嬪更堯女，莫入水仙班。"]'),
('dad9d013-6585-4aad-ab40-a5560fb24c9d','磊石','張孝祥','宋','宋诗','song-poetry','','[]','鼓發營田市，帆收磊石山。',48,'全唐诗/poet.song.149000.json','["鼓發營田市，帆收磊石山。", "冰紈六十里，煙髻兩三鬟。", "天氣水雲合，人家罾網間。", "晚來風更熟，別浦棹歌還。"]'),
('d09ebbfd-587f-47ba-a03f-0605eb55d494','黄州','張孝祥','宋','宋诗','song-poetry','','[]','平生聞赤壁，今日到黄州。',48,'全唐诗/poet.song.149000.json','["平生聞赤壁，今日到黄州。", "古戍參差月，空江浩蕩秋。", "艱難念時事，留滯豈身謀。", "索索悲風裏，滄浪亦白頭。"]'),
('de7b4a7f-911b-417c-be75-ac6b5fb2d440','東坡','張孝祥','宋','宋诗','song-poetry','','[]','繫船著西日，曳杖過東坡。',48,'全唐诗/poet.song.149000.json','["繫船著西日，曳杖過東坡。", "暗井蛙成部，荒祠鳥作窠。", "老仙騎鶴去，穉子飯牛歌。", "興廢何須問，斯文自不磨。"]'),
('626802b0-984e-4b3d-a3a8-8d02afdacee7','過蘄口六奉寺丞仲文親帖之貺今早本約來陳店復勤千騎至冶塘所以招迎之意甚厚感歎不已賦此爲謝','張孝祥','宋','宋诗','song-poetry','','[]','故人經歲別，連日幾封書。',48,'全唐诗/poet.song.149000.json','["故人經歲別，連日幾封書。", "不識江頭路，仍迂長者車。", "追參空幕府，牽挽到賓除。", "太息交情薄，多公不我疎。"]'),
('63803e2a-fc69-4ae5-8b2a-8da54959549a','臨發再和','張孝祥','宋','宋诗','song-poetry','','[]','水落魚成塞，風高鴈欲書。',48,'全唐诗/poet.song.149000.json','["水落魚成塞，風高鴈欲書。", "公爲東道主，我滯北轅車。", "邊障無傳警，朝廷有拜除。", "江干便迎候，此別未云疎。"]'),
('8f38dbbd-416f-4c5a-864f-ad7830c2af48','送仲子弟用同之韻','張孝祥','宋','宋诗','song-poetry','','[]','凄然鴻鴈影，晚歲索衣裘。',48,'全唐诗/poet.song.149000.json','["凄然鴻鴈影，晚歲索衣裘。", "惜別湘江夜，歸程楚甸秋。", "極知違定省，不敢更淹留。", "明月分携處，無言只是愁。"]'),
('ef1317c3-f980-4387-86ee-542e88cdaa6f','送謝夢得歸昭武','張孝祥','宋','宋诗','song-poetry','','[]','莫吟青玉案，恐弊黑貂裘。',48,'全唐诗/poet.song.149000.json','["莫吟青玉案，恐弊黑貂裘。", "國步艱難日，人間浩蕩秋。", "不須鳥工往，且作賈胡留。", "後夜回春閣，凄然一段愁。"]'),
('44acb55b-d666-4dac-91fe-16dddea5ea0a','和欽夫喜雨','張孝祥','宋','宋诗','song-poetry','','[]','佛剎起香雲，高低一雨均。',48,'全唐诗/poet.song.149000.json','["佛剎起香雲，高低一雨均。", "使君心未已，閣老句還新。", "喜入村鄉樂，凉生甕盎春。", "莫嫌知稼穡，我是種田人。"]'),
('2d13adf9-5729-46c9-9ce0-c43063f27a17','詩送荆州進士入都','張孝祥','宋','宋诗','song-poetry','','[]','人才收楚産，賓薦謹周官。',48,'全唐诗/poet.song.149000.json','["人才收楚産，賓薦謹周官。", "就日三吳近，披風七澤寬。", "解包珍貢入，瑑玉寶光寒。", "簇仗春旗裏，看君策治安。"]'),
('e05a17ad-18a3-4413-bf78-edd59c98c8db','城西晚步呈王亮采','張孝祥','宋','宋诗','song-poetry','','[]','城西行半日，佳客偶相隨。',48,'全唐诗/poet.song.149000.json','["城西行半日，佳客偶相隨。", "古寺尋修竹，荒園讀斷碑。", "三杯午時酒，一簇晚沙旗。", "春色從今好，重來未可知。"]'),
('71f459d5-86b8-4299-85b5-935aaf8fd933','壓雲亭','張孝祥','宋','宋诗','song-poetry','','[]','登臨多好處，第一壓雲亭。',48,'全唐诗/poet.song.149000.json','["登臨多好處，第一壓雲亭。", "水作高低白，山分遠近青。", "人家半煙樹，客柁滿春汀。", "賸欲留連晚，歸時更摘星。"]'),
('20bf1ff4-616b-4267-83e5-e630a00a0f9e','玉淵亭','張孝祥','宋','宋诗','song-poetry','','[]','夜投寶覺寺，徑上玉淵亭。',48,'全唐诗/poet.song.149000.json','["夜投寶覺寺，徑上玉淵亭。", "峽束千崖水，天分一段星。", "神光行熠燿，空翠矗青冥。", "雄觀兼幽趣，悠然寄獨醒。"]'),
('bf75870c-7913-4977-90b1-459e64ea48f6','簡寂觀','張孝祥','宋','宋诗','song-poetry','','[]','瀑水流紅葉，荒祠瑣翠微。',48,'全唐诗/poet.song.149000.json','["瀑水流紅葉，荒祠瑣翠微。", "紫霄人不到，白鶴事全非。", "苦笋今年少，黄冠竟日饑。", "摩挲石龍柱，竚立爲歔欷。"]'),
('e7a6f671-aa3b-40c1-a1cd-fb6666d8389b','皇甫坦所居','張孝祥','宋','宋诗','song-poetry','','[]','石側疑無路，峯回別有天。',48,'全唐诗/poet.song.149000.json','["石側疑無路，峯回別有天。", "神泉通玉海，帝畫麗奎躔。", "紫闥雖重到，青瑶却未鎸。", "直須香案吏，爲寫白雲篇。"]'),
('5d9b41ac-4dd2-4c66-be4d-623545be8999','出郊','張孝祥','宋','宋诗','song-poetry','','[]','楚霧侵衣潤，湘江到眼明。',48,'全唐诗/poet.song.149000.json','["楚霧侵衣潤，湘江到眼明。", "春連嶽麓寺，花滿定王城。", "佳客真如此，天公却不晴。", "空濛殊可意，沙濕馬蹄輕。"]'),
('7a3bc110-97d5-4a63-a64f-5bc28d88c2dc','酬朱元晦登定王臺之作','張孝祥','宋','宋诗','song-poetry','','[]','海內朱公子，端能爲我來。',48,'全唐诗/poet.song.149000.json','["海內朱公子，端能爲我來。", "譚諧渺今古，歡喜到輿臺。", "日月何曾蔽，風雲會有開。", "登臨一杯酒，莫作楚囚哀。"]'),
('4edb0cbb-0e20-4074-a954-2f089533a721','吳伯承生孫交游共爲之喜凡七人分韻我亦從來識英物試教啼看定何如某得啼定字  其一','張孝祥','宋','宋诗','song-poetry','','[]','得孫當贊喜，喚客便分題。',48,'全唐诗/poet.song.149000.json','["得孫當贊喜，喚客便分題。", "樓鼓方行夜，天星恰照奎。", "熊羆通夢寐，孔釋自提携。", "湯餠那應晚，吾來爲止啼。"]'),
('354fe34a-3a77-40f8-84e0-a1151cc9cc7d','吳伯承生孫交游共爲之喜凡七人分韻我亦從來識英物試教啼看定何如某得啼定字  其二','張孝祥','宋','宋诗','song-poetry','','[]','吳郎薄軒冕，市隠室垂罄。',48,'全唐诗/poet.song.149000.json','["吳郎薄軒冕，市隠室垂罄。", "兒孫忽成行，乘除乃天定。", "我女才三歲，此事當退聽。", "賸欲便款門，積雨道苦濘。"]'),
('852fed70-908f-4c85-9b2d-d548a6cc6c7c','贈王茂升','張孝祥','宋','宋诗','song-poetry','','[]','薦士移書早，論交識面遲。',48,'全唐诗/poet.song.149000.json','["薦士移書早，論交識面遲。", "寬行十里路，細讀百篇詩。", "句法能如此，胸中定自奇。", "不嫌知己少，莫厭此官卑。"]'),
('598ef158-ed5b-4b18-9500-5f9f4acf0373','秋日郊居','張孝祥','宋','宋诗','song-poetry','','[]','秋日郊扉樂，心閑景趣閑。',48,'全唐诗/poet.song.149000.json','["秋日郊扉樂，心閑景趣閑。", "風生疎竹裏，雨在片雲間。", "疏港聊通水，關門不礙山。", "殘書讀未盡，飛鳥暮雲還。"]'),
('37359fdf-74d9-4150-a255-6eb42020583a','中秋書事','張孝祥','宋','宋诗','song-poetry','','[]','江月清光冷，波亭夜色奇。',48,'全唐诗/poet.song.149000.json','["江月清光冷，波亭夜色奇。", "流螢翻露草，倦鵲遶風枝。", "素魄不長滿，故人頻語離。", "有懷千里恨，若爲一杯辭。"]'),
('5a82898d-84a6-490b-b3d7-55881b44a437','請說歸休好  其一','張孝祥','宋','宋诗','song-poetry','','[]','請說歸休好，扶行白髮親。',48,'全唐诗/poet.song.149000.json','["請說歸休好，扶行白髮親。", "訪醫無遠近，買藥辨新陳。", "索酒兼鄰甕，要賓盡里人。", "短長無不可，且得是閑身。"]'),
('e5f26309-8653-46a1-857c-2a7c6d0a5252','請說歸休好  其二','張孝祥','宋','宋诗','song-poetry','','[]','請說歸休好，從今自在閑。',48,'全唐诗/poet.song.149000.json','["請說歸休好，從今自在閑。", "新除疊黄紙，舊隠接青山。", "竹遶披風榭，蘆藏釣月灣。", "田間四時景，何處不開顔。"]'),
('af483949-8ef3-43ac-b9ff-3afc5db670cc','喜歸作','張孝祥','宋','宋诗','song-poetry','','[]','月地參差影，風簷取次花。',48,'全唐诗/poet.song.149000.json','["月地參差影，風簷取次花。", "酒爲春主掌，貧是老生涯。", "湖海扁舟去，江淮到處家。", "扶持兩仙伯，丹鼎絢彤霞。"]'),
('d4a0ba8a-cfc1-4cdb-992f-2447298eb604','故年家姚公挽章','張孝祥','宋','宋诗','song-poetry','','[]','世德方隆報，君恩未及封。',48,'全唐诗/poet.song.149000.json','["世德方隆報，君恩未及封。", "起家惟子好，弗壽竟誰鍾。", "無復時中聖，遥憐不相舂。", "隻雞吾阻往，抆淚睇喬松。"]'),
('cbcf6ec8-38d8-4f36-bc1e-0a57bc95f0a8','殿廬偶成','張孝祥','宋','宋诗','song-poetry','','[]','簾幕垂垂燕子風，宮花春盡翠陰濃。',32,'全唐诗/poet.song.149000.json','["簾幕垂垂燕子風，宮花春盡翠陰濃。", "日長禁直文書靜，寶爇時時一拆封。"]'),
('ac04dbac-efa8-47dd-bcd9-5b5046f2d1f4','和劉國正覓雌黄  其一','張孝祥','宋','宋诗','song-poetry','','[]','劉郎家具少於車，只有詩囊未厭渠。',32,'全唐诗/poet.song.149000.json','["劉郎家具少於車，只有詩囊未厭渠。", "乞與丹鉛將底用，點勘腹中行秘書。"]'),
('a43983ad-3123-44cf-80a0-a4a86af87c98','和劉國正覓雌黄  其二','張孝祥','宋','宋诗','song-poetry','','[]','蠻牋欹斜落傑句，清似秋月橫蛾眉。',32,'全唐诗/poet.song.149000.json','["蠻牋欹斜落傑句，清似秋月橫蛾眉。", "口中雌黄蓋天下，聊欲教我煩新詩。"]'),
('f4d08498-77c1-4650-ad18-e78a621def5d','蠟梅','張孝祥','宋','宋诗','song-poetry','','[]','滿面宮粧淡淡黄，絳紗封蠟貯幽香。',32,'全唐诗/poet.song.149000.json','["滿面宮粧淡淡黄，絳紗封蠟貯幽香。", "遥憐未識春消息，乞與一枝教斷腸。"]'),
('a5241d20-06ce-4b85-ba48-568dc90446e6','次韻左舉善木樨','張孝祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','想見秋花插滿頭，遥憐不負此山遊。',32,'全唐诗/poet.song.149000.json','["想見秋花插滿頭，遥憐不負此山遊。", "一枝併與詩筒饋，氣壓西湖萬斛秋。"]'),
('27a05ae2-30cc-4126-958d-2ae4c498ad43','以茶芽焦坑送周德友德友來索賜茶僕無之也  其一','張孝祥','宋','宋诗','song-poetry','','[]','帝家好賜矞雲龍，祇到調元六七公。',32,'全唐诗/poet.song.149000.json','["帝家好賜矞雲龍，祇到調元六七公。", "頼有家山供小草，猶堪詩老薦春風。"]'),
('ddd15721-947e-4ee3-9f09-1ea07ed262b9','以茶芽焦坑送周德友德友來索賜茶僕無之也  其二','張孝祥','宋','宋诗','song-poetry','','[]','仇池詩中識焦坑，風味官焙可抗行。',32,'全唐诗/poet.song.149000.json','["仇池詩中識焦坑，風味官焙可抗行。", "鑽餘權倖亦及我，十輩走前公試烹。"]'),
('64032cd4-0471-40f5-addf-e47be2433ead','蘄春道中','張孝祥','宋','宋诗','song-poetry','','[]','霜凈波平水落灣，我行正在畫圖間。',32,'全唐诗/poet.song.149000.json','["霜凈波平水落灣，我行正在畫圖間。", "簾鈎不用怕風日，且看江南江北山。"]'),
('90afada3-9f3c-447e-b4dd-d345c2452acf','次江州王知府叔堅韻  其一','張孝祥','宋','宋诗','song-poetry','','[]','說河不救癡兒渴，砥柱乃障頹波流。',32,'全唐诗/poet.song.149000.json','["說河不救癡兒渴，砥柱乃障頹波流。", "庾公樓中三昧手，何時歸侍殿西頭。"]'),
('6bd8c527-b0f2-4db9-9f29-6e31848c8ece','次江州王知府叔堅韻  其二','張孝祥','宋','宋诗','song-poetry','','[]','霜餘江北山如畫，歲晚家鄉稻作京。',32,'全唐诗/poet.song.149000.json','["霜餘江北山如畫，歲晚家鄉稻作京。", "萬里公方黄鵠舉，扁舟我自白鷗盟。"]'),
('d6acb158-3f47-401d-aa49-2edee392bbf2','次江州王知府叔堅韻  其三','張孝祥','宋','宋诗','song-poetry','','[]','今朝放纜好天色，過午忽作打頭風。',32,'全唐诗/poet.song.149000.json','["今朝放纜好天色，過午忽作打頭風。", "却望江州纔十里，我船且繫蘆花中。"]'),
('22822689-887d-44f3-9757-6193ee66680d','次江州王知府叔堅韻  其四','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山突兀上霄漢，使君豪氣與相酬。',32,'全唐诗/poet.song.149000.json','["廬山突兀上霄漢，使君豪氣與相酬。", "廬山雖好不足戀，歸矣當爲蒼生謀。"]'),
('02f5b08b-3d4a-4488-a413-1272ea709e61','次江州王知府叔堅韻  其五','張孝祥','宋','宋诗','song-poetry','','[]','連城鼠璞不足唾，千金敝帚誰能酬。',32,'全唐诗/poet.song.149000.json','["連城鼠璞不足唾，千金敝帚誰能酬。", "只今機會不容髮，願借前箸君當謀。"]'),
('eeb29c61-4f5b-40dd-a506-644bcff198b5','次江州王知府叔堅韻  其六','張孝祥','宋','宋诗','song-poetry','','[]','谷簾釀酒極清美，風味大似主人翁。',32,'全唐诗/poet.song.149000.json','["谷簾釀酒極清美，風味大似主人翁。", "我有一尊正傾寫，却思煙雨庾樓中。"]'),
('d132613e-c40d-4952-a66a-1e7a9dcb574d','次江州王知府叔堅韻  其七','張孝祥','宋','宋诗','song-poetry','','[]','何人列屋閉嬋娟，憶對清歌重慨然。',32,'全唐诗/poet.song.149000.json','["何人列屋閉嬋娟，憶對清歌重慨然。", "一笑相憐窮相眼，謾撩詩思入愁邊。"]'),
('6ad0f93a-d7a4-45bc-9e45-9009692bffcc','次江州王知府叔堅韻  其八','張孝祥','宋','宋诗','song-poetry','','[]','經行有恨是陰雨，不見香爐生紫煙。',32,'全唐诗/poet.song.149000.json','["經行有恨是陰雨，不見香爐生紫煙。", "安得草堂容一榻，聽松聽水日高眠。"]'),
('3752e2f5-ee84-4a9d-a679-fdae32fb4079','道間見梅','張孝祥','宋','宋诗','song-poetry','','[]','寒女生來不解粧，天然玉色照孤芳。',32,'全唐诗/poet.song.149000.json','["寒女生來不解粧，天然玉色照孤芳。", "疎籬茅舍無端恨，故有幽人與斷腸。"]'),
('74036989-484f-4684-bcb7-2ec564d30094','題定山寺  其一','張孝祥','宋','宋诗','song-poetry','','[]','蹇馿夜入定山寺，古屋貯月松風清。',32,'全唐诗/poet.song.149000.json','["蹇馿夜入定山寺，古屋貯月松風清。", "止聞挂塔一鈴語，不見撞鐘千指迎。"]'),
('fed1b230-ca3a-480d-a7bb-ebf3124d33ca','題定山寺  其二','張孝祥','宋','宋诗','song-poetry','','[]','千山蒼茫月東出，萬木擺摇風怒號。',32,'全唐诗/poet.song.149000.json','["千山蒼茫月東出，萬木擺摇風怒號。", "幽人隠几撫羣動，清燈明滅爐煙高。"]'),
('4bc57d56-376b-403e-bdfb-5999b4f19714','昭亭食柑','張孝祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一雙分我洞庭秋，梨棗傍觀不那羞。',32,'全唐诗/poet.song.149000.json','["一雙分我洞庭秋，梨棗傍觀不那羞。", "喚得風霜回齒頰，夜尋清夢五湖舟。"]'),
('97203246-526a-4999-9895-31ebe8de7c6a','和如庵  其一','張孝祥','宋','宋诗','song-poetry','','[]','厭聽諸方三昧禪，却思夜雨對床眠。',32,'全唐诗/poet.song.149000.json','["厭聽諸方三昧禪，却思夜雨對床眠。", "欲知千偈如翻水，看取朝來綠漲川。"]'),
('bb5d0d1d-577c-489a-a747-3087228da28e','和如庵  其二','張孝祥','宋','宋诗','song-poetry','','[]','不談世法不談禪，徹曉齁齁一覺眠。',32,'全唐诗/poet.song.149000.json','["不談世法不談禪，徹曉齁齁一覺眠。", "箇裏神通元不小，回風急雨震山川。"]'),
('8e7fd72c-6a54-4ec7-9577-71b8a07bf1ff','和如庵  其三','張孝祥','宋','宋诗','song-poetry','','[]','朝供爐香夜供燈，閑來落得困瞢騰。',32,'全唐诗/poet.song.149000.json','["朝供爐香夜供燈，閑來落得困瞢騰。", "如庵許我參堂去，長作昭亭粥飯僧。"]'),
('f5964da2-28ae-4ca6-8146-0f84e4fa7ee0','和如庵  其四','張孝祥','宋','宋诗','song-poetry','','[]','一燈分作百千燈，光徧河沙正鬰騰。',32,'全唐诗/poet.song.149000.json','["一燈分作百千燈，光徧河沙正鬰騰。", "稽首應庵休揀擇，直須傳與在家僧。"]'),
('203d6cd6-a5b1-4325-8406-807bdd1623a4','和如庵  其五','張孝祥','宋','宋诗','song-poetry','','[]','道人受偈自然燈，筆底光芒夜夜騰。',32,'全唐诗/poet.song.149000.json','["道人受偈自然燈，筆底光芒夜夜騰。", "詩成十手不供寫，鑿齒敢對彌天僧。"]'),
('e82005e6-7c74-412a-9205-e8561bedd6cc','和如庵  其六','張孝祥','宋','宋诗','song-poetry','','[]','飛蛾撲撲誤占燈，火色何人要上騰。',32,'全唐诗/poet.song.149000.json','["飛蛾撲撲誤占燈，火色何人要上騰。", "我已澹然忘世味，蒲團紙帳只依僧。"]'),
('6c028421-7b7c-434d-bb21-b73607369b3b','楓橋','張孝祥','宋','宋诗','song-poetry','','[]','四年忽忽兩經過，古岸依然窣堵波。',32,'全唐诗/poet.song.149000.json','["四年忽忽兩經過，古岸依然窣堵波。", "借我繩牀消午暑，亂蟬鳴處竹陰多。"]'),
('ee062af6-b767-4578-bd52-0658aa750def','題西湖可賦軒','張孝祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風光獵獵上烏巾，不那西湖爛熳春。',32,'全唐诗/poet.song.149000.json','["風光獵獵上烏巾，不那西湖爛熳春。", "借我繩床對脩竹，爲君一洗軟紅塵。"]'),
('c7312392-bb2a-4771-bf35-666ec1ee1037','題胡敦約山行圖','張孝祥','宋','宋诗','song-poetry','','[]','松行石磴兩崎嶇，此去長安路更迂。',32,'全唐诗/poet.song.149000.json','["松行石磴兩崎嶇，此去長安路更迂。", "底箇官儂强健在，葛巾芒屩自騎馿。"]'),
('7656df48-6798-4182-aac0-e2f3fa7c3867','從張唐卿乞韭黄','張孝祥','宋','宋诗','song-poetry','','[]','雪壓畦蔬僮手皸，度郎多日欠常珍。',32,'全唐诗/poet.song.149000.json','["雪壓畦蔬僮手皸，度郎多日欠常珍。", "懸知旅食初無恙，窖裏黄芽借得春。"]'),
('9dd13cd9-dd03-4cd7-88a7-06515f68a02a','送紙衾韓中父  其一','張孝祥','宋','宋诗','song-poetry','','[]','韓郎香盡諸緣絕，壞衲篝燈供佛熏。',32,'全唐诗/poet.song.149000.json','["韓郎香盡諸緣絕，壞衲篝燈供佛熏。", "乞與紙衾綿樣暖，撩教醉裏夢紛紜。"]'),
