('9ee2b530-6358-409b-be04-f3be9080b061','琵琶亭  其二','張孝祥','宋','宋诗','song-poetry','','[]','潯陽江上琵琶月，彭澤門前楊柳風。',32,'全唐诗/poet.song.149000.json','["潯陽江上琵琶月，彭澤門前楊柳風。", "兩賢抵許不相似，哀樂雖殊吾意同。"]'),
('68921c0e-9493-47e3-b094-4fc35612c18a','過三塔寺  其一','張孝祥','宋','宋诗','song-poetry','','[]','湖光瀲灧接天浮，風捲銀濤未肯休。',32,'全唐诗/poet.song.149000.json','["湖光瀲灧接天浮，風捲銀濤未肯休。", "夜岸繫舟來古塔，不妨蹤迹更遲留。"]'),
('ddb31f1c-0bbb-4f20-b587-93588bc72048','過三塔寺  其二','張孝祥','宋','宋诗','song-poetry','','[]','層巒疊嶂幾重重，萬頃煙波浩渺中。',32,'全唐诗/poet.song.149000.json','["層巒疊嶂幾重重，萬頃煙波浩渺中。", "釣艇未歸饒夕照，耳邊蘆葦戰寒風。"]'),
('68a70c10-80c1-41cf-b7c8-bcbccdad8e60','玉淵','張孝祥','宋','宋诗','song-poetry','','[]','靈源直上與天通，借路來從五老峯。',32,'全唐诗/poet.song.149000.json','["靈源直上與天通，借路來從五老峯。", "試向欄干敲拄杖，爲君喚起玉淵龍。"]'),
('5c4708e1-3d72-4ef4-8a99-17d33a1fc002','萬杉寺  其一','張孝祥','宋','宋诗','song-poetry','','[]','莊田總是昭陵賜，更著官船載御書。',32,'全唐诗/poet.song.149000.json','["莊田總是昭陵賜，更著官船載御書。", "今日殘僧無飯喫，却催積欠意何如。"]'),
('34a9e005-8001-4737-bbee-b344786d66f6','萬杉寺  其二','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','老榦參天一萬株，廬山佳處著浮圖。',32,'全唐诗/poet.song.149000.json','["老榦參天一萬株，廬山佳處著浮圖。", "只因買斷山中景，破費神龍百斛珠。"]'),
('e3f4a8ec-6852-49de-8146-6950cc72db12','楞伽寺  其一','張孝祥','宋','宋诗','song-poetry','','[]','朱砂峯下楞伽寺，白髮僧生乙丑年。',32,'全唐诗/poet.song.149000.json','["朱砂峯下楞伽寺，白髮僧生乙丑年。", "乞我一杯清凈水，爲扶脚力上層巔。"]'),
('4387290a-0f36-4033-bab8-3d8d7bc851ed','楞伽寺  其二','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','天圍欲盡三千界，地險真成百二關。',32,'全唐诗/poet.song.149000.json','["天圍欲盡三千界，地險真成百二關。", "不向中峯最高處，諸君元未識廬山。"]'),
('9ea0d2a5-2e23-4bdb-a67c-2729ef47d2ee','楞伽寺  其三','張孝祥','宋','宋诗','song-poetry','','[]','山北山南劫火餘，如何留得此僧居。',32,'全唐诗/poet.song.149000.json','["山北山南劫火餘，如何留得此僧居。", "可憐鐘閣三枝竹，無復山房萬卷書。"]'),
('3201b8c3-4364-42ee-ac05-adb6ecbb5d6c','鸞溪','張孝祥','宋','宋诗','song-poetry','','[]','蒼龍翔舞餘千仞，瀑水奔流欲百盤。',32,'全唐诗/poet.song.149000.json','["蒼龍翔舞餘千仞，瀑水奔流欲百盤。", "定自山靈憐寂寞，故教臨鏡有窺鸞。"]'),
('71799122-bb04-4243-9e3e-830cbda34904','漪瀾堂','張孝祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水漫春洲到處通，檣竿無數插空濛。',32,'全唐诗/poet.song.149000.json','["水漫春洲到處通，檣竿無數插空濛。", "主人只愛堂前木，不放廬山入眼中。"]'),
('6cf570ec-b291-4324-970a-54ce6ddc1914','和家君韻寄舅氏','張孝祥','宋','宋诗','song-poetry','','[]','夷齊之清格鄙頑，孳孳盜跖何曾閑。',32,'全唐诗/poet.song.149000.json','["夷齊之清格鄙頑，孳孳盜跖何曾閑。", "空齋風定香縷直，但有書冊猶相關。"]'),
('b9fbef85-ba13-48ee-90bb-1024d1560684','送猿翟伯壽','張孝祥','宋','宋诗','song-poetry','','[]','萬里歸來無苜蓿，扁舟共載兩猿君。',32,'全唐诗/poet.song.149000.json','["萬里歸來無苜蓿，扁舟共載兩猿君。", "今日送君向何處，黄鶴山中多白雲。"]'),
('d091c4a2-0705-489b-bcff-50e20963e236','奉題富文橫舟','張孝祥','宋','宋诗','song-poetry','','[]','山林城市不相得，此處俱勝天下降。',32,'全唐诗/poet.song.149000.json','["山林城市不相得，此處俱勝天下降。", "欲展江天一千里，橫舟西南更開窗。"]'),
('38215bb0-d848-4f8f-91a5-0a3f0304b7ca','子餘許修草堂遣句勸請','張孝祥','宋','宋诗','song-poetry','','[]','蓮社高人久寂寥，草堂風物故蕭蕭。',32,'全唐诗/poet.song.149000.json','["蓮社高人久寂寥，草堂風物故蕭蕭。", "追還舊觀須公等，喚我它年寄一瓢。"]'),
('2c3557d2-165a-46be-8e1e-4f3a113203ba','次韻南軒喜雨  其一','張孝祥','宋','宋诗','song-poetry','','[]','午窗溜雨忽潺潺，想見欣然阡陌間。',32,'全唐诗/poet.song.149000.json','["午窗溜雨忽潺潺，想見欣然阡陌間。", "敬簡堂中有新事，水滿新池雨滿山。"]'),
('a43f9e1f-9050-4f0d-b2d4-504f6bd4c629','次韻南軒喜雨  其二','張孝祥','宋','宋诗','song-poetry','','[]','北風吹雲如裂絲，赤龍卷水尾倒垂。',32,'全唐诗/poet.song.149000.json','["北風吹雲如裂絲，赤龍卷水尾倒垂。", "雷轟電激不敢駐，驅入吾家喜雨詩。"]'),
('30f29bc2-cb50-4c7f-ab2b-15b54e5b839b','次韻南軒喜雨  其三','張孝祥','宋','宋诗','song-poetry','','[]','天公有意不作難，一雨千里須臾間。',32,'全唐诗/poet.song.149000.json','["天公有意不作難，一雨千里須臾間。", "但得湖南今歲熟，我亦腰鎌歸故山。"]'),
('8df70446-2d21-472d-8038-7280ff8b0045','次韻南軒喜雨  其四','張孝祥','宋','宋诗','song-poetry','','[]','使君保障仍繭絲，可憐民屋如罄垂。',32,'全唐诗/poet.song.149000.json','["使君保障仍繭絲，可憐民屋如罄垂。", "今朝一雨秋事了，便可高詠豐年詩。"]'),
('4d824148-70cc-40c3-b7c4-22b11f701bc5','送茶','張孝祥','宋','宋诗','song-poetry','','[]','頭綱八餠密雲龍，曾侍虛皇拆御封。',32,'全唐诗/poet.song.149000.json','["頭綱八餠密雲龍，曾侍虛皇拆御封。", "今日湘中見新夸，喚回清夢九煙重。"]'),
('2f403859-93ce-4c03-a8a8-56556c57306b','從吳伯承乞茶','張孝祥','宋','宋诗','song-poetry','','[]','三月新茶猶未識，作詩去問野堂君。',32,'全唐诗/poet.song.149000.json','["三月新茶猶未識，作詩去問野堂君。", "春風有脚家家到，定爲粗官不見分。"]'),
('8b9b7b37-c1aa-4d99-bf31-d551a5b68be3','送僧遊天台','張孝祥','宋','宋诗','song-poetry','','[]','寶剎憑虛五百仙，猶將心事向塵邊。',32,'全唐诗/poet.song.149000.json','["寶剎憑虛五百仙，猶將心事向塵邊。", "煩君試問橋東寺，若箇而今又應緣。"]'),
('66a6bab6-df56-43fd-8d61-22098f9f1dd0','石惠叔以石斛爲貺因筆賦詩','張孝祥','宋','宋诗','song-poetry','','[]','截得蒼山一段秋，千峯萬壑翠光浮。',32,'全唐诗/poet.song.149000.json','["截得蒼山一段秋，千峯萬壑翠光浮。", "虛堂百尺瑠璃簟，對此真堪作卧游。"]'),
('d4ca0d01-76e4-4cef-89dc-4c3c26878151','題趙知府墓','張孝祥','宋','宋诗','song-poetry','','[]','翁仲無聲石馬閑，墓門蕭瑟鎖青煙。',32,'全唐诗/poet.song.149000.json','["翁仲無聲石馬閑，墓門蕭瑟鎖青煙。", "故人仰卧青松下，落日孤村聞杜鵑。"]'),
('d9e49a56-9fcf-42ad-86de-7dba7844e74b','朝謁南嶽','張孝祥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','泰常嵩岱拱神州，玉帛閑來四十秋。',32,'全唐诗/poet.song.149000.json','["泰常嵩岱拱神州，玉帛閑來四十秋。", "却到朱明回北首，憂時淚作九江流。"]'),
('d4bb4ae2-5cbf-4705-831e-3f3048df89c4','題方務德靜江所作雪觀','張孝祥','宋','宋诗','song-poetry','','[]','昔日主人今法從，空留偉觀古城隅。',32,'全唐诗/poet.song.149000.json','["昔日主人今法從，空留偉觀古城隅。", "邦人指點思遺愛，我亦先生屋上烏。"]'),
('b6fbed87-4192-4380-af0b-7b7046227b66','和伯承送茶韻','張孝祥','宋','宋诗','song-poetry','','[]','佳句新茶亦太奇，嘗新即日未全遲。',32,'全唐诗/poet.song.149000.json','["佳句新茶亦太奇，嘗新即日未全遲。", "掃除鴈鶩行邊事，細輾春風細讀詩。"]'),
('af5f6491-a180-4fef-b8bc-424131819c62','和伯承惠笋  其一','張孝祥','宋','宋诗','song-poetry','','[]','錦籜離離鄉觸藩，怒雷挾雨更追奔。',32,'全唐诗/poet.song.149000.json','["錦籜離離鄉觸藩，怒雷挾雨更追奔。", "絕甘頼有吳公子，菌蠢貓頭不足論。"]'),
('9e8a34bf-64c0-4ffa-aa2a-b0d6c5afb66b','和伯承惠笋  其二','張孝祥','宋','宋诗','song-poetry','','[]','楚産惟渠可定交，時時隔壁望煙梢。',32,'全唐诗/poet.song.149000.json','["楚産惟渠可定交，時時隔壁望煙梢。", "已煩穉子來相過，更有新詩送島郊。"]'),
('4d6ebc8e-9252-44b9-b9e3-9aa82458130b','有懷長沙知識呈欽夫兄弟  其一','張孝祥','宋','宋诗','song-poetry','','[]','順寧去覆郎官錦，府谷仍監太府錢。',32,'全唐诗/poet.song.149000.json','["順寧去覆郎官錦，府谷仍監太府錢。", "唯有吾宗老兄弟，閉門依舊絕韋編。"]'),
('8d31b129-0999-4b2e-82c4-809137bf3eb9','有懷長沙知識呈欽夫兄弟  其二','張孝祥','宋','宋诗','song-poetry','','[]','春風花柳又芳妍，更接髯郎水竹園。',32,'全唐诗/poet.song.149000.json','["春風花柳又芳妍，更接髯郎水竹園。", "小閣橫橋俱勝絕，只應欠我共開尊。"]'),
('f09507a2-069b-4a3b-afa0-17702487ac7a','有懷長沙知識呈欽夫兄弟  其三','張孝祥','宋','宋诗','song-poetry','','[]','召公分陝是東鄰，天遠堂中好主人。',32,'全唐诗/poet.song.149000.json','["召公分陝是東鄰，天遠堂中好主人。", "更喜新來黄太史，剩拚佳句了新春。"]'),
('6544bc12-0e6b-4648-9da2-51a399f2d589','有懷長沙知識呈欽夫兄弟  其四','張孝祥','宋','宋诗','song-poetry','','[]','髯郎高卧元無恙，何日湘濱具一舟。',32,'全唐诗/poet.song.149000.json','["髯郎高卧元無恙，何日湘濱具一舟。", "肯約春風同過我，爲公釃酒炙肥牛。"]'),
('2b489f3a-fa90-475b-9ab8-893f4039fe0c','有懷長沙知識呈欽夫兄弟  其五','張孝祥','宋','宋诗','song-poetry','','[]','洛陽家世邢郎子，間止逍遥自在身。',32,'全唐诗/poet.song.149000.json','["洛陽家世邢郎子，間止逍遥自在身。", "病肺秋來定甦眚，可能乘興到沙津。"]'),
('28ff18f5-f319-47c0-834f-c905436bbf69','題塔子寺','張孝祥','宋','宋诗','song-poetry','','[]','酴醾壓架玉交加，深院無人有落花。',32,'全唐诗/poet.song.149000.json','["酴醾壓架玉交加，深院無人有落花。", "却憶江南田舍樂，旋敲生火煮新茶。"]'),
('85855d4a-6306-409d-aff0-e20df21f2102','題斷堤寺  其一','張孝祥','宋','宋诗','song-poetry','','[]','柔桑細麥綠油油，雲水烘春爛不收。',32,'全唐诗/poet.song.149000.json','["柔桑細麥綠油油，雲水烘春爛不收。", "馬上困來尋歇處，斷堤寺裏半時留。"]'),
('f8cb0a9f-db64-4f85-844c-cb4b81cbf200','題斷堤寺  其二','張孝祥','宋','宋诗','song-poetry','','[]','堤邊楊柳密藏鴉，堤上游人兩髻丫。',32,'全唐诗/poet.song.149000.json','["堤邊楊柳密藏鴉，堤上游人兩髻丫。", "可惜行春來較晚，誰家留得碧桃花。"]'),
('da46b445-af18-41b9-b218-b943069db577','題斷堤寺  其三','張孝祥','宋','宋诗','song-poetry','','[]','古寺留春最得多，紫微花畔海棠窠。',32,'全唐诗/poet.song.149000.json','["古寺留春最得多，紫微花畔海棠窠。", "無人歲晚同幽獨，古柏陰森著薜蘿。"]'),
('fd5ff40a-15ed-4e94-8694-950cc4bd65af','德化漪嵐堂感二林碑六言','張孝祥','宋','宋诗','song-poetry','','[]','兩林文章翰墨，只今塵上牆陰。',28,'全唐诗/poet.song.149000.json','["兩林文章翰墨，只今塵上牆陰。", "炎凉莫作世態，是非當印吾心。"]'),
('70965e76-7f73-44ac-9b5a-0b2a147ffcc0','欽夫遣送箭笋日鑄甚珍用所寄伯承韻作六言便請過臨','張孝祥','宋','宋诗','song-poetry','','[]','君家稚箭寶茗，賜出太官水衡。',28,'全唐诗/poet.song.149000.json','["君家稚箭寶茗，賜出太官水衡。", "已約髯吳過我，更須君來細評。"]'),
('35f367e5-f8e6-4085-a5ab-c9d0f8f202ed','欽夫和六言再用韻','張孝祥','宋','宋诗','song-poetry','','[]','君詩與物俱妙，鄙夫那敢抗衡。',28,'全唐诗/poet.song.149000.json','["君詩與物俱妙，鄙夫那敢抗衡。", "芭蕉辟君三舍，笋脯亦須改評。"]'),
('8c92d4fd-c291-4cfb-a4ff-baffcc0baadc','游湖山贈圓禪六言','張孝祥','宋','宋诗','song-poetry','','[]','素香無脂粉氣，好語諧韶濩音。',28,'全唐诗/poet.song.149000.json','["素香無脂粉氣，好語諧韶濩音。", "有人問西來意，門前秋水沉沉。"]'),
('44a54bf2-5178-4c2c-8355-d3b4f7fcef6c','送萬老六言','張孝祥','宋','宋诗','song-poetry','','[]','桑下不須再宿，囊中莫留一錢。',28,'全唐诗/poet.song.149000.json','["桑下不須再宿，囊中莫留一錢。", "打鼓退高臺寺，洗脚上五湖船。"]'),
('7cb91ec9-c1d0-4b24-9dc0-dc9213d808f0','次東坡先生韻  其一','張孝祥','宋','宋诗','song-poetry','','[]','微凉入船窗，秋水滿湘浦。',24,'全唐诗/poet.song.149000.json','["微凉入船窗，秋水滿湘浦。", "過盡前頭灘，只得夜來雨。"]'),
('e7710b2f-04ea-419e-b365-3a0fb14c91db','次東坡先生韻  其二','張孝祥','宋','宋诗','song-poetry','','[]','人魚不相及，挂頰以香餌。',24,'全唐诗/poet.song.149000.json','["人魚不相及，挂頰以香餌。", "因循十年錯，歸計覺今是。"]'),
('65e3e972-6baf-4af3-9ce3-143180ea8f55','次東坡先生韻  其三','張孝祥','宋','宋诗','song-poetry','','[]','悠然望江南，日出煙靄微。',24,'全唐诗/poet.song.149000.json','["悠然望江南，日出煙靄微。", "倚門雙白髮，屈指待兒歸。"]'),
('82f7ec60-077c-4ffc-99d4-cee5a787fee4','次東坡先生韻  其四','張孝祥','宋','宋诗','song-poetry','','[]','漁師來賣魚，船小風蕩漾。',24,'全唐诗/poet.song.149000.json','["漁師來賣魚，船小風蕩漾。", "得錢瞥波去，不怕江流漲。"]'),
('c9589581-1f2f-4df6-a32c-be5d9b20d6df','次東坡先生韻  其五','張孝祥','宋','宋诗','song-poetry','','[]','朝發方良磯，莫宿白水灣。',24,'全唐诗/poet.song.149000.json','["朝發方良磯，莫宿白水灣。", "寬作一月程，須見江南山。"]'),
('583a195e-ebe6-4d36-8d9d-64dbaecf13b7','次東坡先生韻  其六','張孝祥','宋','宋诗','song-poetry','','[]','我程可默數，中秋過江池。',24,'全唐诗/poet.song.149000.json','["我程可默數，中秋過江池。", "趁得江南米，新舂玉滿箕。"]'),
('d549bd6c-54fc-430a-876a-1be74750ca44','次東坡先生韻  其七','張孝祥','宋','宋诗','song-poetry','','[]','棧羊割肥紅，社甕撥濃綠。',24,'全唐诗/poet.song.149000.json','["棧羊割肥紅，社甕撥濃綠。", "再拜爲親壽，起舞自作曲。"]'),
('4db9f15d-e59f-4a50-80e3-406c0b3be377','次東坡先生韻  其八','張孝祥','宋','宋诗','song-poetry','','[]','閉門靜觀心，踵息閟天和。',24,'全唐诗/poet.song.149000.json','["閉門靜觀心，踵息閟天和。", "從渠江頭人，尺水一丈波。"]'),
('8b942ff7-8e36-4e32-97e7-3b4e3fa2389d','題福嚴寺行者堂','張孝祥','宋','宋诗','song-poetry','','[]','揮毫高山巔，餘墨走龍蛇。',24,'全唐诗/poet.song.149000.json','["揮毫高山巔，餘墨走龍蛇。", "請收今夜雨，爲汝洗袈裟。"]'),
('d0f71f1c-9e04-443b-a72b-a3fac0f4fd6b','題梅塢圖','張孝祥','宋','宋诗','song-poetry','','[]','我曾到梅塢，正自畫不如。',24,'全唐诗/poet.song.149000.json','["我曾到梅塢，正自畫不如。", "是處有風月，君無懷故居。"]'),
('8100d5df-c339-4b87-8b67-df17cc15b9e5','贈趙簽','張孝祥','宋','宋诗','song-poetry','','[]','趙侯富貴種，自有巖壑姿。',24,'全唐诗/poet.song.149000.json','["趙侯富貴種，自有巖壑姿。", "同姓古所敦，早晚踏天墀。"]'),
('4d23a60b-5a84-47c1-9bcd-2a232c430c6c','歸宗寺','張孝祥','宋','宋诗','song-poetry','','[]','兩峰雙澗水，萬古一篇詩。',24,'全唐诗/poet.song.149000.json','["兩峰雙澗水，萬古一篇詩。", "玉局竟仙去，空山無此碑。"]'),
('c9da90f0-7be7-4ab7-a3f3-a9e8700e6888','煙雨觀','張孝祥','宋','宋诗','song-poetry','','[]','七澤闌干外，茲游亦壯哉。',24,'全唐诗/poet.song.149000.json','["七澤闌干外，茲游亦壯哉。", "主人何處去，猶未賦歸來。"]'),
('7adc8ff0-3144-4aa6-9a31-b9d781a56e20','題朱元晦所書凱歌卷後','張孝祥','宋','宋诗','song-poetry','','[]','我詞不足錄，聊以醒渠醉。',24,'全唐诗/poet.song.149000.json','["我詞不足錄，聊以醒渠醉。", "更參三十年，當與風子對。"]'),
('6729054d-2639-40ae-a535-8f8017fb964f','贈萬上座','張孝祥','宋','宋诗','song-poetry','','[]','過了鐵圍山，復生金蓮臺。',24,'全唐诗/poet.song.149000.json','["過了鐵圍山，復生金蓮臺。", "與問萬上座，一笑愁容開。"]'),
('4afc0987-e462-400d-91b2-4ab4b7925b05','野牧圖  其一','張孝祥','宋','宋诗','song-poetry','','[]','吳牛三十角，久與牧相忘。',24,'全唐诗/poet.song.149000.json','["吳牛三十角，久與牧相忘。", "忽憶淮南路，春風滿柘岡。"]'),
('7c8ffa68-b6f9-4ca5-9e5a-e82c7fae5876','野牧圖  其二','張孝祥','宋','宋诗','song-poetry','','[]','秋晚稻生孫，催科不到門。',24,'全唐诗/poet.song.149000.json','["秋晚稻生孫，催科不到門。", "人閑牛亦樂，隨意過前村。"]'),
('c02030d9-bfbb-4aea-9756-577c903cb047','題畫','張孝祥','宋','宋诗','song-poetry','','[]','權郎筆墨禪，往者屢參請。',24,'全唐诗/poet.song.149000.json','["權郎筆墨禪，往者屢參請。", "斯人骨已朽，妙處一笑領。"]'),
('c985b836-8c23-4ee4-ad00-dd7d8e93f926','寧淵觀','張孝祥','宋','宋诗','song-poetry','','[]','極目洪波渺，轟轟浪接天。',48,'全唐诗/poet.song.149000.json','["極目洪波渺，轟轟浪接天。", "江心分殿宇，敕賜號寧淵。", "日照山如畫，雲濃小似烟。", "休尋蓬島地，只此水中仙。"]'),
('e50cae77-bfa9-4200-86cf-ee5130cf6735','寒光亭','張孝祥','宋','宋诗','song-poetry','','[]','亭依三塔占清幽，松竹環除翠欲流。',64,'全唐诗/poet.song.149000.json','["亭依三塔占清幽，松竹環除翠欲流。", "晚色晴開千嶂月，波光冷浸一天秋。", "瓊瑶影裏詩僧屋，雲錦香中釣客舟。", "風送不知何處笛，雁聲驚起荻花洲。"]'),
('1acff061-fd68-437f-93db-2bfc8ad872c3','讀書堂在烏江即唐張文昌讀書處自五代至宋皆世守之渡江後爲史氏所有','張孝祥','宋','宋诗','song-poetry','','[]','漫有五車書不讀，豈似一編勤過目。',136,'全唐诗/poet.song.149000.json','["漫有五車書不讀，豈似一編勤過目。", "癡兒鬻肆蠹魚書，巨富牙籤塵滿屋。", "市南水竹一畝空，平生腹笥史長公。", "閉戶却掃得真樂，冥搜萬古窺鴻濛。", "淹留歲時亦何有，策勛茲事要持久。", "吾家文昌讀書處，好在溪山落君手。", "上方治定登文儒，東觀石渠森寶書，望公起直承明廬。", "從來海內知名士，須讀人間未讀書。"]'),
('f6b76ea8-c2a5-42bf-bd89-57e107b3e025','咏梅次韻二首  其一','張孝祥','宋','宋诗','song-poetry','','[]','樓上簫聲欲斷魂，仙官分與一枝春。',64,'全唐诗/poet.song.149000.json','["樓上簫聲欲斷魂，仙官分與一枝春。", "旋摧粧額添新樣，細撚香鬚數玉塵。", "月下精神宜淡貯，雪邊肌體更清勻。", "老來花事無消息，只有君詩當寫真。"]'),
('2f737159-6cc8-4426-91f2-f6c39583dd53','咏梅次韻二首  其二','張孝祥','宋','宋诗','song-poetry','','[]','天與孤標不受塵，生憎桃李鬭芳新。',64,'全唐诗/poet.song.149000.json','["天與孤標不受塵，生憎桃李鬭芳新。", "詩成名下無虛士，花在身邊當麗人。", "只恐素英欺白髮，試煩纖手插烏巾。", "風流今代神仙尉，管得河陽縣裏春。"]'),
('57ed0378-c4fe-4a01-9310-f079dd1d117b','山居','張孝祥','宋','宋诗','song-poetry','','[]','松韻笙竽徑，雲容水墨天。',48,'全唐诗/poet.song.149000.json','["松韻笙竽徑，雲容水墨天。", "人行秋色裏，鶑語落花邊。", "修竹三間屋，清泉二頃田。", "了無官府事，鷄犬慕神仙。"]'),
('c310fb21-be0d-4fe4-acdf-79655e3c9a6f','上辟廱','張孝祥','宋','宋诗','song-poetry','','[]','金銅隠花古龍澀，朱干大羽紛紜立。',96,'全唐诗/poet.song.149000.json','["金銅隠花古龍澀，朱干大羽紛紜立。", "寶鍾玉磬垂丁東，和鸞雍雍八音翕。", "鯨吞虎噬二十年，至尊戎衣不解鞍。", "里中小兒事刀劍，管鑰擲去塵漫漫。", "真儒倏興明典禮，周庠連雲斬荆祀。", "銀袍如雲拱翠華，師儒便坐講經旨。"]'),
('6c55cb7e-2e5c-43f9-b740-f3284b082d58','船齋','張孝祥','宋','宋诗','song-poetry','','[]','齋居安穩似乘船，魚躍池光鷺宿煙。',32,'全唐诗/poet.song.149000.json','["齋居安穩似乘船，魚躍池光鷺宿煙。", "還有一生江海客，釣竿閑放日高眠。"]'),
('fee8dc74-a5fd-4120-a329-489e0660432b','寄方帥  其一','張孝祥','宋','宋诗','song-poetry','','[]','吳楚山河盡付公，君王長策在平戎。',64,'全唐诗/poet.song.149000.json','["吳楚山河盡付公，君王長策在平戎。", "人才王謝風流似，地望東西節制雄。", "赤手尚能探虎穴，白頭空是釣魚翁。", "將軍知我非徐庶，不向江邊起卧龍。"]'),
('d274f255-aa8e-43fb-ab70-d3cbd122da91','寄方帥  其二','張孝祥','宋','宋诗','song-poetry','','[]','賤子如今休說窮，玉麟銅虎信頻通。',64,'全唐诗/poet.song.149000.json','["賤子如今休說窮，玉麟銅虎信頻通。", "君今持橐甘泉裏，我不投書苦海中。", "且願耕桑依地主，長教溫飽荷天公。", "回思三十三年事，一笑相逢兩禿翁。"]'),
('69d22168-ce7f-4d93-8020-c6c96a5848eb','大麥行','張孝祥','宋','宋诗','song-poetry','','[]','大麥半枯自浮沉，小麥刺水鋪綠針。',96,'全唐诗/poet.song.149000.json','["大麥半枯自浮沉，小麥刺水鋪綠針。", "山邊老農望麥熟，出門見水放聲哭。", "去年泠泠九月雨，秋苗不收一粒穀。", "只今米價貴如玉，併日舉家纔食粥。", "小兒索飯門前啼，大兒雖瘦把鋤犂。", "晴時種麥耕荒隴，正好下秧無稻畦。"]'),
('3c14446f-3ca3-44f1-9267-44a79583a260','送長壽黄主簿','衛博','宋','宋诗','song-poetry','','[]','黄郎千人英，凜凜霜松姿。',216,'全唐诗/poet.song.149000.json','["黄郎千人英，凜凜霜松姿。", "鄴侯三萬卷，載復無遺辭。", "十年居太學，辛勤厭朝虀。", "詞場事雄俊，傲睨深叢羆。", "再拜天子前，袍笏光陸離。", "朅來皖水濱，樂哉同襟期。", "顧我蓬之心，友婭慚非宜。", "朝來擺征衫，悵望當分携。", "君家閩海陬，去作楚郢歸。", "大哉天宇間，會合固有時。", "丈夫志八表，曲士守一涯。", "錦衣行未暮，鸞桂先高枝。", "清潤照冰玉，唱和共塤箎。", "行行得所詣，何必事町畦。", "寒江清無波，愛景摇窗扉。", "衮衮江上山，萬象供品題。", "還登古石城，往和白雪詩。", "儻因西飛鴻，寄我長相思。"]'),
('2998f75c-c1b0-48cb-adca-4cdf0d4f75f1','偶成雜意四首  其一','衛博','宋','宋诗','song-poetry','','[]','清風被草木，歲歲蕃中園。',48,'全唐诗/poet.song.149000.json','["清風被草木，歲歲蕃中園。", "佳蔭欲翳空，擢秀何爭妍。", "黄楊獨咫尺，更說厄閠年。", "惜哉堅正姿，何獨慳於天。"]'),
('b95d2b42-dfda-4034-a1e9-083c264583a4','偶成雜意四首  其二','衛博','宋','宋诗','song-poetry','','[]','長松栽萬年，必在千仞巔。',48,'全唐诗/poet.song.149000.json','["長松栽萬年，必在千仞巔。", "卑哉蓬蒿間，斥鷃無高鶱。", "如何一杯水，活此橫海鱣。", "誰能激滄溟，爲子摶青天。"]'),
('955f3847-3875-45ef-b8ee-60c399447819','偶成雜意四首  其三','衛博','宋','宋诗','song-poetry','','[]','方朔出世士，揮斥隘八極。',48,'全唐诗/poet.song.149000.json','["方朔出世士，揮斥隘八極。", "乃與優侏儒，饑飽同一食。", "調笑劉天子，紿之聊一劇。", "此意竟不傳，無人子思側。"]'),
('0b629da6-3b0b-4dba-9e76-8479b3f86e6c','偶成雜意四首  其四','衛博','宋','宋诗','song-poetry','','[]','朝草百幅牋，暮草千函書。',48,'全唐诗/poet.song.149000.json','["朝草百幅牋，暮草千函書。", "貴人肯首耳，一言躡雲衢。", "但見人因子，不見子亦如。", "梁間嘯者誰，知是鬼揶揄。"]'),
('09f47378-6d0f-4da3-aac9-1b450ab34e03','送楊舒州','衛博','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我昔懷軍書，西行盡淮泗。',240,'全唐诗/poet.song.149000.json','["我昔懷軍書，西行盡淮泗。", "是時敵方張，長江飲渴騎。", "憨將何一律，兩地一朝棄。", "川原厭膏血，關山接烽燧。", "巋然舒子國，屹立干戈地。", "中有袴襦民，未可文法治。", "瘡痍待良藥，天子念循吏。", "誰厭承明直，雅是詩書帥。", "淮揚君肯薄，吾丘世寡二。", "正須烹鮮手，往述羨魚意。", "前驅觸炎熱，弭節及凉吹。", "朝衙百吏散，閉閤有餘致。", "臨州古云樂，此理敢輕議。", "近聞今單于，已遣朝正使。", "公師杜征南，郡得漢龔遂。", "里閭息愁歎，扞牧殆餘事。", "政成多暇日，寄我千金字。", "淮魚秋正美，灊山日空翠。", "匹馬不作難，爲公十日醉。", "頗見有此客，要使州人記。"]'),
('d333b80f-1860-4538-bbcb-2c2d55965c0a','不寐','衛博','宋','宋诗','song-poetry','','[]','夜深耿不寐，鼻息聞比鄰。',288,'全唐诗/poet.song.149000.json','["夜深耿不寐，鼻息聞比鄰。", "家童亦倡酬，轟雷隠牀漘。", "病夫默欹枕，愈覺展轉頻。", "天籟寂不聞，獨此聲輪囷。", "懸知鼾睡夫，定非識字人。", "不然事紛糾，豈得全其真。", "世上學書兒，頗結煩惱因。", "多識一丁字，便欲了八垠。", "誰甘凍龜縮，競作寒螿呻。", "今日爲何時，酣寢圖安身。", "往往中夜興，起舞徒逡巡。", "大哉出世士，天地衾枕均。", "首壓西山巔，氣蓋北海濱。", "死生一夢覺，寒暑同屈伸。", "時於兩踵間，出息疑氤氳。", "蝴蝶亦翩翻，客主誰疎親。", "譬如善飲人，號呶觀衆賓。", "又如富家翁，經營笑彌貧。", "優游木雁際，卒歲誰斧斤。", "問我無眼禪，答君妙入神。", "我亦起洗醆，軟脚長安春。", "垂我大鵬翼，脂我神馬輪。", "未經華胥國，聊追葛天民。", "夢回復惘然，喚起啼叢榛。"]'),
('2ac1220d-49ee-4485-b33f-2322b0fb2095','二貓詩','衛博','宋','宋诗','song-poetry','','[]','地偏人跡希，齋厨冷如刷。',144,'全唐诗/poet.song.149000.json','["地偏人跡希，齋厨冷如刷。", "老僧挑野菜，豈識腥與血。", "饑鼠知自遷，畜貓竟徒設。", "我來客南齋，盤餐稍羅列。", "烹炮愧寡鮮，棄置謝瑣屑。", "二貓亦慕羶，媻跚事爭齧。", "小兒强解事，叱逐加撞㧙。", "尺箠未去手，二貓復及闑。", "懲羹肯吹虀，廢食未因噎。", "小兒恚貓癡，提耳當割切。", "謝兒兒勿嗔，我曹更癡絕。", "要之等爲口，已矣莫中熱。"]'),
('844390ed-7435-4879-be31-64db6d526e9f','題安流亭','衛博','宋','宋诗','song-poetry','','[]','劍潭百尺深，中有神物蟠。',180,'全唐诗/poet.song.149000.json','["劍潭百尺深，中有神物蟠。", "東流并山脚，鑿鑿穿巑岏。", "廣擬一葦航，聲戰兩耳寒。", "異哉黄頭郎，放棹隨飛湍。", "勢若從天來，千仞轉一圜。", "百里不及眴，孰與嶺道難。", "長篙信敏手，岸石如劍攢。", "江頭憚瘏痡，誰不謀所安。", "嗟嗟彼征夫，遭時棄師干。", "不裹馬革中，來葬魚腹間。", "壯士等死耳，此命良辛酸。", "僕夫第知免，笑言雜悲歡。", "寧知利害塗，倚伏如毫端。", "豈無跛男子，不救爲可歎。", "晏安有鴆毒，懷哉宜鑒觀。"]'),
('77ca9438-11e7-4cb0-84a8-6c47656c4ccb','醉歌行','衛博','宋','宋诗','song-poetry','','[]','軟沙挾徑草微微，畫堂甲帳光流離。',192,'全唐诗/poet.song.149000.json','["軟沙挾徑草微微，畫堂甲帳光流離。", "堂外花驄瑪瑙覊，傳呼直到黄金墀。", "黄金墀下班如剪，蒼槐不動蟠蛟螭。", "出門膽落金吾將，歸去泣走銅山兒。", "河龍供鯉桂爲醑，御厨珍送絲絡垂。", "乾坤整頓萬事了，蹴踏四海乘丹梯。", "丈夫生時重意氣，胡爲到處潛傷悲。", "鄉里小兒狐白腋，五陵豪客顛倒衣。", "酒酣耳熱歌浩蕩，揮斥八極隘九圍。", "投戈却日日不住，焚膏尚卜升朝曦。", "君看博浪沙中客，圯下偷生天地窄。", "相期要看後五日，路逢莫問前一著。"]'),
('75843a3d-b5ca-47dd-b661-ccc0fd920ec7','贈王君用求畫小屏','衛博','宋','宋诗','song-poetry','','[]','先生本是談天口，雲夢胸中吞八九。',160,'全唐诗/poet.song.149000.json','["先生本是談天口，雲夢胸中吞八九。", "一丘一壑未忘情，得之於心應之手。", "分裂玄圃翻瀟湘，鬼神夜泣蛟龍藏。", "興來八極眇揮灑，陵奪萬象歸微茫。", "十日一水五日石，千年王宰今相識。", "已知相識意相親，異時直恐空相憶。", "跨鯨挾矢滄海遊，袖無贔屭無乃羞。", "促迫能事吾豈敢，激昂浩興君應酬。", "崩崖壓牀浪翻屋，咫尺端將萬里蹙。", "我生有意水石間，枕潄須君一屏足。"]'),
('b49c1b56-9025-4160-bb12-e47b358fec84','送齊六歸石城','衛博','宋','宋诗','song-poetry','','[]','春衫快馬君來時，寒江穩泛君今歸。',128,'全唐诗/poet.song.149000.json','["春衫快馬君來時，寒江穩泛君今歸。", "人生聚散定何許，悵望十年三別離。", "憶昔見君石城下，雜佩瑶瑜間蘭麝。", "三年一鳴驚倒人，欲和薰風奏韶夏。", "翰林主人子墨卿，文章意氣飄朝雲。", "君歸但掃三千牘，後會却揖賢書登。", "離離漠漠霜蕪沒，江上陰風攪寒日。", "不用長吟河畔草，與君且盡杯中物。"]'),
('5faeb121-a1b2-4984-ab63-b237927d6b7f','次韻張司法題鄭少尹庭下緋桃','衛博','宋','宋诗','song-poetry','','[]','梅飄柳墜半春中，庭下緋英細作叢。',64,'全唐诗/poet.song.149000.json','["梅飄柳墜半春中，庭下緋英細作叢。", "刺眼定添新葉綠，傷心應似故園紅。", "玄都怨感成塵事，石髓追游滿地風。", "報答春光須作意，亂飄繁萼向晴空。"]'),
('5c9d3d1c-1e72-479b-bb8b-f80804297cb3','張君請同次前韻速鄭少尹賞桃','衛博','宋','宋诗','song-poetry','','[]','邂逅溪源一夢中，空餘羅袖疊春叢。',64,'全唐诗/poet.song.149000.json','["邂逅溪源一夢中，空餘羅袖疊春叢。", "生憐烟杏勻肌薄，不分江梅映肉紅。", "要識臨塘比西子，便須索酒對東風。", "隨君拄杖敲門去，莫惜觥船一棹空。"]'),
('f0348bde-fc9d-4b31-a967-fdfc66c6f6ad','十二月十七日病中立春','衛博','宋','宋诗','song-poetry','','[]','綵勝宮花閙九門，挽回和氣入乾坤。',64,'全唐诗/poet.song.149000.json','["綵勝宮花閙九門，挽回和氣入乾坤。", "未教柳樹誇青眼，先與梅花作返魂。", "不見新蔬行節物，漫將一歲答春溫。", "病軀可是能頑巧，偏發天公造化恩。"]'),
('dea41f84-0b44-41ee-9460-fddc6a6a93e5','次韻贈汪解元','衛博','宋','宋诗','song-poetry','','[]','邇來待詔溢金門，詫賦誇詩陋古文。',64,'全唐诗/poet.song.149000.json','["邇來待詔溢金門，詫賦誇詩陋古文。", "獨忿典謨誣舊注，直將堯舜望吾君。", "公車兩吏催朝奏，乙牘中宸達夜分。", "且忍羈孤度殘臘，行看漢殿賞凌雲。"]'),
('608d29b8-06a7-4ed7-af15-f9c7e1c29f63','再次前韻送行','衛博','宋','宋诗','song-poetry','','[]','匆匆行役駐無因，縞紵相看足禮文。',64,'全唐诗/poet.song.149000.json','["匆匆行役駐無因，縞紵相看足禮文。", "江闊孤舟誰伴我，夜闌尊酒獨思君。", "離筵不用歌三疊，元夕重來月十分。", "更欲四方隨孟子，此生安得化爲雲。"]'),
('a6f240fd-1168-453a-8a3e-fd7217f8ff15','次韻汪解元留別','衛博','宋','宋诗','song-poetry','','[]','留別詩成語更酸，誰憐索米困長安。',64,'全唐诗/poet.song.149000.json','["留別詩成語更酸，誰憐索米困長安。", "聖朝有意臺萊詠，高士無嫌桂柏寒。", "聞道新書行入奏，少陪征棹慰餘歡。", "一封臨召君須出，山色溪光不可餐。"]'),
('4d866076-df48-4376-a359-366def96c63d','次韻贈汪解元行','衛博','宋','宋诗','song-poetry','','[]','平湖畫鷁春無際，古寺名花色斬新。',64,'全唐诗/poet.song.149000.json','["平湖畫鷁春無際，古寺名花色斬新。", "走馬未同追勝處，出門翻作送行頻。", "詩成轉覺傷離緒，別去應煩說舊因。", "野店無人山月白，明朝尊酒更愁人。"]'),
('a848feca-e2ab-4faf-aa2f-3f5097c13600','次韻酬大光見贈','衛博','宋','宋诗','song-poetry','','[]','十年蹤跡并萍浮，今日行藏謾倚樓。',64,'全唐诗/poet.song.149000.json','["十年蹤跡并萍浮，今日行藏謾倚樓。", "明月相思淮水外，東風吹夢越江頭。", "深深庭院驚春晚，淡淡鶑花稱客愁。", "記取追隨休暇日，殷勤陶謝許同遊。"]'),
('58d2edfa-5fb4-467a-8387-30c29960be1c','次韻謝王使君見贈二首  其一','衛博','宋','宋诗','song-poetry','','[]','西江派別幾經年，聖處騷人總未傳。',64,'全唐诗/poet.song.149000.json','["西江派別幾經年，聖處騷人總未傳。", "遺我驪珠三歎罷，乞君霞佩一翩然。", "自聞流水知音趣，苦厭秋蟲傍耳煎。", "歸去寒光驚蔀屋，明朝紙價溢都廛。"]'),
('8489215e-5613-412d-88da-e5fe9d47c6a0','次韻謝王使君見贈二首  其二','衛博','宋','宋诗','song-poetry','','[]','功成刻楮謾三年，技拙空慚不可傳。',64,'全唐诗/poet.song.149000.json','["功成刻楮謾三年，技拙空慚不可傳。", "晚事韓門稱弟子，終期幕府頌燕然。", "相看霜幹寒猶在，未許蘭膏明自煎。", "祭竈乞隣端有志，只愁多指費囷廛。"]'),
('6a18fcbb-fd04-4c8b-b769-8617c6090acd','次吳國器韻','衛博','宋','宋诗','song-poetry','','[]','平生不作稻粱謀，身世江湖一舸浮。',64,'全唐诗/poet.song.149000.json','["平生不作稻粱謀，身世江湖一舸浮。", "顧我方論天下事，喜君還向古人求。", "塗窮解識知津意，歲晚應甘短褐憂。", "便欲盡携書策賣，東家還許問鄰不。"]'),
('f82ca180-35de-4eeb-b869-6308ad93d1de','次何友直韻','衛博','宋','宋诗','song-poetry','','[]','野棠堤柳固依然，無奈輕寒濕暝烟。',64,'全唐诗/poet.song.149000.json','["野棠堤柳固依然，無奈輕寒濕暝烟。", "鶑語匆匆無意緒，花時寂寂廢詩篇。", "曉來洗出天容靜，空外吹殘雨脚連。", "春色便須同檢校，已隨流水半涓涓。"]'),
('61265bac-937c-4109-8244-c41a9a975804','次韻王大光見贈','衛博','宋','宋诗','song-poetry','','[]','頭角崢嶸冠八龍，相逢宛馬昔從東。',64,'全唐诗/poet.song.149000.json','["頭角崢嶸冠八龍，相逢宛馬昔從東。", "披懷一笑交情重，轉眼三年世事空。", "浪迹偶登君子里，歲寒今見古人風。", "新詩欲報非瓊玖，涉獵由來愧呂蒙。"]'),
('36fcbedf-9ec9-4665-ae6b-a6c4a28e9061','春晴','衛博','宋','宋诗','song-poetry','','[]','柳梢梅子暗春城，深院誰家曲水橫。',64,'全唐诗/poet.song.149000.json','["柳梢梅子暗春城，深院誰家曲水橫。", "海燕未來人鬭草，野鳩相喚雨初晴。", "韶光縱好都來幾，客抱如今作麽生。", "風物不堪頻檢校，曉來花落半階平。"]'),
('2893a849-a829-4f81-98c9-5540e15933d0','次韻春日書懷','衛博','宋','宋诗','song-poetry','','[]','是非無遇不心亨，此道吾猶及老成。',64,'全唐诗/poet.song.149000.json','["是非無遇不心亨，此道吾猶及老成。", "知己相逢須管鮑，傳家各自歎韋平。", "幽居幸有簞瓢樂，高枕從看宇宙清。", "富貴儻來安足計，且應尊酒話平生。"]'),
('82afd055-a859-4925-aadc-ab2379f2c98e','送江南聞祕校','衛博','宋','宋诗','song-poetry','','[]','胸中逸氣凜橫秋，欬唾珠璣落九州。',64,'全唐诗/poet.song.149000.json','["胸中逸氣凜橫秋，欬唾珠璣落九州。", "堪歎羣兒自相貴，如君百戰未封侯。", "相逢不啻平生舊，一笑還從汗漫游。", "好去慇懃護行李，要看鯨海試吳鈎。"]'),
('6a091387-820c-4171-be5c-ad12675534db','過江上','衛博','宋','宋诗','song-poetry','','[]','失脚塵凡不易收，莫思冠佩裹狙猴。',64,'全唐诗/poet.song.149000.json','["失脚塵凡不易收，莫思冠佩裹狙猴。", "但逢司馬心相許，便擬中郎賦遠遊。", "弱水蓬萊三萬里，仙家日月八千秋。", "聞名徑欲茲山穩，不學劉郎世外求。"]'),
('32a39030-3c77-4416-b9b8-f501ac4be7b4','答吳子文','衛博','宋','宋诗','song-poetry','','[]','東游吳苑定何年，猶有佳名處處傳。',64,'全唐诗/poet.song.149000.json','["東游吳苑定何年，猶有佳名處處傳。", "殆過百聞今果爾，相逢一笑兩欣然。", "强藏燕石知君厚，試乞鸞膠爲我煎。", "世上功名端易與，共期雲翼跨芝廛。"]'),
('cf315a15-61a3-472e-80f6-9b8d93984caf','和人雪詩','衛博','宋','宋诗','song-poetry','','[]','白玉樓臺近廣寒，冷侵銀海眩光翻。',64,'全唐诗/poet.song.149000.json','["白玉樓臺近廣寒，冷侵銀海眩光翻。", "只應天上梨花老，聊作人間柳絮繁。", "慶卜有年先一白，喜隨寬令到千門。", "使君浩興憐詩酒，雋飲誰供五石尊。"]'),
('805633a8-d80d-4f98-bb3c-08c3f915d0c7','病中書懷','衛博','宋','宋诗','song-poetry','','[]','平生技拙笑屠龍，去國尤慚易道東。',64,'全唐诗/poet.song.149000.json','["平生技拙笑屠龍，去國尤慚易道東。", "回望飛雲親舍下，不堪伏枕左書空。", "四方未了男兒志，一飯長懷國士風。", "憐我已深兄弟好，願從之子客東蒙。"]'),
('fb9555dd-e683-4f32-a0fb-476c91df3874','書懷  其一','衛博','宋','宋诗','song-poetry','','[]','一劍西來又蒯緱，空餘逸氣凜橫秋。',64,'全唐诗/poet.song.149000.json','["一劍西來又蒯緱，空餘逸氣凜橫秋。", "羈情正類南飛鵲，生事渾隨萬里鷗。", "歲晚已驚霜入屨，夜寒唯有月當樓。", "四方八表男兒志，留滯江干恐白頭。"]'),
('3e69d9eb-b2db-472b-b4ea-1c4e516810dd','書懷  其二','衛博','宋','宋诗','song-poetry','','[]','萬里江山一褐裘，十年蹤跡并萍浮。',64,'全唐诗/poet.song.149000.json','["萬里江山一褐裘，十年蹤跡并萍浮。", "囷禾誰展周郎指，負米長懷季路憂。", "書劍未酬平昔志，水雲空結異鄉愁。", "悠悠萬事書空足，獨立西風自點頭。"]'),
('a50a150c-83a9-4f2a-ab68-2cf47b05e75b','次韻張君倚春郊且速東山之遊','衛博','宋','宋诗','song-poetry','','[]','瀲色嵐光暖更妍，陰晴恰稱養花天。',64,'全唐诗/poet.song.149000.json','["瀲色嵐光暖更妍，陰晴恰稱養花天。", "惱人春事濃於酒，得意莎茵軟勝綿。", "欲把風光供翰墨，直須杖屨躡雲烟。", "知君已作東山興，緩步何辭十里阡。"]'),
('aa83e699-68a9-472d-8a1c-8a1fd2009d81','明日出城愛其平沙淺水有錢塘西湖氣象借前韻呈諸公','衛博','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花紅水綠鬭春妍，長望江南憶樂天。',64,'全唐诗/poet.song.149000.json','["花紅水綠鬭春妍，長望江南憶樂天。", "黄栗留鳴山寂靜，野棠梨發樹蔫綿。", "樓臺三竺將歸路，氣象西湖欲晚烟。", "風物不殊鄉國異，好尋歸馬問長阡。"]'),
('bd4d13f6-823d-49a4-9a72-af01cdc35c0c','春日書懷  其一','衛博','宋','宋诗','song-poetry','','[]','東風吹雨半斜斜，青草池塘憶謝家。',32,'全唐诗/poet.song.149000.json','["東風吹雨半斜斜，青草池塘憶謝家。", "池李山桃謾春色，傷心不見洛城花。"]'),
('acd8bd42-c62f-4304-a7e7-8c0bd9eaeda8','春日書懷  其二','衛博','宋','宋诗','song-poetry','','[]','人世逢春能幾回，區區從使寸心灰。',32,'全唐诗/poet.song.149000.json','["人世逢春能幾回，區區從使寸心灰。", "故園花柳應依舊，萬里歸思獨上來。"]'),
('18ec7900-97f5-417d-b155-58d519324eca','偈頌一百二十三首  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','三人證龜作鱉，有口都不能說。',41,'全唐诗/poet.song.149000.json','["三人證龜作鱉，有口都不能說。", "須彌頂上浪滔滔，大洋海裏遭火爇。", "別別，金色頭陀曾漏泄。"]'),
('19ad992d-e999-44c1-a29e-cb4b82893de6','偈頌一百二十三首  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','春風浩蕩，古佛榜樣。',56,'全唐诗/poet.song.149000.json','["春風浩蕩，古佛榜樣。", "春水潺湲，急著眼看。", "燈籠跳入露柱，佛殿走出三門，撞著箇無面目漢。", "却道衆口難調，須是臨機妙轉。"]'),
('bff433e8-6bc6-4b46-a4ea-b26a19e89309','偈頌一百二十三首  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','有問西來便答東，從教人笑我佯聾。',32,'全唐诗/poet.song.149000.json','["有問西來便答東，從教人笑我佯聾。", "白雲乍可離青嶂，明月難教下碧空。"]'),
('91e5fae4-ca01-4612-b933-aa4064e860ab','偈頌一百二十三首  其四','釋崇嶽','宋','宋诗','song-poetry','','[]','萬般施設不如常，又不驚人又久長。',28,'全唐诗/poet.song.149000.json','["萬般施設不如常，又不驚人又久長。", "誰知遠煙浪，別有好思量。"]'),
('96a968fa-7029-44a9-8a5a-f2dd3698e6e2','偈頌一百二十三首  其五','釋崇嶽','宋','宋诗','song-poetry','','[]','太虛挂劍全生殺，星馳電卷煙雲豁。',32,'全唐诗/poet.song.149000.json','["太虛挂劍全生殺，星馳電卷煙雲豁。", "可中誰是出頭人，長嘯一聲天地闊。"]'),
('19bde5db-8f9e-48eb-b891-328fcec86286','偈頌一百二十三首  其六','釋崇嶽','宋','宋诗','song-poetry','','[]','彌勒真彌勒，分身千百億。',24,'全唐诗/poet.song.149000.json','["彌勒真彌勒，分身千百億。", "時時示時人，時人皆不識。"]'),
('51f730d9-4f13-417a-8789-36092b782ff1','偈頌一百二十三首  其七','釋崇嶽','宋','宋诗','song-poetry','','[]','有利無利，不離行市，張公喫酒李公醉。',68,'全唐诗/poet.song.149000.json','["有利無利，不離行市，張公喫酒李公醉。", "伸脚打睡有來由，纔放醒醒成忌諱。", "非不非，是不是。", "遇貴即賤，遇賤即貴。", "狸奴白牯念摩訶，祖師不會西來意。"]'),
('54c39f7c-dcc2-4763-b729-c5ff858fb210','偈頌一百二十三首  其八','釋崇嶽','宋','宋诗','song-poetry','','[]','月旦曰朔，月圓曰望。',64,'全唐诗/poet.song.149000.json','["月旦曰朔，月圓曰望。", "八字打開，有收有放。", "薩怛阿竭，二千年前。", "摩醯首羅，頂門正眼。", "覿面提持，生鐵門限。", "俊底撩起便行，漆桶一任擔板。"]'),
('740dc0e8-d31c-40b5-9fb5-9717dfac1eca','偈頌一百二十三首  其九','釋崇嶽','宋','宋诗','song-poetry','','[]','一不成，二不是，突出眼睛失却鼻。',32,'全唐诗/poet.song.149000.json','["一不成，二不是，突出眼睛失却鼻。", "少林剛自覓安心，瞎馿不受靈山記。"]'),
('4d71b05e-1b2c-4742-b0dd-f08ba8774d62','偈頌一百二十三首  其一○','釋崇嶽','宋','宋诗','song-poetry','','[]','千年田，八百主，郎當屋舍沒人修，不風流處也風流。',24,'全唐诗/poet.song.149000.json','["千年田，八百主，郎當屋舍沒人修，不風流處也風流。"]'),
('3f343e2b-b14a-4fa0-8ba8-0532d0131149','偈頌一百二十三首  其一一','釋崇嶽','宋','宋诗','song-poetry','','[]','生平活計一絲頭，嘯月迎風得自由。',32,'全唐诗/poet.song.149000.json','["生平活計一絲頭，嘯月迎風得自由。", "管甚澄江興逆浪，等閑平步過滄洲。"]'),
('a7ce4930-0410-4fd3-a3af-75206fd17093','偈頌一百二十三首  其一二','釋崇嶽','宋','宋诗','song-poetry','','[]','妙用縱橫，十方坐斷。',20,'全唐诗/poet.song.149000.json','["妙用縱橫，十方坐斷。", "未諳此脈，舉步猶難。"]'),
('3bef3d77-e485-47d2-8e8e-79b1ae937c7d','偈頌一百二十三首  其一三','釋崇嶽','宋','宋诗','song-poetry','','[]','冶父方丈，了無遮障。',36,'全唐诗/poet.song.149000.json','["冶父方丈，了無遮障。", "拳踢相應，當人不讓。", "妙轉綿綿一脈通，誰知滅却臨濟宗。"]'),
('3d195e2b-fab5-4212-a117-0ed49d2daf60','偈頌一百二十三首  其一四','釋崇嶽','宋','宋诗','song-poetry','','[]','冶父門風，別無道理。',32,'全唐诗/poet.song.149000.json','["冶父門風，別無道理。", "家田米飯，早眠晏起。", "洗面摸著鼻，啜茶滋却嘴。"]'),
('255e1f6b-2a63-4bb1-a90a-a41ff5969ca1','偈頌一百二十三首  其一五','釋崇嶽','宋','宋诗','song-poetry','','[]','冶父山門齋粥粗，文章佛法一時無。',32,'全唐诗/poet.song.149000.json','["冶父山門齋粥粗，文章佛法一時無。", "地爐些子無煙火，且與禪人樂有餘。"]'),
('b5173478-246b-402e-a54e-75e744b5125f','偈頌一百二十三首  其一六','釋崇嶽','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',20,'全唐诗/poet.song.149000.json','["晷運推移，日南長至。", "上下四維，慶無不利。"]'),
('d0372d08-ddec-4a82-ad6a-8dfe29491977','偈頌一百二十三首  其一七','釋崇嶽','宋','宋诗','song-poetry','','[]','雪雪，明明漏泄。',50,'全唐诗/poet.song.149000.json','["雪雪，明明漏泄。", "枯木開花，虛空迸裂。", "無位真人徹骨寒，燈籠露柱眉毛結。", "忽然晴，沒可說，齊賀豐年好時節。"]'),
('617c63d9-55eb-4e52-9c1b-cb884a8facf5','偈頌一百二十三首  其一八','釋崇嶽','宋','宋诗','song-poetry','','[]','元正改旦，事事成現。',66,'全唐诗/poet.song.149000.json','["元正改旦，事事成現。", "有時放行，有時坐斷。", "不惜兩莖眉，和坐盤掇轉。", "佛法世法，都盧一片。", "既是佛法世法，如何得成一片。", "但辨肯心，必不相賺。"]'),
('87c73b24-bab4-4010-9232-ec0e8a640631','偈頌一百二十三首  其一九','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝結制，叢林體例。',36,'全唐诗/poet.song.149000.json','["今朝結制，叢林體例。", "長期短期，似兀如癡。", "離四句，絕百非，大家相聚喫莖虀。"]'),
('48c1fdc0-2d5d-4ea5-bcb9-95b0dde4f1d7','偈頌一百二十三首  其二○','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝五月端午節，衲僧門下無一說。',32,'全唐诗/poet.song.149000.json','["今朝五月端午節，衲僧門下無一說。", "千妖百怪自潛蹤，萬里長天一條鐵。"]'),
('26ff9162-90ed-4ff3-b749-dc3949f4cb20','偈頌一百二十三首  其二一','釋崇嶽','宋','宋诗','song-poetry','','[]','江月照，松風吹，永夜清霄何所爲。',32,'全唐诗/poet.song.149000.json','["江月照，松風吹，永夜清霄何所爲。", "無孔笛吹雲外曲，相逢知我者還稀。"]'),
('6f224627-9503-4979-96bb-1e4b043b7de9','偈頌一百二十三首  其二二','釋崇嶽','宋','宋诗','song-poetry','','[]','十五已前取不得，十五已後捨不得。',40,'全唐诗/poet.song.149000.json','["十五已前取不得，十五已後捨不得。", "正當十五日，築著磕著七花八裂，明眼衲僧只得一橛。"]'),
('a6246ce6-7582-434b-85fa-d4ebe2f1251d','偈頌一百二十三首  其二三','釋崇嶽','宋','宋诗','song-poetry','','[]','入得冶父門，不避冶父劍。',48,'全唐诗/poet.song.149000.json','["入得冶父門，不避冶父劍。", "劍下驀翻身，爲君通一線。", "喫底劈胸拳，透底生鐵面。", "莫怪粗糲藜，方便沒方便。"]'),
('9fd81abd-5c65-417a-97a9-c11bd2377b34','偈頌一百二十三首  其二四','釋崇嶽','宋','宋诗','song-poetry','','[]','秋光清淺時，白露和煙島。',36,'全唐诗/poet.song.149000.json','["秋光清淺時，白露和煙島。", "良哉觀世音，全身入荒草。", "一鏃破三關，低頭何處討。"]'),
('9bce93b1-021e-44b2-ae7e-2c4fb96418a2','偈頌一百二十三首  其二五','釋崇嶽','宋','宋诗','song-poetry','','[]','日可冷，月可熱，衆魔不能壞真說。',32,'全唐诗/poet.song.149000.json','["日可冷，月可熱，衆魔不能壞真說。", "且道如何是真說，鉢盂一日兩度濕。"]'),
('8278c2b0-e60c-428e-ae00-bcdae4f70259','偈頌一百二十三首  其二六','釋崇嶽','宋','宋诗','song-poetry','','[]','冶父生來百拙，開口都無一說。',28,'全唐诗/poet.song.149000.json','["冶父生來百拙，開口都無一說。", "今朝指空畫空，笑倒清風明月。"]'),
('006d7d16-510d-431e-9529-7f35dde769d0','偈頌一百二十三首  其二七','釋崇嶽','宋','宋诗','song-poetry','','[]','一方一所，叢林保社。',42,'全唐诗/poet.song.149000.json','["一方一所，叢林保社。", "或廢或興，截鐵斬釘。", "推倒嘉州大像，扶起迦葉師兄，管取曹源一派清。"]'),
('591826a9-0fac-4e5e-979e-38dacf592001','偈頌一百二十三首  其二八','釋崇嶽','宋','宋诗','song-poetry','','[]','當陽顯赫，神龍妙訣。',20,'全唐诗/poet.song.149000.json','["當陽顯赫，神龍妙訣。", "倒嶽傾湫，雷轟電掣。"]'),
('5f1777b4-75f3-4d69-a3db-02508f1afef6','偈頌一百二十三首  其二九','釋崇嶽','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',28,'全唐诗/poet.song.149000.json','["有句無句，如藤倚樹。", "築著磕著，了無回互，八臂那吒留不住。"]'),
('a83c68c6-a476-4306-a236-39aa81c15e08','偈頌一百二十三首  其三○','釋崇嶽','宋','宋诗','song-poetry','','[]','只箇長行粥飯僧，江南江北震乾坤。',32,'全唐诗/poet.song.149000.json','["只箇長行粥飯僧，江南江北震乾坤。", "而今又却隨他去，討甚楊岐八世孫。"]'),
('20043077-4a1d-4228-9436-e1cdd188b3ea','偈頌一百二十三首  其三一','釋崇嶽','宋','宋诗','song-poetry','','[]','入門正路，不容回互。',20,'全唐诗/poet.song.149000.json','["入門正路，不容回互。", "千人萬人，當陽蹉過。"]'),
('78797571-b1da-4597-9e42-eb225f681a47','偈頌一百二十三首  其三二','釋崇嶽','宋','宋诗','song-poetry','','[]','要行便行，要坐便坐。',20,'全唐诗/poet.song.149000.json','["要行便行，要坐便坐。", "自古自今，只是這箇。"]'),
('827325c4-4e31-4b4d-a0ff-b2487f5ac9e6','偈頌一百二十三首  其三三','釋崇嶽','宋','宋诗','song-poetry','','[]','一著高一著，一步闊一步。',24,'全唐诗/poet.song.149000.json','["一著高一著，一步闊一步。", "坐斷佛祖關，迷却來時路。"]'),
('e519ee1b-72b3-46a3-b75a-3505f9211892','偈頌一百二十三首  其三四','釋崇嶽','宋','宋诗','song-poetry','','[]','十五日已前取不得，十五日已後捨不得。',48,'全唐诗/poet.song.149000.json','["十五日已前取不得，十五日已後捨不得。", "正當十五日，取即是，捨即是。", "問汝問余都不會，可憐只解那斯祁。"]'),
('b49aaa11-7ae5-4b35-a72f-40ffaa6627a8','偈頌一百二十三首  其三五','釋崇嶽','宋','宋诗','song-poetry','','[]','薦福住院，事事成現。',40,'全唐诗/poet.song.149000.json','["薦福住院，事事成現。", "露柱燈籠，三門佛殿。", "若上若下，和光同塵。", "有時又却，神頭鬼面。"]'),
('6982e775-33ff-42af-b011-3ce57b70ffbb','偈頌一百二十三首  其三六','釋崇嶽','宋','宋诗','song-poetry','','[]','衲僧一拶，鉢盂口闊。',20,'全唐诗/poet.song.149000.json','["衲僧一拶，鉢盂口闊。", "天下楊岐，望林止渴。"]'),
('ab4ca548-0fd5-4762-b071-9980bc07960c','偈頌一百二十三首  其三七','釋崇嶽','宋','宋诗','song-poetry','','[]','元正改旦，來千去萬。',36,'全唐诗/poet.song.149000.json','["元正改旦，來千去萬。", "物物咸新，眼上生塵。", "拶破多年桃核裏，分明只是舊時人。"]'),
('b8b52f47-cb4c-4b9c-9d1f-5e9137c8bf72','偈頌一百二十三首  其三八','釋崇嶽','宋','宋诗','song-poetry','','[]','張弓架箭魚游網，物外安身鳥入籠。',32,'全唐诗/poet.song.149000.json','["張弓架箭魚游網，物外安身鳥入籠。", "生殺盡時蠶作繭，如何透得這三重。"]'),
('26dae350-cc84-4da4-81ee-caf633521b6f','偈頌一百二十三首  其三九','釋崇嶽','宋','宋诗','song-poetry','','[]','達磨九年面壁，二祖立雪齊腰。',28,'全唐诗/poet.song.149000.json','["達磨九年面壁，二祖立雪齊腰。", "三人證龜成鱉，一塊頑銅鈍鐵。"]'),
('6d7354ab-d37b-4621-a7c5-69997012b923','偈頌一百二十三首  其四○','釋崇嶽','宋','宋诗','song-poetry','','[]','殺人刀，活人劍。',28,'全唐诗/poet.song.149000.json','["殺人刀，活人劍。", "那吒眼睛，金剛正焰。", "咬定牙關，赤心片片。"]'),
('f996ed50-1148-420e-94cc-33703812647f','偈頌一百二十三首  其四一','釋崇嶽','宋','宋诗','song-poetry','','[]','有解有結，虛空釘橛。',45,'全唐诗/poet.song.149000.json','["有解有結，虛空釘橛。", "無解無結，咬著生鐵。", "二千年代錯流傳，天下衲僧無處雪。", "雪不雪，崖崩石裂。"]'),
('6982b2b4-e930-4d81-86c3-8ccd09c9d622','偈頌一百二十三首  其四二','釋崇嶽','宋','宋诗','song-poetry','','[]','莫莫，大海乾枯，須彌倒卓。',31,'全唐诗/poet.song.149000.json','["莫莫，大海乾枯，須彌倒卓。", "逆行順行，將錯就錯，明眼衲僧休卜度。"]'),
('faea97d5-6bb1-46c9-9b66-344ef961850e','偈頌一百二十三首  其四三','釋崇嶽','宋','宋诗','song-poetry','','[]','分明月上長珊瑚，一段風光爍太虛。',32,'全唐诗/poet.song.149000.json','["分明月上長珊瑚，一段風光爍太虛。", "大地衆生同受用，如來藏裏本來無。"]'),
('12c24c18-9b14-4077-882d-449c2f62a694','偈頌一百二十三首  其四四','釋崇嶽','宋','宋诗','song-poetry','','[]','哭不徹，笑不徹，倒腹傾腸向君說。',32,'全唐诗/poet.song.149000.json','["哭不徹，笑不徹，倒腹傾腸向君說。", "父子非親知不知，擡頭腦後三斤鐵。"]'),
('27657eeb-eb4b-4e5f-8ecb-1b22ed7357b5','偈頌一百二十三首  其四五','釋崇嶽','宋','宋诗','song-poetry','','[]','海上爭馳老柏庭，生憎佛祖長無明。',32,'全唐诗/poet.song.149000.json','["海上爭馳老柏庭，生憎佛祖長無明。", "驀然打箇翻身轉，依舊龍門一派清。"]'),
('7b15ee5d-502d-4ad9-8b4f-13526aaed188','偈頌一百二十三首  其四六','釋崇嶽','宋','宋诗','song-poetry','','[]','仰面不見天，低頭不見地。',24,'全唐诗/poet.song.149000.json','["仰面不見天，低頭不見地。", "喫飯了噇眠，聖諦第一義。"]'),
('dde19f7a-068a-43fc-8dda-c8cd00e57308','偈頌一百二十三首  其四七','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝正月半，舉箇舊公案。',50,'全唐诗/poet.song.149000.json','["今朝正月半，舉箇舊公案。", "一燈百千燈，千人萬人看。", "百草頭邊，威音那畔。", "相逢若是箇中人，終不隨他光影轉。"]'),
('d80b6b58-2a03-4a62-96b1-c659362826ff','偈頌一百二十三首  其四八','釋崇嶽','宋','宋诗','song-poetry','','[]','萬戶千門到者稀，一挨一拶在臨時。',32,'全唐诗/poet.song.149000.json','["萬戶千門到者稀，一挨一拶在臨時。", "威音那畔真消息，不是知音莫與知。"]'),
('cf2d68cc-3911-4e85-9a49-b7b41c1bfb9f','偈頌一百二十三首  其四九','釋崇嶽','宋','宋诗','song-poetry','','[]','薦福少方便，拳頭如掣電。',32,'全唐诗/poet.song.149000.json','["薦福少方便，拳頭如掣電。", "千眼無摸索，千耳不可見，家家門首透長安。"]'),
('e29bf20f-5565-4053-8129-8a73ace1ec05','偈頌一百二十三首  其五○','釋崇嶽','宋','宋诗','song-poetry','','[]','威音那畔真消息，累及瞿曇老祖翁。',32,'全唐诗/poet.song.149000.json','["威音那畔真消息，累及瞿曇老祖翁。", "四十九年顛倒說，人間天上謾流通。"]'),
('5b693303-f4af-42cc-862f-e7719e2f2bfb','偈頌一百二十三首  其五一','釋崇嶽','宋','宋诗','song-poetry','','[]','五月端午，薦福直舉不會，諸方書符呪土。',35,'全唐诗/poet.song.149000.json','["五月端午，薦福直舉不會，諸方書符呪土。", "風從虎兮雲從龍，千妖百怪自潛蹤。"]'),
('6ab0d396-2046-451b-b90e-a229ddec18db','偈頌一百二十三首  其五二','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝九月二十，莫怪光陰電急。',36,'全唐诗/poet.song.149000.json','["今朝九月二十，莫怪光陰電急。", "游人南北憧憧，不識自家城邑。", "眨上眉毛從此入。"]'),
('1eae65ec-0aba-45ee-be10-8c8afe37578b','偈頌一百二十三首  其五三','釋崇嶽','宋','宋诗','song-poetry','','[]','十方同聚會，箇箇學無爲。',24,'全唐诗/poet.song.149000.json','["十方同聚會，箇箇學無爲。", "此是選佛場，心空及第歸。"]'),
('c063c436-cb45-4704-a410-a7d7d057b442','偈頌一百二十三首  其五四','釋崇嶽','宋','宋诗','song-poetry','','[]','春風似箭，春雨如膏。',20,'全唐诗/poet.song.149000.json','["春風似箭，春雨如膏。", "曠劫來事，不隔絲毫。"]'),
('eaffa629-eabb-4ac7-a4a8-e006c835385c','偈頌一百二十三首  其五五','釋崇嶽','宋','宋诗','song-poetry','','[]','行亦禪，坐亦禪，語默動靜體安然。',32,'全唐诗/poet.song.149000.json','["行亦禪，坐亦禪，語默動靜體安然。", "匝地普天收不得，都來不直半分錢。"]'),
('9cba66dc-f8ff-4be9-b616-5e49c2cccc71','偈頌一百二十三首  其五六','釋崇嶽','宋','宋诗','song-poetry','','[]','石鞏張弓，魯祖面壁。',20,'全唐诗/poet.song.149000.json','["石鞏張弓，魯祖面壁。", "正令不行，拗曲作直。"]'),
('0fc9a785-2f30-40b6-bdc2-8f6aa272fce0','偈頌一百二十三首  其五七','釋崇嶽','宋','宋诗','song-poetry','','[]','欲得現前，莫存順逆。',25,'全唐诗/poet.song.149000.json','["欲得現前，莫存順逆。", "祖師來也還見麽，切忌扶籬摸壁。"]'),
('58b1e986-430b-42dc-863a-5b30e9db79b3','偈頌一百二十三首  其五八','釋崇嶽','宋','宋诗','song-poetry','','[]','空手把鋤頭，蚊子上鐵牛。',48,'全唐诗/poet.song.149000.json','["空手把鋤頭，蚊子上鐵牛。", "步行騎水牛，黄河水逆流。", "人從橋上過，猛虎當路坐。", "橋流水不流，佛祖是仇讎。"]'),
('9d1e7cd3-0063-461c-8c5f-accae97e5f94','偈頌一百二十三首  其五九','釋崇嶽','宋','宋诗','song-poetry','','[]','五年於此謾隨緣，去住無心自坦然。',32,'全唐诗/poet.song.149000.json','["五年於此謾隨緣，去住無心自坦然。", "六月霏霏飄瑞雪，須知別是一壺天。"]'),
('45446a55-2b57-4e4e-a309-a3cf1e65b8c6','偈頌一百二十三首  其六○','釋崇嶽','宋','宋诗','song-poetry','','[]','有時堆堆坐禪，有時一向打閧。',52,'全唐诗/poet.song.149000.json','["有時堆堆坐禪，有時一向打閧。", "年來行脚衲僧，都是箇般病痛。", "報君知，休打閧。", "入門拚却箇渾身，頭頭自有生蛇弄。"]'),
('495383a1-b587-4311-b21a-106f300228c9','偈頌一百二十三首  其六一','釋崇嶽','宋','宋诗','song-poetry','','[]','五祖老人好語，只爲探頭太過。',52,'全唐诗/poet.song.149000.json','["五祖老人好語，只爲探頭太過。", "香山有箇方便，也要諸人共知。", "透得金剛圈，細嚼鐵餕餡。", "一飽忘百饑，始信不相賺。"]'),
('a3b09552-541a-4402-846d-d14528ac524b','偈頌一百二十三首  其六二','釋崇嶽','宋','宋诗','song-poetry','','[]','年去年來貧復貧，祖師擡脚重千斤。',32,'全唐诗/poet.song.149000.json','["年去年來貧復貧，祖師擡脚重千斤。", "愁人莫向愁人說，說向愁人愁殺人。"]'),
('b5d636e0-2441-46dd-8f50-c7016e09567e','偈頌一百二十三首  其六三','釋崇嶽','宋','宋诗','song-poetry','','[]','鐵山崩倒壓銀山，盤走珠兮珠走盤。',32,'全唐诗/poet.song.149000.json','["鐵山崩倒壓銀山，盤走珠兮珠走盤。", "密把鴛鴦閑繡出，金針終不與人看。"]'),
('14c35dfa-a958-45de-8f0e-a5d16c45b438','偈頌一百二十三首  其六四','釋崇嶽','宋','宋诗','song-poetry','','[]','半雨半晴，桃紅李白。',20,'全唐诗/poet.song.149000.json','["半雨半晴，桃紅李白。", "點著便行，不勞啗啄。"]'),
('1c13ad4a-4fba-4f0e-96a3-9d1f24ff776d','偈頌一百二十三首  其六五','釋崇嶽','宋','宋诗','song-poetry','','[]','青天白日，悟箇什麽。',22,'全唐诗/poet.song.149000.json','["青天白日，悟箇什麽。", "咄咄咄，驪珠擊碎蒼龍窟。"]'),
('5e1854de-b16f-4c4b-b459-4085440f15f4','偈頌一百二十三首  其六六','釋崇嶽','宋','宋诗','song-poetry','','[]','第七箇沒尾巴，不落羣隊獨露爪牙。',32,'全唐诗/poet.song.149000.json','["第七箇沒尾巴，不落羣隊獨露爪牙。", "擬心湊泊終難見，須信蓮開火裏花。"]'),
('4a7516b3-34f0-4eac-9189-2b6130da55c6','偈頌一百二十三首  其六七','釋崇嶽','宋','宋诗','song-poetry','','[]','靜處閙浩浩，閙中靜悄悄。',44,'全唐诗/poet.song.149000.json','["靜處閙浩浩，閙中靜悄悄。", "鐘動月黄昏，雞鳴五更早。", "拄杖子，却懊惱，可惜好光陰，等閑空過了。"]'),
('02cb6946-a976-4543-a93e-8274995b4e11','偈頌一百二十三首  其六八','釋崇嶽','宋','宋诗','song-poetry','','[]','坐斷毗盧頂，超然亙古今。',24,'全唐诗/poet.song.149000.json','["坐斷毗盧頂，超然亙古今。", "萬緣俱剔脫，一片祖師心。"]'),
('62dbe5d3-4bee-4b63-9e1b-7f7f97a2e852','偈頌一百二十三首  其六九','釋崇嶽','宋','宋诗','song-poetry','','[]','入門一句，賓主歷然。',28,'全唐诗/poet.song.149000.json','["入門一句，賓主歷然。", "不勞彈指，天寬地寬。", "壺中消息異人間。"]'),
('13c2e73f-da2b-494d-9ee5-5a87a60f9b14','偈頌一百二十三首  其七○','釋崇嶽','宋','宋诗','song-poetry','','[]','一著高一著，一步闊一步。',30,'全唐诗/poet.song.149000.json','["一著高一著，一步闊一步。", "明眼人前，猶涉路布。", "鳳棲不在梧桐樹。"]'),
('0eb7de13-73fb-417a-820c-2bc1744f4d09','偈頌一百二十三首  其七一','釋崇嶽','宋','宋诗','song-poetry','','[]','佛眼覷不得，祖師提不起。',38,'全唐诗/poet.song.149000.json','["佛眼覷不得，祖師提不起。", "石裂崖崩，掀翻到底。", "不風流處更風流，也是波斯入閙市。"]'),
('66b30820-2789-49e1-989d-6bb87e82f993','偈頌一百二十三首  其七二','釋崇嶽','宋','宋诗','song-poetry','','[]','恁麽恁麽，牽犁拽杷。',35,'全唐诗/poet.song.149000.json','["恁麽恁麽，牽犁拽杷。", "不恁麽不恁麽，泥多佛大。", "臨濟三玄，趙州勘破鼻孔大。"]'),
('6269077e-5af2-433d-8375-002b72d41711','偈頌一百二十三首  其七三','釋崇嶽','宋','宋诗','song-poetry','','[]','欲得大用現前，直下頓忘知見。',29,'全唐诗/poet.song.149000.json','["欲得大用現前，直下頓忘知見。", "諸見若盡，昏霧不生，大智洞然。"]'),
('7fae5e18-caf8-482f-b152-aac3fce9d8eb','偈頌一百二十三首  其七四','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝九月初一，祝聖陞堂已畢。',28,'全唐诗/poet.song.149000.json','["今朝九月初一，祝聖陞堂已畢。", "若是達磨兒孫，瞥轉雲門念七。"]'),
('5acc2843-ebc5-4828-a416-34119c02ccb7','偈頌一百二十三首  其七五','釋崇嶽','宋','宋诗','song-poetry','','[]','諸方如法開爐，虎丘家風淡泊。',44,'全唐诗/poet.song.149000.json','["諸方如法開爐，虎丘家風淡泊。", "拈出箇鐵餕餡，箇裏寧容啗啄。", "休啗啄，丹霞燒木佛，院主眉鬚落。"]'),
('eed42cc0-66e5-4d42-89cb-b2dab4a1ab8d','偈頌一百二十三首  其七六','釋崇嶽','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','一人打氈拍板，一人吹無孔笛。',40,'全唐诗/poet.song.149000.json','["一人打氈拍板，一人吹無孔笛。", "梵音清雅，令人樂聞。", "且道是什麽曲調，洞庭山脚太湖心。"]'),
('7813d589-8290-426c-8a27-2c0c20e4fd8d','偈頌一百二十三首  其七七','釋崇嶽','宋','宋诗','song-poetry','','[]','年去實不去，年來實不來。',24,'全唐诗/poet.song.149000.json','["年去實不去，年來實不來。", "山僧都不會，露柱笑咍咍。"]'),
('1e9b0c7d-48a0-4f32-a3b2-db7330df357d','偈頌一百二十三首  其七八','釋崇嶽','宋','宋诗','song-poetry','','[]','深聞淺悟，三更問路。',40,'全唐诗/poet.song.149000.json','["深聞淺悟，三更問路。", "深悟淺聞，痛處遭針。", "胡盧子，放教沉。", "莫將閑學解，埋沒祖師心。"]'),
('f0c2ff63-8e0b-4fe7-b53f-b38983070794','偈頌一百二十三首  其七九','釋崇嶽','宋','宋诗','song-poetry','','[]','總是掩耳偷鈴，殊不知甘贄有收有放，首座徹底惺惺。',40,'全唐诗/poet.song.149000.json','["總是掩耳偷鈴，殊不知甘贄有收有放，首座徹底惺惺。", "雲收雨霽長空闊，一對鴛鴦畫不成。"]'),
('3f30e1d6-4350-49d4-bc15-75c73634afb3','偈頌一百二十三首  其八○','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝五月五，粗言及細語。',24,'全唐诗/poet.song.149000.json','["今朝五月五，粗言及細語。", "會得也尋常，不會超佛祖。"]'),
('9ed4aedf-f366-4615-a1c2-d047db6f0ca5','偈頌一百二十三首  其八一','釋崇嶽','宋','宋诗','song-poetry','','[]','去却一，拈却七，佛祖玄關元不識。',48,'全唐诗/poet.song.149000.json','["去却一，拈却七，佛祖玄關元不識。", "百尺竿頭掉臂行，笑指西方日頭出。", "透金圈，吞栗棘，明眼衲僧沒氣息。"]'),
('3989c10b-ec57-41b5-a83c-1dd3d3d1f227','偈頌一百二十三首  其八二','釋崇嶽','宋','宋诗','song-poetry','','[]','靈源洞徹，真照無邊。',48,'全唐诗/poet.song.149000.json','["靈源洞徹，真照無邊。", "萬機旋復，十方目前。", "聖中聖，天中天，最尊貴，復何言。", "文明齊北極，睿算等南山。"]'),
('5f497632-51ae-438e-a7ef-59401e3ce117','偈頌一百二十三首  其八三','釋崇嶽','宋','宋诗','song-poetry','','[]','懷州牛喫禾，益州馬腹脹。',40,'全唐诗/poet.song.149000.json','["懷州牛喫禾，益州馬腹脹。", "天下覓醫人，灸豬左膊上。", "也好笑，也堪悲，耳垛元來兩片皮。"]'),
('bfc40d8e-9ddf-44f7-b6de-a5e2327562a5','偈頌一百二十三首  其八四','釋崇嶽','宋','宋诗','song-poetry','','[]','十月瑞慶節，真人降中天。',40,'全唐诗/poet.song.149000.json','["十月瑞慶節，真人降中天。", "萬國葵藿心，虔祝一爐煙。", "龍圖鳳曆等乾坤，睿算彌隆億萬年。"]'),
('7ee5aa32-d95a-4c28-9c47-db03fdce1bb5','偈頌一百二十三首  其八五','釋崇嶽','宋','宋诗','song-poetry','','[]','一不做，二不休，賓主互換有來由。',32,'全唐诗/poet.song.149000.json','["一不做，二不休，賓主互換有來由。", "焦磚打著連底凍，赤眼撞著火柴頭。"]'),
('3eb8ca7f-fe44-452e-aa5f-1cc60512df34','偈頌一百二十三首  其八六','釋崇嶽','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',25,'全唐诗/poet.song.149000.json','["有句無句，如藤倚樹。", "孟八郎漢，便恁麽去。", "蘇嚕蘇嚕。"]'),
('52e3fb6f-6760-493b-9730-1e60c4d03714','偈頌一百二十三首  其八七','釋崇嶽','宋','宋诗','song-poetry','','[]','是即全是，非即全非。',28,'全唐诗/poet.song.149000.json','["是即全是，非即全非。", "大用現前，携手同歸，不知猶自涉離微。"]'),
('98d1a0fe-47c5-45f0-98d4-390cef3b1021','偈頌一百二十三首  其八八','釋崇嶽','宋','宋诗','song-poetry','','[]','打睡坐禪，坐禪打睡。',36,'全唐诗/poet.song.149000.json','["打睡坐禪，坐禪打睡。", "有利無利，不離行市。", "老黄檗，太憨癡，深耕淺種少人知。"]'),
('cfc9c6bc-6f07-4669-871a-c131290e633e','偈頌一百二十三首  其八九','釋崇嶽','宋','宋诗','song-poetry','','[]','世尊三昧，文殊三昧，總在拂子頭上。',29,'全唐诗/poet.song.149000.json','["世尊三昧，文殊三昧，總在拂子頭上。", "卧龍纔奮迅，丹鳳便翺翔。"]'),
('6ee8eab8-7935-4786-a780-5776ad9b012f','偈頌一百二十三首  其九○','釋崇嶽','宋','宋诗','song-poetry','','[]','百丈耳聾，黄檗吐舌。',36,'全唐诗/poet.song.149000.json','["百丈耳聾，黄檗吐舌。", "後代兒孫，半生半滅。", "破沙盆，曾漏泄，炎天六月飄霜雪。"]'),
('60168841-d8db-4b26-9b12-8f9365a20808','偈頌一百二十三首  其九一','釋崇嶽','宋','宋诗','song-poetry','','[]','傾盡寶山寶，全身入荒草。',24,'全唐诗/poet.song.149000.json','["傾盡寶山寶，全身入荒草。", "若是鳳凰兒，不向那邊討。"]'),
('22c69458-a279-4a8c-a47b-244be7a7b964','偈頌一百二十三首  其九二','釋崇嶽','宋','宋诗','song-poetry','','[]','萬法是心光，諸緣惟性曉。',24,'全唐诗/poet.song.149000.json','["萬法是心光，諸緣惟性曉。", "本無迷悟人，只要今日了。"]'),
('2efae49d-8b0f-40d7-90f3-a89043c2b7ff','偈頌一百二十三首  其九三','釋崇嶽','宋','宋诗','song-poetry','','[]','靈隠開爐，火種全無。',36,'全唐诗/poet.song.149000.json','["靈隠開爐，火種全無。", "將無作有，孰辨精粗。", "擬議烏藤劈脊摟，從教箇箇嘴盧都。"]'),
('1b35c2d0-4c7c-4b42-91ad-6759a36f6afb','偈頌一百二十三首  其九四','釋崇嶽','宋','宋诗','song-poetry','','[]','東過西西過東，主中賓賓中主。',36,'全唐诗/poet.song.149000.json','["東過西西過東，主中賓賓中主。", "大地全收，千差一舉。", "打鼓普請看，通身是泥土。"]'),
('78c3595e-1184-4b9c-b0c2-98a7eb80e7d0','偈頌一百二十三首  其九五','釋崇嶽','宋','宋诗','song-poetry','','[]','仰面不見天，低頭不見地。',36,'全唐诗/poet.song.149000.json','["仰面不見天，低頭不見地。", "眉毛在眼上，鼻孔裏出氣。", "易分雪裏粉，難辨墨中煤。"]'),
('6c9de24d-7929-48a2-9286-f5e2a574302f','偈頌一百二十三首  其九六','釋崇嶽','宋','宋诗','song-poetry','','[]','今朝十五，陞堂直舉。',40,'全唐诗/poet.song.149000.json','["今朝十五，陞堂直舉。", "全主全賓，燈籠露柱。", "不是佛，不是祖。", "剔起兩莖眉，三更日卓午。"]'),
('3e93698f-dac4-42e8-873f-66b15fa96842','偈頌一百二十三首  其九七','釋崇嶽','宋','宋诗','song-poetry','','[]','年年此日潑惡水，箇事從悉達多起。',32,'全唐诗/poet.song.149000.json','["年年此日潑惡水，箇事從悉達多起。", "自云遍界獨稱尊，後代兒孫誰管你。"]'),
('fd451dec-1113-45fd-8204-a44e656c51fc','偈頌一百二十三首  其九八','釋崇嶽','宋','宋诗','song-poetry','','[]','忽雨忽晴，天平地平。',20,'全唐诗/poet.song.149000.json','["忽雨忽晴，天平地平。", "釋迦彌勒，打失眼睛。"]'),
('375ab1ac-48ad-4d8e-8dbe-5724754ebb46','偈頌一百二十三首  其九九','釋崇嶽','宋','宋诗','song-poetry','','[]','借手行拳，驚羣動衆。',30,'全唐诗/poet.song.149000.json','["借手行拳，驚羣動衆。", "龍門上客，未舉先知。", "若不然者，靈隠失利。"]'),
('24d611a0-2db1-4336-a87a-cac508dc1eff','偈頌一百二十三首  其一○○','釋崇嶽','宋','宋诗','song-poetry','','[]','大人具大見，大智得大用。',52,'全唐诗/poet.song.149000.json','["大人具大見，大智得大用。", "一舉定千差，百發而百中。", "密贊中興業，了無毫末共。", "福如滄海壽如山，赫赫聲名繼前踵。"]'),
('20b49614-cd82-422a-90ef-33e5dc557e28','偈頌一百二十三首  其一○一','釋崇嶽','宋','宋诗','song-poetry','','[]','青天復青天，打失髑髏前。',24,'全唐诗/poet.song.149000.json','["青天復青天，打失髑髏前。", "看看日又過，爭教人少年。"]'),
('765bf3cd-8182-4cff-9952-ce0140aada85','偈頌一百二十三首  其一○二','釋崇嶽','宋','宋诗','song-poetry','','[]','道人相見，如如不變。',32,'全唐诗/poet.song.149000.json','["道人相見，如如不變。", "同氣連枝，略通一線。", "笑揖飛來峰，大家看佛面。"]'),
('8cf0887d-2609-49fe-b282-a80348d918e8','偈頌一百二十三首  其一○三','釋崇嶽','宋','宋诗','song-poetry','','[]','西天四七，唐土二三。',36,'全唐诗/poet.song.149000.json','["西天四七，唐土二三。", "天下老和尚，的的相承，不容眨眼，老德山因甚拆却佛殿。"]'),
('a2c3ed2d-3ea3-42a4-9001-10e232bdbfda','偈頌一百二十三首  其一○四','釋崇嶽','宋','宋诗','song-poetry','','[]','第一義諦，分文不直。',30,'全唐诗/poet.song.149000.json','["第一義諦，分文不直。", "略露機鋒，青天霹靂。", "恁麽恁麽，不識不識。"]'),
('2e2d41ca-7ce7-4d89-b144-518dbc2d1589','偈頌一百二十三首  其一○五','釋崇嶽','宋','宋诗','song-poetry','','[]','急水波心下直鈎，魚龍蝦蟹一時收。',32,'全唐诗/poet.song.149000.json','["急水波心下直鈎，魚龍蝦蟹一時收。", "祖師活計無多子，惱亂春風卒未休。"]'),
('91b677ac-f8a1-45ec-a6cf-46dfa7ad70fa','偈頌一百二十三首  其一○六','釋崇嶽','宋','宋诗','song-poetry','','[]','言無展事，語不投機。',32,'全唐诗/poet.song.149000.json','["言無展事，語不投機。", "承言者喪，滯句者迷。", "和底掀翻了，趙州東院西。"]'),
