('ddd7c071-ae88-4fa4-b1d2-3acc79493117','頌古二十五首  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','坐斷千峰路，穿開碧落天。',24,'全唐诗/poet.song.149000.json','["坐斷千峰路，穿開碧落天。", "那容問端的，端的髑髏前。"]'),
('e49be32d-d206-4e90-8996-fc695e39809e','頌古二十五首  其四','釋崇嶽','宋','宋诗','song-poetry','','[]','大道透長安，言端語亦端。',24,'全唐诗/poet.song.149000.json','["大道透長安，言端語亦端。", "臘盡雪消去，春來依舊寒。"]'),
('8bbc5263-8d79-453d-9ed8-548881f1a3c1','頌古二十五首  其五','釋崇嶽','宋','宋诗','song-poetry','','[]','分明寫出與君看，意在鈎頭不在盤。',32,'全唐诗/poet.song.149000.json','["分明寫出與君看，意在鈎頭不在盤。", "縱使石人開得口，不知猶被舌頭瞞。"]'),
('b8423c11-b7ca-4bee-be5f-7fcb765833f8','頌古二十五首  其六','釋崇嶽','宋','宋诗','song-poetry','','[]','出得出不得，攧落精靈窟。',24,'全唐诗/poet.song.149000.json','["出得出不得，攧落精靈窟。", "何處不風流，祖師無妙訣。"]'),
('f32f39b6-b970-4c92-b1ad-86dfa88c86d0','頌古二十五首  其七','釋崇嶽','宋','宋诗','song-poetry','','[]','大梅梅子熟，龐老已先知。',24,'全唐诗/poet.song.149000.json','["大梅梅子熟，龐老已先知。", "正眼驗深要，相逢拍手歸。"]'),
('ee84af24-dbc3-47b6-b24e-9012b314074f','頌古二十五首  其八','釋崇嶽','宋','宋诗','song-poetry','','[]','十月清霜重，臨風徹骨寒。',24,'全唐诗/poet.song.149000.json','["十月清霜重，臨風徹骨寒。", "苦無栖泊處，擺手出長安。"]'),
('06fd9a77-7742-4bdf-bbc8-427b08a5c223','頌古二十五首  其九','釋崇嶽','宋','宋诗','song-poetry','','[]','京師出大黄，見賊便見贓。',24,'全唐诗/poet.song.149000.json','["京師出大黄，見賊便見贓。", "竹杖化龍去，癡人戽夜塘。"]'),
('4c07f60d-4642-47d0-bf90-0419e7b967a4','頌古二十五首  其一○','釋崇嶽','宋','宋诗','song-poetry','','[]','水急魚行澀，峰高鳥不栖。',24,'全唐诗/poet.song.149000.json','["水急魚行澀，峰高鳥不栖。", "世情看冷暖，人面逐高低。"]'),
('49a4dcca-ec20-4513-90b0-ffe8c9e94710','頌古二十五首  其一一','釋崇嶽','宋','宋诗','song-poetry','','[]','殺活全機覿面提，大家相聚喫莖虀。',32,'全唐诗/poet.song.149000.json','["殺活全機覿面提，大家相聚喫莖虀。", "後生不省這箇意，只管忙忙打野榸。"]'),
('19e9f1f8-a8ed-49c3-83b1-162d4373459d','頌古二十五首  其一二','釋崇嶽','宋','宋诗','song-poetry','','[]','雲門一曲，徹髓徹骨。',31,'全唐诗/poet.song.149000.json','["雲門一曲，徹髓徹骨。", "霽雪千峰，寒梅破萼。", "啐啄公子，風流鳴木鐸。"]'),
('e7522ab2-e89c-45e0-a02d-67c51e068206','頌古二十五首  其一三','釋崇嶽','宋','宋诗','song-poetry','','[]','寒暑分明說向君，不容擬議辨疎親。',32,'全唐诗/poet.song.149000.json','["寒暑分明說向君，不容擬議辨疎親。", "匾擔驀折兩頭脫，舉目長空一笑新。"]'),
('3a667a80-8d19-41f0-979d-c4342b9811ec','頌古二十五首  其一四','釋崇嶽','宋','宋诗','song-poetry','','[]','不是風兮不是幡，分明裂破萬重關。',32,'全唐诗/poet.song.149000.json','["不是風兮不是幡，分明裂破萬重關。", "誰知用盡腕頭力，惹得閑名落世間。"]'),
('172c22ed-72ac-4fd2-b203-3ad8f7bd3631','頌古二十五首  其一五','釋崇嶽','宋','宋诗','song-poetry','','[]','雲門小廝兒，作大獅子吼。',24,'全唐诗/poet.song.149000.json','["雲門小廝兒，作大獅子吼。", "鼻孔得半邊，不知失却口。"]'),
('cc3342b6-99ad-4911-97bb-b4647a7d2b27','頌古二十五首  其一六','釋崇嶽','宋','宋诗','song-poetry','','[]','閃電光中賓主分，虛空背上立綱宗。',32,'全唐诗/poet.song.149000.json','["閃電光中賓主分，虛空背上立綱宗。", "祖師活計只如此，後代兒孫掃地空。"]'),
('f0b2d1bd-c7f0-4a8f-8e7e-3460301075c6','頌古二十五首  其一七','釋崇嶽','宋','宋诗','song-poetry','','[]','趙州喫茶去，毒蛇橫古路。',24,'全唐诗/poet.song.149000.json','["趙州喫茶去，毒蛇橫古路。", "踏著乃知非，佛也不堪做。"]'),
('fd422bc4-7803-4adf-a5c1-c1c4d6f38e43','頌古二十五首  其一八','釋崇嶽','宋','宋诗','song-poetry','','[]','夫子不識字，達磨不會禪。',24,'全唐诗/poet.song.149000.json','["夫子不識字，達磨不會禪。", "大唐天子國，依舊化三千。"]'),
('95665ecb-d0f1-40cb-804f-d0548e0b7405','頌古二十五首  其一九','釋崇嶽','宋','宋诗','song-poetry','','[]','雲開空自闊，葉落即歸根。',24,'全唐诗/poet.song.149000.json','["雲開空自闊，葉落即歸根。", "回首煙波裏，漁歌過遠村。"]'),
('48daea77-86c0-41c5-b22f-a2d9c845ac76','頌古二十五首  其二○','釋崇嶽','宋','宋诗','song-poetry','','[]','出水何如未出水，蓮花荷葉有來由。',32,'全唐诗/poet.song.149000.json','["出水何如未出水，蓮花荷葉有來由。", "定光金地遥招手，智者江陵暗點頭。"]'),
('8d1a5e40-28de-46f0-b813-07df0f9ccb7a','頌古二十五首  其二一','釋崇嶽','宋','宋诗','song-poetry','','[]','百丈狸奴面，溈山鬼眼睛。',24,'全唐诗/poet.song.149000.json','["百丈狸奴面，溈山鬼眼睛。", "見人空解笑，弄物不知名。"]'),
('70ce1705-1f72-4ef7-9109-e8da862d83f0','頌古二十五首  其二二','釋崇嶽','宋','宋诗','song-poetry','','[]','拄地撐天全體用，夕陽影裏不藏身。',32,'全唐诗/poet.song.149000.json','["拄地撐天全體用，夕陽影裏不藏身。", "有時獨坐孤峰頂，寂寂猶聞落葉頻。"]'),
('0e7462dd-6c53-4ac6-89cb-dc9a2a949128','頌古二十五首  其二三','釋崇嶽','宋','宋诗','song-poetry','','[]','描不成兮畫不成，卧龍長怖碧潭清。',32,'全唐诗/poet.song.149000.json','["描不成兮畫不成，卧龍長怖碧潭清。", "擬心湊泊終難會，達者應須暗裏驚。"]'),
('49f5be34-ab4e-4532-a2c3-fee6c380b8de','頌古二十五首  其二四','釋崇嶽','宋','宋诗','song-poetry','','[]','臘月燒山，天寬地寬。',20,'全唐诗/poet.song.149000.json','["臘月燒山，天寬地寬。", "築著磕著，徹骨毛寒。"]'),
('82fc488a-0b6a-4248-9d75-987daf0784b4','頌古二十五首  其二五','釋崇嶽','宋','宋诗','song-poetry','','[]','莫莫，拈出一條斷貫索。',27,'全唐诗/poet.song.149000.json','["莫莫，拈出一條斷貫索。", "任從我佛及衆生，撩天鼻孔都穿却。"]'),
('42efd3fe-6d36-49b8-a93e-dc056a311878','釋迦出山相贊','釋崇嶽','宋','宋诗','song-poetry','','[]','棄輪王位放癡獃，夜半逾城心未灰。',32,'全唐诗/poet.song.149000.json','["棄輪王位放癡獃，夜半逾城心未灰。", "冷坐六年無折合，有何面目出山來。"]'),
('1bdee24e-9cb0-41a8-8913-7cd16573df89','無量壽佛贊','釋崇嶽','宋','宋诗','song-poetry','','[]','四十八弘誓願，百千萬億彌陀。',30,'全唐诗/poet.song.149000.json','["四十八弘誓願，百千萬億彌陀。", "水鳥樹林開正眼，爲人親切不消多。"]'),
('c6faf4e9-9992-47d7-84af-d8920b296603','觀音贊','釋崇嶽','宋','宋诗','song-poetry','','[]','月團團，星斗寒。',26,'全唐诗/poet.song.149000.json','["月團團，星斗寒。", "風振海，雷破山。", "圓通大士，瑞應人間。"]'),
('158d14a4-d057-4a05-8bcc-86c71ba0e78c','九祖贊','釋崇嶽','宋','宋诗','song-poetry','','[]','半生足不履地，軒知路遍天涯。',28,'全唐诗/poet.song.149000.json','["半生足不履地，軒知路遍天涯。", "得箇冬瓜印子，至今目瞠口呿。"]'),
('bf817785-7ea6-4d24-9437-a4fc20c60d3e','維摩贊','釋崇嶽','宋','宋诗','song-poetry','','[]','深入不二門，巧盡翻成拙。',34,'全唐诗/poet.song.149000.json','["深入不二門，巧盡翻成拙。", "一默定千差，常說熾然說說拙，萬古清風寒徹骨。"]'),
('d067f630-7cf1-49cc-bcd1-f4f7d70be963','達磨贊  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','鳳凰城闕，不通水泄。',34,'全唐诗/poet.song.149000.json','["鳳凰城闕，不通水泄。", "少室巖前，話作兩橛。", "賺它人家男女，開眼喚龜作鱉。"]'),
('d1dd3194-8044-4c69-905e-2999d3586cbc','達磨贊  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','直指西來，分明禍胎。',34,'全唐诗/poet.song.149000.json','["直指西來，分明禍胎。", "渡江面壁，偷心未息。", "從茲皮髓分張，轟起青天霹靂。"]'),
('bbb0f508-aa9c-4ad2-b4f1-f7c0555abf35','達磨贊  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','一葦渡江，無處埋藏。',34,'全唐诗/poet.song.149000.json','["一葦渡江，無處埋藏。", "分皮分髓，瞞神謼鬼。", "忙忙直向西歸，不知失却隻履。"]'),
('98716272-7d8d-45eb-b120-c1d890d8a739','龐居士贊','釋崇嶽','宋','宋诗','song-poetry','','[]','心空及第，深根固蒂。',36,'全唐诗/poet.song.149000.json','["心空及第，深根固蒂。", "共說無生，異類中行。", "惱亂禪家至今日，不知日午打三更。"]'),
('d1c08c13-96c2-46d4-b26c-d595d4196d8b','臨濟贊','釋崇嶽','宋','宋诗','song-poetry','','[]','一棒一喝，傾湫倒嶽。',20,'全唐诗/poet.song.149000.json','["一棒一喝，傾湫倒嶽。", "凌蔑吾宗，這白拈賊。"]'),
('027d2aab-405c-4918-9054-225083f48e4b','金華聖者贊','釋崇嶽','宋','宋诗','song-poetry','','[]','千兵不若一將，伎倆何如帳樣。',28,'全唐诗/poet.song.149000.json','["千兵不若一將，伎倆何如帳樣。", "不識古佛定光，稽首豬頭和尚。"]'),
('a9786fdd-228d-42eb-80e9-120ada341dc1','大巔和尚贊','釋崇嶽','宋','宋诗','song-poetry','','[]','趕首座出院，勘三平中箭。',40,'全唐诗/poet.song.149000.json','["趕首座出院，勘三平中箭。", "放過韓文公，鈎頭通一線。", "謾道晝夜一百八，也是和盲悖訴瞎。"]'),
('b579e66f-e242-4320-b740-cfb70e97c953','應庵師祖贊  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','深入虎穴，有屈難雪。',20,'全唐诗/poet.song.149000.json','["深入虎穴，有屈難雪。", "天下應庵，只得一橛。"]'),
('dc42f8a6-1373-469a-9a69-766616558f7f','應庵師祖贊  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','虎口裏轉身，拳頭上捏怪。',32,'全唐诗/poet.song.149000.json','["虎口裏轉身，拳頭上捏怪。", "胡亂三十年，起東山正派。", "不知過犯彌天大。"]'),
('aeaafa6b-13c6-4516-bda2-99aea6102b3a','密庵先師贊','釋崇嶽','宋','宋诗','song-poetry','','[]','咬豬狗之手討甚巴鼻，奮劈胸之拳瞎却頂門。',58,'全唐诗/poet.song.149000.json','["咬豬狗之手討甚巴鼻，奮劈胸之拳瞎却頂門。", "出達磨身血，斷衲僧命根。", "纖毫不肯放過，叢林爲讎爲冤。", "箇般種草决，定累及兒孫。"]'),
('13a4018a-a33d-4974-a24f-6db980804889','芝山智默長老請贊密庵先師','釋崇嶽','宋','宋诗','song-poetry','','[]','擊石火裏穿遼天鼻孔，妙轉機前打鳳羅龍。',57,'全唐诗/poet.song.149000.json','["擊石火裏穿遼天鼻孔，妙轉機前打鳳羅龍。", "正法眼，瞎馿邊。", "滅却破沙盆，扶臨濟正宗。", "門庭峭峻，孰敢當鋒，鐵壁銀山一線通。"]'),
('c7b972be-43e7-4276-a024-115e7b660c98','能仁光睦長老畫師頂相請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','恣拍盲性，用劈胸拳。',40,'全唐诗/poet.song.149000.json','["恣拍盲性，用劈胸拳。", "併蕩三玄三要，管甚栗棘金圈。", "渠儂已是滅胡種，不知將底付兒孫。"]'),
('22436d8f-944a-4c3c-a570-ba720efcbff7','雲居善開長老請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','爲人巴鼻，一點渾無。',48,'全唐诗/poet.song.149000.json','["爲人巴鼻，一點渾無。", "明眼衲僧，失却鼻孔。", "鐵餕餡，金剛圈。", "分明開口不在舌頭邊，累及後代結佛祖深冤。"]'),
('9a31bf20-02c6-4b84-817b-01cc385711a6','道巖首座請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','人我如山，狠氣如雲。',36,'全唐诗/poet.song.149000.json','["人我如山，狠氣如雲。", "炊無米飯，接不來人。", "電光影裏賓主分，不是冤家不與隣。"]'),
('510bab59-82ae-440d-a8e0-bf9a9d84ceda','師肇首座請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','這箇漢，太愚癡。',56,'全唐诗/poet.song.149000.json','["這箇漢，太愚癡。", "一句子，佛不知。", "臨濟老，客作兒。", "四天下，更有誰。", "擬開口，劈胸椎。", "肇首座，莫學伊，學伊彼此落便宜。"]'),
('dececf9d-8fbe-4576-b17c-617548e8c104','師警維那請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','冤有頭，債有主。',34,'全唐诗/poet.song.149000.json','["冤有頭，債有主。", "鱉鼻蛇，白額虎。", "活捉生擒，當陽直舉，發機須是千鈞弩。"]'),
('9293cb83-674a-4663-98b9-c86d41922ba7','希璉書記請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','臘長年高，甚生風彩。',54,'全唐诗/poet.song.149000.json','["臘長年高，甚生風彩。", "南來北來，無可相待。", "黑漆竹篦聊一揮，看你當人在不在。", "璉書記，甚尀耐。", "鎮海明珠，懸空撲碎。"]'),
('929c0eaa-7bdc-43ae-b46c-7b70529ecc80','大成藏主請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','一段風光，寧容描邈。',36,'全唐诗/poet.song.149000.json','["一段風光，寧容描邈。", "祖祖相傳，將錯就錯。", "不以佛法作人情，掣電機前活卓卓。"]'),
('a8bdcfa7-eaa7-47d4-afc3-e5623a6db4da','文蔚侍者請贊','釋崇嶽','宋','宋诗','song-poetry','','[]','心粗膽大，少實多虛。',50,'全唐诗/poet.song.149000.json','["心粗膽大，少實多虛。", "瞎衲僧眼，斷肘後符。", "臨濟東山之道命若懸絲，念念刀耕火種老此殘軀。", "寥落林泉意自殊。"]'),
('bcdb14ca-9acb-4bf3-ae51-1e1d0708bacb','惠文伯居士請贊  其一','釋崇嶽','宋','宋诗','song-poetry','','[]','不著佛求，不著法求。',52,'全唐诗/poet.song.149000.json','["不著佛求，不著法求。", "人天眼目，佛祖冤讎。", "香岩下指南作北，劍池上看樓打樓。", "機輪妙轉一絲頭，不得鯢鯨不肯休。"]'),
('be805885-e513-42f6-b734-47bc48fa93a2','惠文伯居士請贊  其二','釋崇嶽','宋','宋诗','song-poetry','','[]','這箇賊，無面目。',42,'全唐诗/poet.song.149000.json','["這箇賊，無面目。", "指東南，看西北。", "不住雲居，又憎薦福。", "自知不解守叢林，永劫甘心入地獄。"]'),
('e7376287-2137-4976-975f-1ffc94e9a5a6','惠文伯居士請贊  其三','釋崇嶽','宋','宋诗','song-poetry','','[]','這漢生來無狀，佛祖亦難近傍。',28,'全唐诗/poet.song.149000.json','["這漢生來無狀，佛祖亦難近傍。", "趯出金圈栗蓬，開口不在舌上。"]'),
('ef5127e8-73f5-4d81-956b-58516ec2582a','惠文伯居士請贊  其四','釋崇嶽','宋','宋诗','song-poetry','','[]','是人道渠執拗，不知年老成魔。',42,'全唐诗/poet.song.149000.json','["是人道渠執拗，不知年老成魔。", "偏要時時入室，所招怪恨者多。", "阿呵呵，屈指東西誰似它。", "咄。"]'),
('689479ef-80ea-461d-a3d1-877de35a4ce6','惠文伯居士請贊  其五','釋崇嶽','宋','宋诗','song-poetry','','[]','肋下三拳，攔顋一掌。',36,'全唐诗/poet.song.149000.json','["肋下三拳，攔顋一掌。", "據令而行，誰知痛癢。", "轉身一拶驗來端，楊岐種草鐵心肝。"]'),
('0927c438-f524-444e-87d5-17ced86068f6','惠文伯居士請贊  其六','釋崇嶽','宋','宋诗','song-poetry','','[]','無卓錐之地，有無價之寶。',42,'全唐诗/poet.song.149000.json','["無卓錐之地，有無價之寶。", "元不用安排，拈來用恰好。", "沒人情，佛亦掃。", "這般村僧，脫空到老。"]'),
('ef1dc1ba-acec-45af-a8e8-5169099f7164','惠文伯居士請贊  其七','釋崇嶽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','行脚不到廬山，住院只在江浙。',46,'全唐诗/poet.song.149000.json','["行脚不到廬山，住院只在江浙。", "偏要冷笑諸方，忘却自家百拙。", "討便宜，破邪說。", "一錐一劄，不妨凜冽。"]'),
('ead9d05f-e432-40f5-a8ae-668386d6d562','送悟藏主還姑蘇','釋崇嶽','宋','宋诗','song-poetry','','[]','玲瓏巖畔瞥不瞥，豎起脊梁生鐵橛。',192,'全唐诗/poet.song.149000.json','["玲瓏巖畔瞥不瞥，豎起脊梁生鐵橛。", "無端林下錯商量，携手相隨入虎穴。", "甕裏驀然失却鱉，箇事明明向誰說。", "彼時只是此時人，誰知眼裏重添屑。", "我携拄杖奔南北，君入西山恣輕忽。", "放下蛇頭捋虎鬚，翻身便作白拈賊。", "太虛全布目前機，生殺交馳誰敢窺。", "我來一笑重相見，鼻孔由來向下垂。", "密庵家風徹骨貧，密庵有眼且無筋。", "將無作有這些子，透這些子能幾人。", "西風落木天宇迥，君兮不住別峰頂。", "曹谿一滴杖頭挑，漲起吳江千萬頃。"]'),
('b45844e9-3c6f-4ef3-9a35-9539f65dfe66','題張直閣亦庵','釋崇嶽','宋','宋诗','song-poetry','','[]','曹溪無一滴，誰道庵名亦。',24,'全唐诗/poet.song.149000.json','["曹溪無一滴，誰道庵名亦。", "問訊老維摩，鐵壁復鐵壁。"]'),
('4fbedb8b-fa6d-48b6-9d69-b7a6d57153c9','題先登齋','釋崇嶽','宋','宋诗','song-poetry','','[]','大道難將萬物齊，先登猶自涉階梯。',32,'全唐诗/poet.song.149000.json','["大道難將萬物齊，先登猶自涉階梯。", "翻身直透青霄外，回首方知宇宙低。"]'),
('5a50227d-bec8-4350-b057-a0be4b449761','送聰首座之弋陽兼呈陳郎中','釋崇嶽','宋','宋诗','song-poetry','','[]','當頭一著沒巴鼻，坐斷諸方成忌諱。',64,'全唐诗/poet.song.149000.json','["當頭一著沒巴鼻，坐斷諸方成忌諱。", "此心不向白雲閑，一錫飄然下層翠。", "晦庵過犯彌天大，居士無端也捏怪。", "至今落賺有誰知，也要大家償夙債。"]'),
('6cf8e9c5-2dcb-4de2-ab85-196dd6169693','柏庭永和尚出世天禧以頌寄之','釋崇嶽','宋','宋诗','song-poetry','','[]','林下相從知幾年，好因緣是惡因緣。',32,'全唐诗/poet.song.149000.json','["林下相從知幾年，好因緣是惡因緣。", "雖然不受靈山記，鼻孔依前著那邊。"]');
